;\\n$print-body-min-width:              map-get($grid-breakpoints, \\\"lg\\\") !default;\\n\",","\t\t\"// Toggles\\n//\\n// Used in conjunction with global variables to enable certain theme features.\\n\\n// Vendor\\n@import \\\"vendor/rfs\\\";\\n\\n// Deprecate\\n@import \\\"mixins/deprecate\\\";\\n\\n// Utilities\\n@import \\\"mixins/breakpoints\\\";\\n@import \\\"mixins/hover\\\";\\n@import \\\"mixins/image\\\";\\n@import \\\"mixins/badge\\\";\\n@import \\\"mixins/resize\\\";\\n@import \\\"mixins/screen-reader\\\";\\n@import \\\"mixins/size\\\";\\n@import \\\"mixins/reset-text\\\";\\n@import \\\"mixins/text-emphasis\\\";\\n@import \\\"mixins/text-hide\\\";\\n@import \\\"mixins/text-truncate\\\";\\n@import \\\"mixins/visibility\\\";\\n\\n// // Components\\n@import \\\"mixins/alert\\\";\\n@import \\\"mixins/buttons\\\";\\n@import \\\"mixins/caret\\\";\\n@import \\\"mixins/pagination\\\";\\n@import \\\"mixins/lists\\\";\\n@import \\\"mixins/list-group\\\";\\n@import \\\"mixins/nav-divider\\\";\\n@import \\\"mixins/forms\\\";\\n@import \\\"mixins/table-row\\\";\\n\\n// // Skins\\n@import \\\"mixins/background-variant\\\";\\n@import \\\"mixins/border-radius\\\";\\n@import \\\"mixins/box-shadow\\\";\\n@import \\\"mixins/gradients\\\";\\n@import \\\"mixins/transition\\\";\\n\\n// // Layout\\n@import \\\"mixins/clearfix\\\";\\n@import \\\"mixins/grid-framework\\\";\\n@import \\\"mixins/grid\\\";\\n@import \\\"mixins/float\\\";\\n\",","\t\t\"// stylelint-disable property-blacklist, scss/dollar-variable-default\\n\\n// SCSS RFS mixin\\n//\\n// Automated font-resizing\\n//\\n// See https://github.com/twbs/rfs\\n\\n// Configuration\\n\\n// Base font size\\n$rfs-base-font-size: 1.25rem !default;\\n$rfs-font-size-unit: rem !default;\\n\\n// Breakpoint at where font-size starts decreasing if screen width is smaller\\n$rfs-breakpoint: 1200px !default;\\n$rfs-breakpoint-unit: px !default;\\n\\n// Resize font-size based on screen height and width\\n$rfs-two-dimensional: false !default;\\n\\n// Factor of decrease\\n$rfs-factor: 10 !default;\\n\\n@if type-of($rfs-factor) != \\\"number\\\" or $rfs-factor \u003c= 1 {\\n  @error \\\"`#{$rfs-factor}` is not a valid  $rfs-factor, it must be greater than 1.\\\";\\n}\\n\\n// Generate enable or disable classes. Possibilities: false, \\\"enable\\\" or \\\"disable\\\"\\n$rfs-class: false !default;\\n\\n// 1 rem = $rfs-rem-value px\\n$rfs-rem-value: 16 !default;\\n\\n// Safari iframe resize bug: https://github.com/twbs/rfs/issues/14\\n$rfs-safari-iframe-resize-bug-fix: false !default;\\n\\n// Disable RFS by setting $enable-responsive-font-sizes to false\\n$enable-responsive-font-sizes: true !default;\\n\\n// Cache $rfs-base-font-size unit\\n$rfs-base-font-size-unit: unit($rfs-base-font-size);\\n\\n// Remove px-unit from $rfs-base-font-size for calculations\\n@if $rfs-base-font-size-unit == \\\"px\\\" {\\n  $rfs-base-font-size: $rfs-base-font-size / ($rfs-base-font-size * 0 + 1);\\n}\\n@else if $rfs-base-font-size-unit == \\\"rem\\\" {\\n  $rfs-base-font-size: $rfs-base-font-size / ($rfs-base-font-size * 0 + 1 / $rfs-rem-value);\\n}\\n\\n// Cache $rfs-breakpoint unit to prevent multiple calls\\n$rfs-breakpoint-unit-cache: unit($rfs-breakpoint);\\n\\n// Remove unit from $rfs-breakpoint for calculations\\n@if $rfs-breakpoint-unit-cache == \\\"px\\\" {\\n  $rfs-breakpoint: $rfs-breakpoint / ($rfs-breakpoint * 0 + 1);\\n}\\n@else if $rfs-breakpoint-unit-cache == \\\"rem\\\" or $rfs-breakpoint-unit-cache == \\\"em\\\" {\\n  $rfs-breakpoint: $rfs-breakpoint / ($rfs-breakpoint * 0 + 1 / $rfs-rem-value);\\n}\\n\\n// Responsive font-size mixin\\n@mixin rfs($fs, $important: false) {\\n  // Cache $fs unit\\n  $fs-unit: if(type-of($fs) == \\\"number\\\", unit($fs), false);\\n\\n  // Add !important suffix if needed\\n  $rfs-suffix: if($important, \\\" !important\\\", \\\"\\\");\\n\\n  // If $fs isn't a number (like inherit) or $fs has a unit (not px or rem, like 1.5em) or $ is 0, just print the value\\n  @if not $fs-unit or $fs-unit != \\\"\\\" and $fs-unit != \\\"px\\\" and $fs-unit != \\\"rem\\\" or $fs == 0 {\\n    font-size: #{$fs}#{$rfs-suffix};\\n  }\\n  @else {\\n    // Variables for storing static and fluid rescaling\\n    $rfs-static: null;\\n    $rfs-fluid: null;\\n\\n    // Remove px-unit from $fs for calculations\\n    @if $fs-unit == \\\"px\\\" {\\n      $fs: $fs / ($fs * 0 + 1);\\n    }\\n    @else if $fs-unit == \\\"rem\\\" {\\n      $fs: $fs / ($fs * 0 + 1 / $rfs-rem-value);\\n    }\\n\\n    // Set default font-size\\n    @if $rfs-font-size-unit == rem {\\n      $rfs-static: #{$fs / $rfs-rem-value}rem#{$rfs-suffix};\\n    }\\n    @else if $rfs-font-size-unit == px {\\n      $rfs-static: #{$fs}px#{$rfs-suffix};\\n    }\\n    @else {\\n      @error \\\"`#{$rfs-font-size-unit}` is not a valid unit for $rfs-font-size-unit. Use `px` or `rem`.\\\";\\n    }\\n\\n    // Only add media query if font-size is bigger as the minimum font-size\\n    // If $rfs-factor == 1, no rescaling will take place\\n    @if $fs \u003e $rfs-base-font-size and $enable-responsive-font-sizes {\\n      $min-width: null;\\n      $variable-unit: null;\\n\\n      // Calculate minimum font-size for given font-size\\n      $fs-min: $rfs-base-font-size + ($fs - $rfs-base-font-size) / $rfs-factor;\\n\\n      // Calculate difference between given font-size and minimum font-size for given font-size\\n      $fs-diff: $fs - $fs-min;\\n\\n      // Base font-size formatting\\n      // No need to check if the unit is valid, because we did that before\\n      $min-width: if($rfs-font-size-unit == rem, #{$fs-min / $rfs-rem-value}rem, #{$fs-min}px);\\n\\n      // If two-dimensional, use smallest of screen width and height\\n      $variable-unit: if($rfs-two-dimensional, vmin, vw);\\n\\n      // Calculate the variable width between 0 and $rfs-breakpoint\\n      $variable-width: #{$fs-diff * 100 / $rfs-breakpoint}#{$variable-unit};\\n\\n      // Set the calculated font-size.\\n      $rfs-fluid: calc(#{$min-width} + #{$variable-width}) #{$rfs-suffix};\\n    }\\n\\n    // Rendering\\n    @if $rfs-fluid == null {\\n      // Only render static font-size if no fluid font-size is available\\n      font-size: $rfs-static;\\n    }\\n    @else {\\n      $mq-value: null;\\n\\n      // RFS breakpoint formatting\\n      @if $rfs-breakpoint-unit == em or $rfs-breakpoint-unit == rem {\\n        $mq-value: #{$rfs-breakpoint / $rfs-rem-value}#{$rfs-breakpoint-unit};\\n      }\\n      @else if $rfs-breakpoint-unit == px {\\n        $mq-value: #{$rfs-breakpoint}px;\\n      }\\n      @else {\\n        @error \\\"`#{$rfs-breakpoint-unit}` is not a valid unit for $rfs-breakpoint-unit. Use `px`, `em` or `rem`.\\\";\\n      }\\n\\n      @if $rfs-class == \\\"disable\\\" {\\n        // Adding an extra class increases specificity,\\n        // which prevents the media query to override the font size\\n        \u0026,\\n        .disable-responsive-font-size \u0026,\\n        \u0026.disable-responsive-font-size {\\n          font-size: $rfs-static;\\n        }\\n      }\\n      @else {\\n        font-size: $rfs-static;\\n      }\\n\\n      @if $rfs-two-dimensional {\\n        @media (max-width: #{$mq-value}), (max-height: #{$mq-value}) {\\n          @if $rfs-class == \\\"enable\\\" {\\n            .enable-responsive-font-size \u0026,\\n            \u0026.enable-responsive-font-size {\\n              font-size: $rfs-fluid;\\n            }\\n          }\\n          @else {\\n            font-size: $rfs-fluid;\\n          }\\n\\n          @if $rfs-safari-iframe-resize-bug-fix {\\n            // stylelint-disable-next-line length-zero-no-unit\\n            min-width: 0vw;\\n          }\\n        }\\n      }\\n      @else {\\n        @media (max-width: #{$mq-value}) {\\n          @if $rfs-class == \\\"enable\\\" {\\n            .enable-responsive-font-size \u0026,\\n            \u0026.enable-responsive-font-size {\\n              font-size: $rfs-fluid;\\n            }\\n          }\\n          @else {\\n            font-size: $rfs-fluid;\\n          }\\n\\n          @if $rfs-safari-iframe-resize-bug-fix {\\n            // stylelint-disable-next-line length-zero-no-unit\\n            min-width: 0vw;\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n// The font-size \u0026 responsive-font-size mixin uses RFS to rescale font sizes\\n@mixin font-size($fs, $important: false) {\\n  @include rfs($fs, $important);\\n}\\n\\n@mixin responsive-font-size($fs, $important: false) {\\n  @include rfs($fs, $important);\\n}\\n\",","\t\t\"// Deprecate mixin\\n//\\n// This mixin can be used to deprecate mixins or functions.\\n// `$enable-deprecation-messages` is a global variable, `$ignore-warning` is a variable that can be passed to\\n// some deprecated mixins to suppress the warning (for example if the mixin is still be used in the current version of Bootstrap)\\n@mixin deprecate($name, $deprecate-version, $remove-version, $ignore-warning: false) {\\n  @if ($enable-deprecation-messages != false and $ignore-warning != true) {\\n    @warn \\\"#{$name} has been deprecated as of #{$deprecate-version}. It will be removed entirely in #{$remove-version}.\\\";\\n  }\\n}\\n\",","\t\t\"// Breakpoint viewport sizes and media queries.\\n//\\n// Breakpoints are defined as a map of (name: minimum width), order from small to large:\\n//\\n//    (xs: 0, sm: 576px, md: 768px, lg: 992px, xl: 1200px)\\n//\\n// The map defined in the `$grid-breakpoints` global variable is used as the `$breakpoints` argument by default.\\n\\n// Name of the next breakpoint, or null for the last breakpoint.\\n//\\n//    \u003e\u003e breakpoint-next(sm)\\n//    md\\n//    \u003e\u003e breakpoint-next(sm, (xs: 0, sm: 576px, md: 768px, lg: 992px, xl: 1200px))\\n//    md\\n//    \u003e\u003e breakpoint-next(sm, $breakpoint-names: (xs sm md lg xl))\\n//    md\\n@function breakpoint-next($name, $breakpoints: $grid-breakpoints, $breakpoint-names: map-keys($breakpoints)) {\\n  $n: index($breakpoint-names, $name);\\n  @return if($n != null and $n \u003c length($breakpoint-names), nth($breakpoint-names, $n + 1), null);\\n}\\n\\n// Minimum breakpoint width. Null for the smallest (first) breakpoint.\\n//\\n//    \u003e\u003e breakpoint-min(sm, (xs: 0, sm: 576px, md: 768px, lg: 992px, xl: 1200px))\\n//    576px\\n@function breakpoint-min($name, $breakpoints: $grid-breakpoints) {\\n  $min: map-get($breakpoints, $name);\\n  @return if($min != 0, $min, null);\\n}\\n\\n// Maximum breakpoint width. Null for the largest (last) breakpoint.\\n// The maximum value is calculated as the minimum of the next one less 0.02px\\n// to work around the limitations of `min-` and `max-` prefixes and viewports with fractional widths.\\n// See https://www.w3.org/TR/mediaqueries-4/#mq-min-max\\n// Uses 0.02px rather than 0.01px to work around a current rounding bug in Safari.\\n// See https://bugs.webkit.org/show_bug.cgi?id=178261\\n//\\n//    \u003e\u003e breakpoint-max(sm, (xs: 0, sm: 576px, md: 768px, lg: 992px, xl: 1200px))\\n//    767.98px\\n@function breakpoint-max($name, $breakpoints: $grid-breakpoints) {\\n  $next: breakpoint-next($name, $breakpoints);\\n  @return if($next, breakpoint-min($next, $breakpoints) - .02, null);\\n}\\n\\n// Returns a blank string if smallest breakpoint, otherwise returns the name with a dash in front.\\n// Useful for making responsive utilities.\\n//\\n//    \u003e\u003e breakpoint-infix(xs, (xs: 0, sm: 576px, md: 768px, lg: 992px, xl: 1200px))\\n//    \\\"\\\"  (Returns a blank string)\\n//    \u003e\u003e breakpoint-infix(sm, (xs: 0, sm: 576px, md: 768px, lg: 992px, xl: 1200px))\\n//    \\\"-sm\\\"\\n@function breakpoint-infix($name, $breakpoints: $grid-breakpoints) {\\n  @return if(breakpoint-min($name, $breakpoints) == null, \\\"\\\", \\\"-#{$name}\\\");\\n}\\n\\n// Media of at least the minimum breakpoint width. No query for the smallest breakpoint.\\n// Makes the @content apply to the given breakpoint and wider.\\n@mixin media-breakpoint-up($name, $breakpoints: $grid-breakpoints) {\\n  $min: breakpoint-min($name, $breakpoints);\\n  @if $min {\\n    @media (min-width: $min) {\\n      @content;\\n    }\\n  } @else {\\n    @content;\\n  }\\n}\\n\\n// Media of at most the maximum breakpoint width. No query for the largest breakpoint.\\n// Makes the @content apply to the given breakpoint and narrower.\\n@mixin media-breakpoint-down($name, $breakpoints: $grid-breakpoints) {\\n  $max: breakpoint-max($name, $breakpoints);\\n  @if $max {\\n    @media (max-width: $max) {\\n      @content;\\n    }\\n  } @else {\\n    @content;\\n  }\\n}\\n\\n// Media that spans multiple breakpoint widths.\\n// Makes the @content apply between the min and max breakpoints\\n@mixin media-breakpoint-between($lower, $upper, $breakpoints: $grid-breakpoints) {\\n  $min: breakpoint-min($lower, $breakpoints);\\n  $max: breakpoint-max($upper, $breakpoints);\\n\\n  @if $min != null and $max != null {\\n    @media (min-width: $min) and (max-width: $max) {\\n      @content;\\n    }\\n  } @else if $max == null {\\n    @include media-breakpoint-up($lower, $breakpoints) {\\n      @content;\\n    }\\n  } @else if $min == null {\\n    @include media-breakpoint-down($upper, $breakpoints) {\\n      @content;\\n    }\\n  }\\n}\\n\\n// Media between the breakpoint's minimum and maximum widths.\\n// No minimum for the smallest breakpoint, and no maximum for the largest one.\\n// Makes the @content apply only to the given breakpoint, not viewports any wider or narrower.\\n@mixin media-breakpoint-only($name, $breakpoints: $grid-breakpoints) {\\n  $min: breakpoint-min($name, $breakpoints);\\n  $max: breakpoint-max($name, $breakpoints);\\n\\n  @if $min != null and $max != null {\\n    @media (min-width: $min) and (max-width: $max) {\\n      @content;\\n    }\\n  } @else if $max == null {\\n    @include media-breakpoint-up($name, $breakpoints) {\\n      @content;\\n    }\\n  } @else if $min == null {\\n    @include media-breakpoint-down($name, $breakpoints) {\\n      @content;\\n    }\\n  }\\n}\\n\",","\t\t\"// Hover mixin and `$enable-hover-media-query` are deprecated.\\n//\\n// Originally added during our alphas and maintained during betas, this mixin was\\n// designed to prevent `:hover` stickiness on iOS-an issue where hover styles\\n// would persist after initial touch.\\n//\\n// For backward compatibility, we've kept these mixins and updated them to\\n// always return their regular pseudo-classes instead of a shimmed media query.\\n//\\n// Issue: https://github.com/twbs/bootstrap/issues/25195\\n\\n@mixin hover {\\n  \u0026:hover { @content; }\\n}\\n\\n@mixin hover-focus {\\n  \u0026:hover,\\n  \u0026:focus {\\n    @content;\\n  }\\n}\\n\\n@mixin plain-hover-focus {\\n  \u0026,\\n  \u0026:hover,\\n  \u0026:focus {\\n    @content;\\n  }\\n}\\n\\n@mixin hover-focus-active {\\n  \u0026:hover,\\n  \u0026:focus,\\n  \u0026:active {\\n    @content;\\n  }\\n}\\n\",","\t\t\"// Image Mixins\\n// - Responsive image\\n// - Retina image\\n\\n\\n// Responsive image\\n//\\n// Keep images from scaling beyond the width of their parents.\\n\\n@mixin img-fluid {\\n  // Part 1: Set a maximum relative to the parent\\n  max-width: 100%;\\n  // Part 2: Override the height to auto, otherwise images will be stretched\\n  // when setting a width and height attribute on the img element.\\n  height: auto;\\n}\\n\\n\\n// Retina image\\n//\\n// Short retina mixin for setting background-image and -size.\\n\\n@mixin img-retina($file-1x, $file-2x, $width-1x, $height-1x) {\\n  background-image: url($file-1x);\\n\\n  // Autoprefixer takes care of adding -webkit-min-device-pixel-ratio and -o-min-device-pixel-ratio,\\n  // but doesn't convert dppx=\u003edpi.\\n  // There's no such thing as unprefixed min-device-pixel-ratio since it's nonstandard.\\n  // Compatibility info: https://caniuse.com/#feat=css-media-resolution\\n  @media only screen and (min-resolution: 192dpi), // IE9-11 don't support dppx\\n    only screen and (min-resolution: 2dppx) { // Standardized\\n    background-image: url($file-2x);\\n    background-size: $width-1x $height-1x;\\n  }\\n  @include deprecate(\\\"`img-retina()`\\\", \\\"v4.3.0\\\", \\\"v5\\\");\\n}\\n\",","\t\t\"@mixin badge-variant($bg) {\\n  color: color-yiq($bg);\\n  background-color: $bg;\\n\\n  @at-root a#{\u0026} {\\n    @include hover-focus {\\n      color: color-yiq($bg);\\n      background-color: darken($bg, 10%);\\n    }\\n\\n    \u0026:focus,\\n    \u0026.focus {\\n      outline: 0;\\n      box-shadow: 0 0 0 $badge-focus-width rgba($bg, .5);\\n    }\\n  }\\n}\\n\",","\t\t\"// Resize anything\\n\\n@mixin resizable($direction) {\\n  overflow: auto; // Per CSS3 UI, `resize` only applies when `overflow` isn't `visible`\\n  resize: $direction; // Options: horizontal, vertical, both\\n}\\n\",","\t\t\"// Only display content to screen readers\\n//\\n// See: https://a11yproject.com/posts/how-to-hide-content/\\n// See: https://hugogiraudel.com/2016/10/13/css-hide-and-seek/\\n\\n@mixin sr-only {\\n  position: absolute;\\n  width: 1px;\\n  height: 1px;\\n  padding: 0;\\n  overflow: hidden;\\n  clip: rect(0, 0, 0, 0);\\n  white-space: nowrap;\\n  border: 0;\\n}\\n\\n// Use in conjunction with .sr-only to only display content when it's focused.\\n//\\n// Useful for \\\"Skip to main content\\\" links; see https://www.w3.org/TR/2013/NOTE-WCAG20-TECHS-20130905/G1\\n//\\n// Credit: HTML5 Boilerplate\\n\\n@mixin sr-only-focusable {\\n  \u0026:active,\\n  \u0026:focus {\\n    position: static;\\n    width: auto;\\n    height: auto;\\n    overflow: visible;\\n    clip: auto;\\n    white-space: normal;\\n  }\\n}\\n\",","\t\t\"// Sizing shortcuts\\n\\n@mixin size($width, $height: $width) {\\n  width: $width;\\n  height: $height;\\n  @include deprecate(\\\"`size()`\\\", \\\"v4.3.0\\\", \\\"v5\\\");\\n}\\n\",","\t\t\"@mixin reset-text {\\n  font-family: $font-family-base;\\n  // We deliberately do NOT reset font-size or word-wrap.\\n  font-style: normal;\\n  font-weight: $font-weight-normal;\\n  line-height: $line-height-base;\\n  text-align: left; // Fallback for where `start` is not supported\\n  text-align: start;\\n  text-decoration: none;\\n  text-shadow: none;\\n  text-transform: none;\\n  letter-spacing: normal;\\n  word-break: normal;\\n  word-spacing: normal;\\n  white-space: normal;\\n  line-break: auto;\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Typography\\n\\n@mixin text-emphasis-variant($parent, $color) {\\n  #{$parent} {\\n    color: $color !important;\\n  }\\n  @if $emphasized-link-hover-darken-percentage != 0 {\\n    a#{$parent} {\\n      @include hover-focus {\\n        color: darken($color, $emphasized-link-hover-darken-percentage) !important;\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"// CSS image replacement\\n@mixin text-hide($ignore-warning: false) {\\n  // stylelint-disable-next-line font-family-no-missing-generic-family-keyword\\n  font: 0/0 a;\\n  color: transparent;\\n  text-shadow: none;\\n  background-color: transparent;\\n  border: 0;\\n\\n  @include deprecate(\\\"`text-hide()`\\\", \\\"v4.1.0\\\", \\\"v5\\\", $ignore-warning);\\n}\\n\",","\t\t\"// Text truncate\\n// Requires inline-block or block for proper styling\\n\\n@mixin text-truncate() {\\n  overflow: hidden;\\n  text-overflow: ellipsis;\\n  white-space: nowrap;\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Visibility\\n\\n@mixin invisible($visibility) {\\n  visibility: $visibility !important;\\n  @include deprecate(\\\"`invisible()`\\\", \\\"v4.3.0\\\", \\\"v5\\\");\\n}\\n\",","\t\t\"@mixin alert-variant($background, $border, $color) {\\n  color: $color;\\n  @include gradient-bg($background);\\n  border-color: $border;\\n\\n  hr {\\n    border-top-color: darken($border, 5%);\\n  }\\n\\n  .alert-link {\\n    color: darken($color, 10%);\\n  }\\n}\\n\",","\t\t\"// Button variants\\n//\\n// Easily pump out default styles, as well as :hover, :focus, :active,\\n// and disabled options for all buttons\\n\\n@mixin button-variant($background, $border, $hover-background: darken($background, 7.5%), $hover-border: darken($border, 10%), $active-background: darken($background, 10%), $active-border: darken($border, 12.5%)) {\\n  color: color-yiq($background);\\n  @include gradient-bg($background);\\n  border-color: $border;\\n  @include box-shadow($btn-box-shadow);\\n\\n  @include hover {\\n    color: color-yiq($hover-background);\\n    @include gradient-bg($hover-background);\\n    border-color: $hover-border;\\n  }\\n\\n  \u0026:focus,\\n  \u0026.focus {\\n    // Avoid using mixin so we can pass custom focus shadow properly\\n    @if $enable-shadows {\\n      box-shadow: $btn-box-shadow, 0 0 0 $btn-focus-width rgba(mix(color-yiq($background), $border, 15%), .5);\\n    } @else {\\n      box-shadow: 0 0 0 $btn-focus-width rgba(mix(color-yiq($background), $border, 15%), .5);\\n    }\\n  }\\n\\n  // Disabled comes first so active can properly restyle\\n  \u0026.disabled,\\n  \u0026:disabled {\\n    color: color-yiq($background);\\n    background-color: $background;\\n    border-color: $border;\\n    // Remove CSS gradients if they're enabled\\n    @if $enable-gradients {\\n      background-image: none;\\n    }\\n  }\\n\\n  \u0026:not(:disabled):not(.disabled):active,\\n  \u0026:not(:disabled):not(.disabled).active,\\n  .show \u003e \u0026.dropdown-toggle {\\n    color: color-yiq($active-background);\\n    background-color: $active-background;\\n    @if $enable-gradients {\\n      background-image: none; // Remove the gradient for the pressed/active state\\n    }\\n    border-color: $active-border;\\n\\n    \u0026:focus {\\n      // Avoid using mixin so we can pass custom focus shadow properly\\n      @if $enable-shadows and $btn-active-box-shadow != none {\\n        box-shadow: $btn-active-box-shadow, 0 0 0 $btn-focus-width rgba(mix(color-yiq($background), $border, 15%), .5);\\n      } @else {\\n        box-shadow: 0 0 0 $btn-focus-width rgba(mix(color-yiq($background), $border, 15%), .5);\\n      }\\n    }\\n  }\\n}\\n\\n@mixin button-outline-variant($color, $color-hover: color-yiq($color), $active-background: $color, $active-border: $color) {\\n  color: $color;\\n  border-color: $color;\\n\\n  @include hover {\\n    color: $color-hover;\\n    background-color: $active-background;\\n    border-color: $active-border;\\n  }\\n\\n  \u0026:focus,\\n  \u0026.focus {\\n    box-shadow: 0 0 0 $btn-focus-width rgba($color, .5);\\n  }\\n\\n  \u0026.disabled,\\n  \u0026:disabled {\\n    color: $color;\\n    background-color: transparent;\\n  }\\n\\n  \u0026:not(:disabled):not(.disabled):active,\\n  \u0026:not(:disabled):not(.disabled).active,\\n  .show \u003e \u0026.dropdown-toggle {\\n    color: color-yiq($active-background);\\n    background-color: $active-background;\\n    border-color: $active-border;\\n\\n    \u0026:focus {\\n      // Avoid using mixin so we can pass custom focus shadow properly\\n      @if $enable-shadows and $btn-active-box-shadow != none {\\n        box-shadow: $btn-active-box-shadow, 0 0 0 $btn-focus-width rgba($color, .5);\\n      } @else {\\n        box-shadow: 0 0 0 $btn-focus-width rgba($color, .5);\\n      }\\n    }\\n  }\\n}\\n\\n// Button sizes\\n@mixin button-size($padding-y, $padding-x, $font-size, $line-height, $border-radius) {\\n  padding: $padding-y $padding-x;\\n  @include font-size($font-size);\\n  line-height: $line-height;\\n  // Manually declare to provide an override to the browser default\\n  @include border-radius($border-radius, 0);\\n}\\n\",","\t\t\"@mixin caret-down {\\n  border-top: $caret-width solid;\\n  border-right: $caret-width solid transparent;\\n  border-bottom: 0;\\n  border-left: $caret-width solid transparent;\\n}\\n\\n@mixin caret-up {\\n  border-top: 0;\\n  border-right: $caret-width solid transparent;\\n  border-bottom: $caret-width solid;\\n  border-left: $caret-width solid transparent;\\n}\\n\\n@mixin caret-right {\\n  border-top: $caret-width solid transparent;\\n  border-right: 0;\\n  border-bottom: $caret-width solid transparent;\\n  border-left: $caret-width solid;\\n}\\n\\n@mixin caret-left {\\n  border-top: $caret-width solid transparent;\\n  border-right: $caret-width solid;\\n  border-bottom: $caret-width solid transparent;\\n}\\n\\n@mixin caret($direction: down) {\\n  @if $enable-caret {\\n    \u0026::after {\\n      display: inline-block;\\n      margin-left: $caret-spacing;\\n      vertical-align: $caret-vertical-align;\\n      content: \\\"\\\";\\n      @if $direction == down {\\n        @include caret-down;\\n      } @else if $direction == up {\\n        @include caret-up;\\n      } @else if $direction == right {\\n        @include caret-right;\\n      }\\n    }\\n\\n    @if $direction == left {\\n      \u0026::after {\\n        display: none;\\n      }\\n\\n      \u0026::before {\\n        display: inline-block;\\n        margin-right: $caret-spacing;\\n        vertical-align: $caret-vertical-align;\\n        content: \\\"\\\";\\n        @include caret-left;\\n      }\\n    }\\n\\n    \u0026:empty::after {\\n      margin-left: 0;\\n    }\\n  }\\n}\\n\",","\t\t\"// Pagination\\n\\n@mixin pagination-size($padding-y, $padding-x, $font-size, $line-height, $border-radius) {\\n  .page-link {\\n    padding: $padding-y $padding-x;\\n    @include font-size($font-size);\\n    line-height: $line-height;\\n  }\\n\\n  .page-item {\\n    \u0026:first-child {\\n      .page-link {\\n        @include border-left-radius($border-radius);\\n      }\\n    }\\n    \u0026:last-child {\\n      .page-link {\\n        @include border-right-radius($border-radius);\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"// Lists\\n\\n// Unstyled keeps list items block level, just removes default browser padding and list-style\\n@mixin list-unstyled {\\n  padding-left: 0;\\n  list-style: none;\\n}\\n\",","\t\t\"// List Groups\\n\\n@mixin list-group-item-variant($state, $background, $color) {\\n  .list-group-item-#{$state} {\\n    color: $color;\\n    background-color: $background;\\n\\n    \u0026.list-group-item-action {\\n      @include hover-focus {\\n        color: $color;\\n        background-color: darken($background, 5%);\\n      }\\n\\n      \u0026.active {\\n        color: $white;\\n        background-color: $color;\\n        border-color: $color;\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"// Horizontal dividers\\n//\\n// Dividers (basically an hr) within dropdowns and nav lists\\n\\n@mixin nav-divider($color: $nav-divider-color, $margin-y: $nav-divider-margin-y) {\\n  height: 0;\\n  margin: $margin-y 0;\\n  overflow: hidden;\\n  border-top: 1px solid $color;\\n}\\n\",","\t\t\"// Form control focus state\\n//\\n// Generate a customized focus state and for any input with the specified color,\\n// which defaults to the `$input-focus-border-color` variable.\\n//\\n// We highly encourage you to not customize the default value, but instead use\\n// this to tweak colors on an as-needed basis. This aesthetic change is based on\\n// WebKit's default styles, but applicable to a wider range of browsers. Its\\n// usability and accessibility should be taken into account with any change.\\n//\\n// Example usage: change the default blue border and shadow to white for better\\n// contrast against a dark gray background.\\n@mixin form-control-focus() {\\n  \u0026:focus {\\n    color: $input-focus-color;\\n    background-color: $input-focus-bg;\\n    border-color: $input-focus-border-color;\\n    outline: 0;\\n    // Avoid using mixin so we can pass custom focus shadow properly\\n    @if $enable-shadows {\\n      box-shadow: $input-box-shadow, $input-focus-box-shadow;\\n    } @else {\\n      box-shadow: $input-focus-box-shadow;\\n    }\\n  }\\n}\\n\\n\\n@mixin form-validation-state($state, $color, $icon) {\\n  .#{$state}-feedback {\\n    display: none;\\n    width: 100%;\\n    margin-top: $form-feedback-margin-top;\\n    @include font-size($form-feedback-font-size);\\n    color: $color;\\n  }\\n\\n  .#{$state}-tooltip {\\n    position: absolute;\\n    top: 100%;\\n    z-index: 5;\\n    display: none;\\n    max-width: 100%; // Contain to parent when possible\\n    padding: $form-feedback-tooltip-padding-y $form-feedback-tooltip-padding-x;\\n    margin-top: .1rem;\\n    @include font-size($form-feedback-tooltip-font-size);\\n    line-height: $form-feedback-tooltip-line-height;\\n    color: color-yiq($color);\\n    background-color: rgba($color, $form-feedback-tooltip-opacity);\\n    @include border-radius($form-feedback-tooltip-border-radius);\\n  }\\n\\n  .form-control {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      border-color: $color;\\n\\n      @if $enable-validation-icons {\\n        padding-right: $input-height-inner;\\n        background-image: $icon;\\n        background-repeat: no-repeat;\\n        background-position: center right $input-height-inner-quarter;\\n        background-size: $input-height-inner-half $input-height-inner-half;\\n      }\\n\\n      \u0026:focus {\\n        border-color: $color;\\n        box-shadow: 0 0 0 $input-focus-width rgba($color, .25);\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n    }\\n  }\\n\\n  // stylelint-disable-next-line selector-no-qualifying-type\\n  textarea.form-control {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      @if $enable-validation-icons {\\n        padding-right: $input-height-inner;\\n        background-position: top $input-height-inner-quarter right $input-height-inner-quarter;\\n      }\\n    }\\n  }\\n\\n  .custom-select {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      border-color: $color;\\n\\n      @if $enable-validation-icons {\\n        padding-right: $custom-select-feedback-icon-padding-right;\\n        background: $custom-select-background, $icon $custom-select-bg no-repeat $custom-select-feedback-icon-position / $custom-select-feedback-icon-size;\\n      }\\n\\n      \u0026:focus {\\n        border-color: $color;\\n        box-shadow: 0 0 0 $input-focus-width rgba($color, .25);\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n    }\\n  }\\n\\n\\n  .form-control-file {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n    }\\n  }\\n\\n  .form-check-input {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .form-check-label {\\n        color: $color;\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n    }\\n  }\\n\\n  .custom-control-input {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .custom-control-label {\\n        color: $color;\\n\\n        \u0026::before {\\n          border-color: $color;\\n        }\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n\\n      \u0026:checked {\\n        ~ .custom-control-label::before {\\n          border-color: lighten($color, 10%);\\n          @include gradient-bg(lighten($color, 10%));\\n        }\\n      }\\n\\n      \u0026:focus {\\n        ~ .custom-control-label::before {\\n          box-shadow: 0 0 0 $input-focus-width rgba($color, .25);\\n        }\\n\\n        \u0026:not(:checked) ~ .custom-control-label::before {\\n          border-color: $color;\\n        }\\n      }\\n    }\\n  }\\n\\n  // custom file\\n  .custom-file-input {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .custom-file-label {\\n        border-color: $color;\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n\\n      \u0026:focus {\\n        ~ .custom-file-label {\\n          border-color: $color;\\n          box-shadow: 0 0 0 $input-focus-width rgba($color, .25);\\n        }\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"// Tables\\n\\n@mixin table-row-variant($state, $background, $border: null) {\\n  // Exact selectors below required to override `.table-striped` and prevent\\n  // inheritance to nested tables.\\n  .table-#{$state} {\\n    \u0026,\\n    \u003e th,\\n    \u003e td {\\n      background-color: $background;\\n    }\\n\\n    @if $border != null {\\n      th,\\n      td,\\n      thead th,\\n      tbody + tbody {\\n        border-color: $border;\\n      }\\n    }\\n  }\\n\\n  // Hover states for `.table-hover`\\n  // Note: this is not available for cells or rows within `thead` or `tfoot`.\\n  .table-hover {\\n    $hover-background: darken($background, 5%);\\n\\n    .table-#{$state} {\\n      @include hover {\\n        background-color: $hover-background;\\n\\n        \u003e td,\\n        \u003e th {\\n          background-color: $hover-background;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Contextual backgrounds\\n\\n@mixin bg-variant($parent, $color) {\\n  #{$parent} {\\n    background-color: $color !important;\\n  }\\n  a#{$parent},\\n  button#{$parent} {\\n    @include hover-focus {\\n      background-color: darken($color, 10%) !important;\\n    }\\n  }\\n}\\n\\n@mixin bg-gradient-variant($parent, $color) {\\n  #{$parent} {\\n    background: $color linear-gradient(180deg, mix($body-bg, $color, 15%), $color) repeat-x !important;\\n  }\\n}\\n\",","\t\t\"// stylelint-disable property-blacklist\\n// Single side border-radius\\n\\n@mixin border-radius($radius: $border-radius, $fallback-border-radius: false) {\\n  @if $enable-rounded {\\n    border-radius: $radius;\\n  }\\n  @else if $fallback-border-radius != false {\\n    border-radius: $fallback-border-radius;\\n  }\\n}\\n\\n@mixin border-top-radius($radius) {\\n  @if $enable-rounded {\\n    border-top-left-radius: $radius;\\n    border-top-right-radius: $radius;\\n  }\\n}\\n\\n@mixin border-right-radius($radius) {\\n  @if $enable-rounded {\\n    border-top-right-radius: $radius;\\n    border-bottom-right-radius: $radius;\\n  }\\n}\\n\\n@mixin border-bottom-radius($radius) {\\n  @if $enable-rounded {\\n    border-bottom-right-radius: $radius;\\n    border-bottom-left-radius: $radius;\\n  }\\n}\\n\\n@mixin border-left-radius($radius) {\\n  @if $enable-rounded {\\n    border-top-left-radius: $radius;\\n    border-bottom-left-radius: $radius;\\n  }\\n}\\n\\n@mixin border-top-left-radius($radius) {\\n  @if $enable-rounded {\\n    border-top-left-radius: $radius;\\n  }\\n}\\n\\n@mixin border-top-right-radius($radius) {\\n  @if $enable-rounded {\\n    border-top-right-radius: $radius;\\n  }\\n}\\n\\n@mixin border-bottom-right-radius($radius) {\\n  @if $enable-rounded {\\n    border-bottom-right-radius: $radius;\\n  }\\n}\\n\\n@mixin border-bottom-left-radius($radius) {\\n  @if $enable-rounded {\\n    border-bottom-left-radius: $radius;\\n  }\\n}\\n\",","\t\t\"@mixin box-shadow($shadow...) {\\n  @if $enable-shadows {\\n    $result: ();\\n\\n    @if (length($shadow) == 1) {\\n      // We can pass `@include box-shadow(none);`\\n      $result: $shadow;\\n    } @else {\\n      // Filter to avoid invalid properties for example `box-shadow: none, 1px 1px black;`\\n      @for $i from 1 through length($shadow) {\\n        @if nth($shadow, $i) != \\\"none\\\" {\\n          $result: append($result, nth($shadow, $i), \\\"comma\\\");\\n        }\\n      }\\n    }\\n    @if (length($result) \u003e 0) {\\n      box-shadow: $result;\\n    }\\n  }\\n}\\n\",","\t\t\"// Gradients\\n\\n@mixin gradient-bg($color) {\\n  @if $enable-gradients {\\n    background: $color linear-gradient(180deg, mix($body-bg, $color, 15%), $color) repeat-x;\\n  } @else {\\n    background-color: $color;\\n  }\\n}\\n\\n// Horizontal gradient, from left to right\\n//\\n// Creates two color stops, start and end, by specifying a color and position for each color stop.\\n@mixin gradient-x($start-color: $gray-700, $end-color: $gray-800, $start-percent: 0%, $end-percent: 100%) {\\n  background-image: linear-gradient(to right, $start-color $start-percent, $end-color $end-percent);\\n  background-repeat: repeat-x;\\n}\\n\\n// Vertical gradient, from top to bottom\\n//\\n// Creates two color stops, start and end, by specifying a color and position for each color stop.\\n@mixin gradient-y($start-color: $gray-700, $end-color: $gray-800, $start-percent: 0%, $end-percent: 100%) {\\n  background-image: linear-gradient(to bottom, $start-color $start-percent, $end-color $end-percent);\\n  background-repeat: repeat-x;\\n}\\n\\n@mixin gradient-directional($start-color: $gray-700, $end-color: $gray-800, $deg: 45deg) {\\n  background-image: linear-gradient($deg, $start-color, $end-color);\\n  background-repeat: repeat-x;\\n}\\n@mixin gradient-x-three-colors($start-color: $blue, $mid-color: $purple, $color-stop: 50%, $end-color: $red) {\\n  background-image: linear-gradient(to right, $start-color, $mid-color $color-stop, $end-color);\\n  background-repeat: no-repeat;\\n}\\n@mixin gradient-y-three-colors($start-color: $blue, $mid-color: $purple, $color-stop: 50%, $end-color: $red) {\\n  background-image: linear-gradient($start-color, $mid-color $color-stop, $end-color);\\n  background-repeat: no-repeat;\\n}\\n@mixin gradient-radial($inner-color: $gray-700, $outer-color: $gray-800) {\\n  background-image: radial-gradient(circle, $inner-color, $outer-color);\\n  background-repeat: no-repeat;\\n}\\n@mixin gradient-striped($color: rgba($white, .15), $angle: 45deg) {\\n  background-image: linear-gradient($angle, $color 25%, transparent 25%, transparent 50%, $color 50%, $color 75%, transparent 75%, transparent);\\n}\\n\",","\t\t\"// stylelint-disable property-blacklist\\n@mixin transition($transition...) {\\n  @if $enable-transitions {\\n    @if length($transition) == 0 {\\n      transition: $transition-base;\\n    } @else {\\n      transition: $transition;\\n    }\\n  }\\n\\n  @if $enable-prefers-reduced-motion-media-query {\\n    @media (prefers-reduced-motion: reduce) {\\n      transition: none;\\n    }\\n  }\\n}\\n\",","\t\t\"@mixin clearfix() {\\n  \u0026::after {\\n    display: block;\\n    clear: both;\\n    content: \\\"\\\";\\n  }\\n}\\n\",","\t\t\"// Framework grid generation\\n//\\n// Used only by Bootstrap to generate the correct number of grid classes given\\n// any value of `$grid-columns`.\\n\\n@mixin make-grid-columns($columns: $grid-columns, $gutter: $grid-gutter-width, $breakpoints: $grid-breakpoints) {\\n  // Common properties for all breakpoints\\n  %grid-column {\\n    position: relative;\\n    width: 100%;\\n    padding-right: $gutter / 2;\\n    padding-left: $gutter / 2;\\n  }\\n\\n  @each $breakpoint in map-keys($breakpoints) {\\n    $infix: breakpoint-infix($breakpoint, $breakpoints);\\n\\n    // Allow columns to stretch full width below their breakpoints\\n    @for $i from 1 through $columns {\\n      .col#{$infix}-#{$i} {\\n        @extend %grid-column;\\n      }\\n    }\\n    .col#{$infix},\\n    .col#{$infix}-auto {\\n      @extend %grid-column;\\n    }\\n\\n    @include media-breakpoint-up($breakpoint, $breakpoints) {\\n      // Provide basic `.col-{bp}` classes for equal-width flexbox columns\\n      .col#{$infix} {\\n        flex-basis: 0;\\n        flex-grow: 1;\\n        max-width: 100%;\\n      }\\n      .col#{$infix}-auto {\\n        flex: 0 0 auto;\\n        width: auto;\\n        max-width: 100%; // Reset earlier grid tiers\\n      }\\n\\n      @for $i from 1 through $columns {\\n        .col#{$infix}-#{$i} {\\n          @include make-col($i, $columns);\\n        }\\n      }\\n\\n      .order#{$infix}-first { order: -1; }\\n\\n      .order#{$infix}-last { order: $columns + 1; }\\n\\n      @for $i from 0 through $columns {\\n        .order#{$infix}-#{$i} { order: $i; }\\n      }\\n\\n      // `$columns - 1` because offsetting by the width of an entire row isn't possible\\n      @for $i from 0 through ($columns - 1) {\\n        @if not ($infix == \\\"\\\" and $i == 0) { // Avoid emitting useless .offset-0\\n          .offset#{$infix}-#{$i} {\\n            @include make-col-offset($i, $columns);\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"/// Grid system\\n//\\n// Generate semantic grid columns with these mixins.\\n\\n@mixin make-container($gutter: $grid-gutter-width) {\\n  width: 100%;\\n  padding-right: $gutter / 2;\\n  padding-left: $gutter / 2;\\n  margin-right: auto;\\n  margin-left: auto;\\n}\\n\\n\\n// For each breakpoint, define the maximum width of the container in a media query\\n@mixin make-container-max-widths($max-widths: $container-max-widths, $breakpoints: $grid-breakpoints) {\\n  @each $breakpoint, $container-max-width in $max-widths {\\n    @include media-breakpoint-up($breakpoint, $breakpoints) {\\n      max-width: $container-max-width;\\n    }\\n  }\\n}\\n\\n@mixin make-row($gutter: $grid-gutter-width) {\\n  display: flex;\\n  flex-wrap: wrap;\\n  margin-right: -$gutter / 2;\\n  margin-left: -$gutter / 2;\\n}\\n\\n@mixin make-col-ready($gutter: $grid-gutter-width) {\\n  position: relative;\\n  // Prevent columns from becoming too narrow when at smaller grid tiers by\\n  // always setting `width: 100%;`. This works because we use `flex` values\\n  // later on to override this initial width.\\n  width: 100%;\\n  padding-right: $gutter / 2;\\n  padding-left: $gutter / 2;\\n}\\n\\n@mixin make-col($size, $columns: $grid-columns) {\\n  flex: 0 0 percentage($size / $columns);\\n  // Add a `max-width` to ensure content within each column does not blow out\\n  // the width of the column. Applies to IE10+ and Firefox. Chrome and Safari\\n  // do not appear to require this.\\n  max-width: percentage($size / $columns);\\n}\\n\\n@mixin make-col-offset($size, $columns: $grid-columns) {\\n  $num: $size / $columns;\\n  margin-left: if($num == 0, 0, percentage($num));\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n@mixin float-left {\\n  float: left !important;\\n  @include deprecate(\\\"The `float-left` mixin\\\", \\\"v4.3.0\\\", \\\"v5\\\");\\n}\\n@mixin float-right {\\n  float: right !important;\\n  @include deprecate(\\\"The `float-right` mixin\\\", \\\"v4.3.0\\\", \\\"v5\\\");\\n}\\n@mixin float-none {\\n  float: none !important;\\n  @include deprecate(\\\"The `float-none` mixin\\\", \\\"v4.3.0\\\", \\\"v5\\\");\\n}\\n\",","\t\t\":root {\\n  // Custom variable values only support SassScript inside `#{}`.\\n  @each $color, $value in $colors {\\n    --#{$color}: #{$value};\\n  }\\n\\n  @each $color, $value in $theme-colors {\\n    --#{$color}: #{$value};\\n  }\\n\\n  @each $bp, $value in $grid-breakpoints {\\n    --breakpoint-#{$bp}: #{$value};\\n  }\\n\\n  // Use `inspect` for lists so that quoted items keep the quotes.\\n  // See https://github.com/sass/sass/issues/2383#issuecomment-336349172\\n  --font-family-sans-serif: #{inspect($font-family-sans-serif)};\\n  --font-family-monospace: #{inspect($font-family-monospace)};\\n}\\n\",","\t\t\"// stylelint-disable at-rule-no-vendor-prefix, declaration-no-important, selector-no-qualifying-type, property-no-vendor-prefix\\n\\n// Reboot\\n//\\n// Normalization of HTML elements, manually forked from Normalize.css to remove\\n// styles targeting irrelevant browsers while applying new styles.\\n//\\n// Normalize is licensed MIT. https://github.com/necolas/normalize.css\\n\\n\\n// Document\\n//\\n// 1. Change from `box-sizing: content-box` so that `width` is not affected by `padding` or `border`.\\n// 2. Change the default font family in all browsers.\\n// 3. Correct the line height in all browsers.\\n// 4. Prevent adjustments of font size after orientation changes in IE on Windows Phone and in iOS.\\n// 5. Change the default tap highlight to be completely transparent in iOS.\\n\\n*,\\n*::before,\\n*::after {\\n  box-sizing: border-box; // 1\\n}\\n\\nhtml {\\n  font-family: sans-serif; // 2\\n  line-height: 1.15; // 3\\n  -webkit-text-size-adjust: 100%; // 4\\n  -webkit-tap-highlight-color: rgba($black, 0); // 5\\n}\\n\\n// Shim for \\\"new\\\" HTML5 structural elements to display correctly (IE10, older browsers)\\n// TODO: remove in v5\\n// stylelint-disable-next-line selector-list-comma-newline-after\\narticle, aside, figcaption, figure, footer, header, hgroup, main, nav, section {\\n  display: block;\\n}\\n\\n// Body\\n//\\n// 1. Remove the margin in all browsers.\\n// 2. As a best practice, apply a default `background-color`.\\n// 3. Set an explicit initial text-align value so that we can later use\\n//    the `inherit` value on things like `\u003cth\u003e` elements.\\n\\nbody {\\n  margin: 0; // 1\\n  font-family: $font-family-base;\\n  @include font-size($font-size-base);\\n  font-weight: $font-weight-base;\\n  line-height: $line-height-base;\\n  color: $body-color;\\n  text-align: left; // 3\\n  background-color: $body-bg; // 2\\n}\\n\\n// Suppress the focus outline on elements that cannot be accessed via keyboard.\\n// This prevents an unwanted focus outline from appearing around elements that\\n// might still respond to pointer events.\\n//\\n// Credit: https://github.com/suitcss/base\\n[tabindex=\\\"-1\\\"]:focus {\\n  outline: 0 !important;\\n}\\n\\n\\n// Content grouping\\n//\\n// 1. Add the correct box sizing in Firefox.\\n// 2. Show the overflow in Edge and IE.\\n\\nhr {\\n  box-sizing: content-box; // 1\\n  height: 0; // 1\\n  overflow: visible; // 2\\n}\\n\\n\\n//\\n// Typography\\n//\\n\\n// Remove top margins from headings\\n//\\n// By default, `\u003ch1\u003e`-`\u003ch6\u003e` all receive top and bottom margins. We nuke the top\\n// margin for easier control within type scales as it avoids margin collapsing.\\n// stylelint-disable-next-line selector-list-comma-newline-after\\nh1, h2, h3, h4, h5, h6 {\\n  margin-top: 0;\\n  margin-bottom: $headings-margin-bottom;\\n}\\n\\n// Reset margins on paragraphs\\n//\\n// Similarly, the top margin on `\u003cp\u003e`s get reset. However, we also reset the\\n// bottom margin to use `rem` units instead of `em`.\\np {\\n  margin-top: 0;\\n  margin-bottom: $paragraph-margin-bottom;\\n}\\n\\n// Abbreviations\\n//\\n// 1. Duplicate behavior to the data-* attribute for our tooltip plugin\\n// 2. Add the correct text decoration in Chrome, Edge, IE, Opera, and Safari.\\n// 3. Add explicit cursor to indicate changed behavior.\\n// 4. Remove the bottom border in Firefox 39-.\\n// 5. Prevent the text-decoration to be skipped.\\n\\nabbr[title],\\nabbr[data-original-title] { // 1\\n  text-decoration: underline; // 2\\n  text-decoration: underline dotted; // 2\\n  cursor: help; // 3\\n  border-bottom: 0; // 4\\n  text-decoration-skip-ink: none; // 5\\n}\\n\\naddress {\\n  margin-bottom: 1rem;\\n  font-style: normal;\\n  line-height: inherit;\\n}\\n\\nol,\\nul,\\ndl {\\n  margin-top: 0;\\n  margin-bottom: 1rem;\\n}\\n\\nol ol,\\nul ul,\\nol ul,\\nul ol {\\n  margin-bottom: 0;\\n}\\n\\ndt {\\n  font-weight: $dt-font-weight;\\n}\\n\\ndd {\\n  margin-bottom: .5rem;\\n  margin-left: 0; // Undo browser default\\n}\\n\\nblockquote {\\n  margin: 0 0 1rem;\\n}\\n\\nb,\\nstrong {\\n  font-weight: $font-weight-bolder; // Add the correct font weight in Chrome, Edge, and Safari\\n}\\n\\nsmall {\\n  @include font-size(80%); // Add the correct font size in all browsers\\n}\\n\\n//\\n// Prevent `sub` and `sup` elements from affecting the line height in\\n// all browsers.\\n//\\n\\nsub,\\nsup {\\n  position: relative;\\n  @include font-size(75%);\\n  line-height: 0;\\n  vertical-align: baseline;\\n}\\n\\nsub { bottom: -.25em; }\\nsup { top: -.5em; }\\n\\n\\n//\\n// Links\\n//\\n\\na {\\n  color: $link-color;\\n  text-decoration: $link-decoration;\\n  background-color: transparent; // Remove the gray background on active links in IE 10.\\n\\n  @include hover {\\n    color: $link-hover-color;\\n    text-decoration: $link-hover-decoration;\\n  }\\n}\\n\\n// And undo these styles for placeholder links/named anchors (without href)\\n// which have not been made explicitly keyboard-focusable (without tabindex).\\n// It would be more straightforward to just use a[href] in previous block, but that\\n// causes specificity issues in many other styles that are too complex to fix.\\n// See https://github.com/twbs/bootstrap/issues/19402\\n\\na:not([href]):not([tabindex]) {\\n  color: inherit;\\n  text-decoration: none;\\n\\n  @include hover-focus {\\n    color: inherit;\\n    text-decoration: none;\\n  }\\n\\n  \u0026:focus {\\n    outline: 0;\\n  }\\n}\\n\\n\\n//\\n// Code\\n//\\n\\npre,\\ncode,\\nkbd,\\nsamp {\\n  font-family: $font-family-monospace;\\n  @include font-size(1em); // Correct the odd `em` font sizing in all browsers.\\n}\\n\\npre {\\n  // Remove browser default top margin\\n  margin-top: 0;\\n  // Reset browser default of `1em` to use `rem`s\\n  margin-bottom: 1rem;\\n  // Don't allow content to break outside\\n  overflow: auto;\\n}\\n\\n\\n//\\n// Figures\\n//\\n\\nfigure {\\n  // Apply a consistent margin strategy (matches our type styles).\\n  margin: 0 0 1rem;\\n}\\n\\n\\n//\\n// Images and content\\n//\\n\\nimg {\\n  vertical-align: middle;\\n  border-style: none; // Remove the border on images inside links in IE 10-.\\n}\\n\\nsvg {\\n  // Workaround for the SVG overflow bug in IE10/11 is still required.\\n  // See https://github.com/twbs/bootstrap/issues/26878\\n  overflow: hidden;\\n  vertical-align: middle;\\n}\\n\\n\\n//\\n// Tables\\n//\\n\\ntable {\\n  border-collapse: collapse; // Prevent double borders\\n}\\n\\ncaption {\\n  padding-top: $table-cell-padding;\\n  padding-bottom: $table-cell-padding;\\n  color: $table-caption-color;\\n  text-align: left;\\n  caption-side: bottom;\\n}\\n\\nth {\\n  // Matches default `\u003ctd\u003e` alignment by inheriting from the `\u003cbody\u003e`, or the\\n  // closest parent with a set `text-align`.\\n  text-align: inherit;\\n}\\n\\n\\n//\\n// Forms\\n//\\n\\nlabel {\\n  // Allow labels to use `margin` for spacing.\\n  display: inline-block;\\n  margin-bottom: $label-margin-bottom;\\n}\\n\\n// Remove the default `border-radius` that macOS Chrome adds.\\n//\\n// Details at https://github.com/twbs/bootstrap/issues/24093\\nbutton {\\n  // stylelint-disable-next-line property-blacklist\\n  border-radius: 0;\\n}\\n\\n// Work around a Firefox/IE bug where the transparent `button` background\\n// results in a loss of the default `button` focus styles.\\n//\\n// Credit: https://github.com/suitcss/base/\\nbutton:focus {\\n  outline: 1px dotted;\\n  outline: 5px auto -webkit-focus-ring-color;\\n}\\n\\ninput,\\nbutton,\\nselect,\\noptgroup,\\ntextarea {\\n  margin: 0; // Remove the margin in Firefox and Safari\\n  font-family: inherit;\\n  @include font-size(inherit);\\n  line-height: inherit;\\n}\\n\\nbutton,\\ninput {\\n  overflow: visible; // Show the overflow in Edge\\n}\\n\\nbutton,\\nselect {\\n  text-transform: none; // Remove the inheritance of text transform in Firefox\\n}\\n\\n// Remove the inheritance of word-wrap in Safari.\\n//\\n// Details at https://github.com/twbs/bootstrap/issues/24990\\nselect {\\n  word-wrap: normal;\\n}\\n\\n\\n// 1. Prevent a WebKit bug where (2) destroys native `audio` and `video`\\n//    controls in Android 4.\\n// 2. Correct the inability to style clickable types in iOS and Safari.\\nbutton,\\n[type=\\\"button\\\"], // 1\\n[type=\\\"reset\\\"],\\n[type=\\\"submit\\\"] {\\n  -webkit-appearance: button; // 2\\n}\\n\\n// Opinionated: add \\\"hand\\\" cursor to non-disabled button elements.\\n@if $enable-pointer-cursor-for-buttons {\\n  button,\\n  [type=\\\"button\\\"],\\n  [type=\\\"reset\\\"],\\n  [type=\\\"submit\\\"] {\\n    \u0026:not(:disabled) {\\n      cursor: pointer;\\n    }\\n  }\\n}\\n\\n// Remove inner border and padding from Firefox, but don't restore the outline like Normalize.\\nbutton::-moz-focus-inner,\\n[type=\\\"button\\\"]::-moz-focus-inner,\\n[type=\\\"reset\\\"]::-moz-focus-inner,\\n[type=\\\"submit\\\"]::-moz-focus-inner {\\n  padding: 0;\\n  border-style: none;\\n}\\n\\ninput[type=\\\"radio\\\"],\\ninput[type=\\\"checkbox\\\"] {\\n  box-sizing: border-box; // 1. Add the correct box sizing in IE 10-\\n  padding: 0; // 2. Remove the padding in IE 10-\\n}\\n\\n\\ninput[type=\\\"date\\\"],\\ninput[type=\\\"time\\\"],\\ninput[type=\\\"datetime-local\\\"],\\ninput[type=\\\"month\\\"] {\\n  // Remove the default appearance of temporal inputs to avoid a Mobile Safari\\n  // bug where setting a custom line-height prevents text from being vertically\\n  // centered within the input.\\n  // See https://bugs.webkit.org/show_bug.cgi?id=139848\\n  // and https://github.com/twbs/bootstrap/issues/11266\\n  -webkit-appearance: listbox;\\n}\\n\\ntextarea {\\n  overflow: auto; // Remove the default vertical scrollbar in IE.\\n  // Textareas should really only resize vertically so they don't break their (horizontal) containers.\\n  resize: vertical;\\n}\\n\\nfieldset {\\n  // Browsers set a default `min-width: min-content;` on fieldsets,\\n  // unlike e.g. `\u003cdiv\u003e`s, which have `min-width: 0;` by default.\\n  // So we reset that to ensure fieldsets behave more like a standard block element.\\n  // See https://github.com/twbs/bootstrap/issues/59\\n  // and https://html.spec.whatwg.org/multipage/#the-fieldset-and-legend-elements\\n  min-width: 0;\\n  // Reset the default outline behavior of fieldsets so they don't affect page layout.\\n  padding: 0;\\n  margin: 0;\\n  border: 0;\\n}\\n\\n// 1. Correct the text wrapping in Edge and IE.\\n// 2. Correct the color inheritance from `fieldset` elements in IE.\\nlegend {\\n  display: block;\\n  width: 100%;\\n  max-width: 100%; // 1\\n  padding: 0;\\n  margin-bottom: .5rem;\\n  @include font-size(1.5rem);\\n  line-height: inherit;\\n  color: inherit; // 2\\n  white-space: normal; // 1\\n}\\n\\nprogress {\\n  vertical-align: baseline; // Add the correct vertical alignment in Chrome, Firefox, and Opera.\\n}\\n\\n// Correct the cursor style of increment and decrement buttons in Chrome.\\n[type=\\\"number\\\"]::-webkit-inner-spin-button,\\n[type=\\\"number\\\"]::-webkit-outer-spin-button {\\n  height: auto;\\n}\\n\\n[type=\\\"search\\\"] {\\n  // This overrides the extra rounded corners on search inputs in iOS so that our\\n  // `.form-control` class can properly style them. Note that this cannot simply\\n  // be added to `.form-control` as it's not specific enough. For details, see\\n  // https://github.com/twbs/bootstrap/issues/11586.\\n  outline-offset: -2px; // 2. Correct the outline style in Safari.\\n  -webkit-appearance: none;\\n}\\n\\n//\\n// Remove the inner padding in Chrome and Safari on macOS.\\n//\\n\\n[type=\\\"search\\\"]::-webkit-search-decoration {\\n  -webkit-appearance: none;\\n}\\n\\n//\\n// 1. Correct the inability to style clickable types in iOS and Safari.\\n// 2. Change font properties to `inherit` in Safari.\\n//\\n\\n::-webkit-file-upload-button {\\n  font: inherit; // 2\\n  -webkit-appearance: button; // 1\\n}\\n\\n//\\n// Correct element displays\\n//\\n\\noutput {\\n  display: inline-block;\\n}\\n\\nsummary {\\n  display: list-item; // Add the correct display in all browsers\\n  cursor: pointer;\\n}\\n\\ntemplate {\\n  display: none; // Add the correct display in IE\\n}\\n\\n// Always hide an element with the `hidden` HTML attribute (from PureCSS).\\n// Needed for proper display in IE 10-.\\n[hidden] {\\n  display: none !important;\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important, selector-list-comma-newline-after\\n\\n//\\n// Headings\\n//\\n\\nh1, h2, h3, h4, h5, h6,\\n.h1, .h2, .h3, .h4, .h5, .h6 {\\n  margin-bottom: $headings-margin-bottom;\\n  font-family: $headings-font-family;\\n  font-weight: $headings-font-weight;\\n  line-height: $headings-line-height;\\n  color: $headings-color;\\n}\\n\\nh1, .h1 { @include font-size($h1-font-size); }\\nh2, .h2 { @include font-size($h2-font-size); }\\nh3, .h3 { @include font-size($h3-font-size); }\\nh4, .h4 { @include font-size($h4-font-size); }\\nh5, .h5 { @include font-size($h5-font-size); }\\nh6, .h6 { @include font-size($h6-font-size); }\\n\\n.lead {\\n  @include font-size($lead-font-size);\\n  font-weight: $lead-font-weight;\\n}\\n\\n// Type display classes\\n.display-1 {\\n  @include font-size($display1-size);\\n  font-weight: $display1-weight;\\n  line-height: $display-line-height;\\n}\\n.display-2 {\\n  @include font-size($display2-size);\\n  font-weight: $display2-weight;\\n  line-height: $display-line-height;\\n}\\n.display-3 {\\n  @include font-size($display3-size);\\n  font-weight: $display3-weight;\\n  line-height: $display-line-height;\\n}\\n.display-4 {\\n  @include font-size($display4-size);\\n  font-weight: $display4-weight;\\n  line-height: $display-line-height;\\n}\\n\\n\\n//\\n// Horizontal rules\\n//\\n\\nhr {\\n  margin-top: $hr-margin-y;\\n  margin-bottom: $hr-margin-y;\\n  border: 0;\\n  border-top: $hr-border-width solid $hr-border-color;\\n}\\n\\n\\n//\\n// Emphasis\\n//\\n\\nsmall,\\n.small {\\n  @include font-size($small-font-size);\\n  font-weight: $font-weight-normal;\\n}\\n\\nmark,\\n.mark {\\n  padding: $mark-padding;\\n  background-color: $mark-bg;\\n}\\n\\n\\n//\\n// Lists\\n//\\n\\n.list-unstyled {\\n  @include list-unstyled;\\n}\\n\\n// Inline turns list items into inline-block\\n.list-inline {\\n  @include list-unstyled;\\n}\\n.list-inline-item {\\n  display: inline-block;\\n\\n  \u0026:not(:last-child) {\\n    margin-right: $list-inline-padding;\\n  }\\n}\\n\\n\\n//\\n// Misc\\n//\\n\\n// Builds on `abbr`\\n.initialism {\\n  @include font-size(90%);\\n  text-transform: uppercase;\\n}\\n\\n// Blockquotes\\n.blockquote {\\n  margin-bottom: $spacer;\\n  @include font-size($blockquote-font-size);\\n}\\n\\n.blockquote-footer {\\n  display: block;\\n  @include font-size($blockquote-small-font-size);\\n  color: $blockquote-small-color;\\n\\n  \u0026::before {\\n    content: \\\"\\\\2014\\\\00A0\\\"; // em dash, nbsp\\n  }\\n}\\n\",","\t\t\"// Responsive images (ensure images don't scale beyond their parents)\\n//\\n// This is purposefully opt-in via an explicit class rather than being the default for all `\u003cimg\u003e`s.\\n// We previously tried the \\\"images are responsive by default\\\" approach in Bootstrap v2,\\n// and abandoned it in Bootstrap v3 because it breaks lots of third-party widgets (including Google Maps)\\n// which weren't expecting the images within themselves to be involuntarily resized.\\n// See also https://github.com/twbs/bootstrap/issues/18178\\n.img-fluid {\\n  @include img-fluid;\\n}\\n\\n\\n// Image thumbnails\\n.img-thumbnail {\\n  padding: $thumbnail-padding;\\n  background-color: $thumbnail-bg;\\n  border: $thumbnail-border-width solid $thumbnail-border-color;\\n  @include border-radius($thumbnail-border-radius);\\n  @include box-shadow($thumbnail-box-shadow);\\n\\n  // Keep them at most 100% wide\\n  @include img-fluid;\\n}\\n\\n//\\n// Figures\\n//\\n\\n.figure {\\n  // Ensures the caption's text aligns with the image.\\n  display: inline-block;\\n}\\n\\n.figure-img {\\n  margin-bottom: $spacer / 2;\\n  line-height: 1;\\n}\\n\\n.figure-caption {\\n  @include font-size($figure-caption-font-size);\\n  color: $figure-caption-color;\\n}\\n\",","\t\t\"// Inline code\\ncode {\\n  @include font-size($code-font-size);\\n  color: $code-color;\\n  word-break: break-word;\\n\\n  // Streamline the style when inside anchors to avoid broken underline and more\\n  a \u003e \u0026 {\\n    color: inherit;\\n  }\\n}\\n\\n// User input typically entered via keyboard\\nkbd {\\n  padding: $kbd-padding-y $kbd-padding-x;\\n  @include font-size($kbd-font-size);\\n  color: $kbd-color;\\n  background-color: $kbd-bg;\\n  @include border-radius($border-radius-sm);\\n  @include box-shadow($kbd-box-shadow);\\n\\n  kbd {\\n    padding: 0;\\n    @include font-size(100%);\\n    font-weight: $nested-kbd-font-weight;\\n    @include box-shadow(none);\\n  }\\n}\\n\\n// Blocks of code\\npre {\\n  display: block;\\n  @include font-size($code-font-size);\\n  color: $pre-color;\\n\\n  // Account for some code outputs that place code tags in pre tags\\n  code {\\n    @include font-size(inherit);\\n    color: inherit;\\n    word-break: normal;\\n  }\\n}\\n\\n// Enable scrollable blocks of code\\n.pre-scrollable {\\n  max-height: $pre-scrollable-max-height;\\n  overflow-y: scroll;\\n}\\n\",","\t\t\"// Container widths\\n//\\n// Set the container width, and override it for fixed navbars in media queries.\\n\\n@if $enable-grid-classes {\\n  .container {\\n    @include make-container();\\n    @include make-container-max-widths();\\n  }\\n}\\n\\n// Fluid container\\n//\\n// Utilizes the mixin meant for fixed width containers, but with 100% width for\\n// fluid, full width layouts.\\n\\n@if $enable-grid-classes {\\n  .container-fluid {\\n    @include make-container();\\n  }\\n}\\n\\n// Row\\n//\\n// Rows contain and clear the floats of your columns.\\n\\n@if $enable-grid-classes {\\n  .row {\\n    @include make-row();\\n  }\\n\\n  // Remove the negative margin from default .row, then the horizontal padding\\n  // from all immediate children columns (to prevent runaway style inheritance).\\n  .no-gutters {\\n    margin-right: 0;\\n    margin-left: 0;\\n\\n    \u003e .col,\\n    \u003e [class*=\\\"col-\\\"] {\\n      padding-right: 0;\\n      padding-left: 0;\\n    }\\n  }\\n}\\n\\n// Columns\\n//\\n// Common styles for small and large grid columns\\n\\n@if $enable-grid-classes {\\n  @include make-grid-columns();\\n}\\n\",","\t\t\"//\\n// Basic Bootstrap table\\n//\\n\\n.table {\\n  width: 100%;\\n  margin-bottom: $spacer;\\n  color: $table-color;\\n  background-color: $table-bg; // Reset for nesting within parents with `background-color`.\\n\\n  th,\\n  td {\\n    padding: $table-cell-padding;\\n    vertical-align: top;\\n    border-top: $table-border-width solid $table-border-color;\\n  }\\n\\n  thead th {\\n    vertical-align: bottom;\\n    border-bottom: (2 * $table-border-width) solid $table-border-color;\\n  }\\n\\n  tbody + tbody {\\n    border-top: (2 * $table-border-width) solid $table-border-color;\\n  }\\n}\\n\\n\\n//\\n// Condensed table w/ half padding\\n//\\n\\n.table-sm {\\n  th,\\n  td {\\n    padding: $table-cell-padding-sm;\\n  }\\n}\\n\\n\\n// Border versions\\n//\\n// Add or remove borders all around the table and between all the columns.\\n\\n.table-bordered {\\n  border: $table-border-width solid $table-border-color;\\n\\n  th,\\n  td {\\n    border: $table-border-width solid $table-border-color;\\n  }\\n\\n  thead {\\n    th,\\n    td {\\n      border-bottom-width: 2 * $table-border-width;\\n    }\\n  }\\n}\\n\\n.table-borderless {\\n  th,\\n  td,\\n  thead th,\\n  tbody + tbody {\\n    border: 0;\\n  }\\n}\\n\\n// Zebra-striping\\n//\\n// Default zebra-stripe styles (alternating gray and transparent backgrounds)\\n\\n.table-striped {\\n  tbody tr:nth-of-type(#{$table-striped-order}) {\\n    background-color: $table-accent-bg;\\n  }\\n}\\n\\n\\n// Hover effect\\n//\\n// Placed here since it has to come after the potential zebra striping\\n\\n.table-hover {\\n  tbody tr {\\n    @include hover {\\n      color: $table-hover-color;\\n      background-color: $table-hover-bg;\\n    }\\n  }\\n}\\n\\n\\n// Table backgrounds\\n//\\n// Exact selectors below required to override `.table-striped` and prevent\\n// inheritance to nested tables.\\n\\n@each $color, $value in $theme-colors {\\n  @include table-row-variant($color, theme-color-level($color, $table-bg-level), theme-color-level($color, $table-border-level));\\n}\\n\\n@include table-row-variant(active, $table-active-bg);\\n\\n\\n// Dark styles\\n//\\n// Same table markup, but inverted color scheme: dark background and light text.\\n\\n// stylelint-disable-next-line no-duplicate-selectors\\n.table {\\n  .thead-dark {\\n    th {\\n      color: $table-dark-color;\\n      background-color: $table-dark-bg;\\n      border-color: $table-dark-border-color;\\n    }\\n  }\\n\\n  .thead-light {\\n    th {\\n      color: $table-head-color;\\n      background-color: $table-head-bg;\\n      border-color: $table-border-color;\\n    }\\n  }\\n}\\n\\n.table-dark {\\n  color: $table-dark-color;\\n  background-color: $table-dark-bg;\\n\\n  th,\\n  td,\\n  thead th {\\n    border-color: $table-dark-border-color;\\n  }\\n\\n  \u0026.table-bordered {\\n    border: 0;\\n  }\\n\\n  \u0026.table-striped {\\n    tbody tr:nth-of-type(odd) {\\n      background-color: $table-dark-accent-bg;\\n    }\\n  }\\n\\n  \u0026.table-hover {\\n    tbody tr {\\n      @include hover {\\n        color: $table-dark-hover-color;\\n        background-color: $table-dark-hover-bg;\\n      }\\n    }\\n  }\\n}\\n\\n\\n// Responsive tables\\n//\\n// Generate series of `.table-responsive-*` classes for configuring the screen\\n// size of where your table will overflow.\\n\\n.table-responsive {\\n  @each $breakpoint in map-keys($grid-breakpoints) {\\n    $next: breakpoint-next($breakpoint, $grid-breakpoints);\\n    $infix: breakpoint-infix($next, $grid-breakpoints);\\n\\n    \u0026#{$infix} {\\n      @include media-breakpoint-down($breakpoint) {\\n        display: block;\\n        width: 100%;\\n        overflow-x: auto;\\n        -webkit-overflow-scrolling: touch;\\n\\n        // Prevent double border on horizontal scroll due to use of `display: block;`\\n        \u003e .table-bordered {\\n          border: 0;\\n        }\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable selector-no-qualifying-type\\n\\n//\\n// Textual form controls\\n//\\n\\n.form-control {\\n  display: block;\\n  width: 100%;\\n  height: $input-height;\\n  padding: $input-padding-y $input-padding-x;\\n  font-family: $input-font-family;\\n  @include font-size($input-font-size);\\n  font-weight: $input-font-weight;\\n  line-height: $input-line-height;\\n  color: $input-color;\\n  background-color: $input-bg;\\n  background-clip: padding-box;\\n  border: $input-border-width solid $input-border-color;\\n\\n  // Note: This has no effect on \u003cselect\u003es in some browsers, due to the limited stylability of `\u003cselect\u003e`s in CSS.\\n  @include border-radius($input-border-radius, 0);\\n\\n  @include box-shadow($input-box-shadow);\\n  @include transition($input-transition);\\n\\n  // Unstyle the caret on `\u003cselect\u003e`s in IE10+.\\n  \u0026::-ms-expand {\\n    background-color: transparent;\\n    border: 0;\\n  }\\n\\n  // Customize the `:focus` state to imitate native WebKit styles.\\n  @include form-control-focus();\\n\\n  // Placeholder\\n  \u0026::placeholder {\\n    color: $input-placeholder-color;\\n    // Override Firefox's unusual default opacity; see https://github.com/twbs/bootstrap/pull/11526.\\n    opacity: 1;\\n  }\\n\\n  // Disabled and read-only inputs\\n  //\\n  // HTML5 says that controls under a fieldset \u003e legend:first-child won't be\\n  // disabled if the fieldset is disabled. Due to implementation difficulty, we\\n  // don't honor that edge case; we style them as disabled anyway.\\n  \u0026:disabled,\\n  \u0026[readonly] {\\n    background-color: $input-disabled-bg;\\n    // iOS fix for unreadable disabled content; see https://github.com/twbs/bootstrap/issues/11655.\\n    opacity: 1;\\n  }\\n}\\n\\nselect.form-control {\\n  \u0026:focus::-ms-value {\\n    // Suppress the nested default white text on blue background highlight given to\\n    // the selected option text when the (still closed) \u003cselect\u003e receives focus\\n    // in IE and (under certain conditions) Edge, as it looks bad and cannot be made to\\n    // match the appearance of the native widget.\\n    // See https://github.com/twbs/bootstrap/issues/19398.\\n    color: $input-color;\\n    background-color: $input-bg;\\n  }\\n}\\n\\n// Make file inputs better match text inputs by forcing them to new lines.\\n.form-control-file,\\n.form-control-range {\\n  display: block;\\n  width: 100%;\\n}\\n\\n\\n//\\n// Labels\\n//\\n\\n// For use with horizontal and inline forms, when you need the label (or legend)\\n// text to align with the form controls.\\n.col-form-label {\\n  padding-top: calc(#{$input-padding-y} + #{$input-border-width});\\n  padding-bottom: calc(#{$input-padding-y} + #{$input-border-width});\\n  margin-bottom: 0; // Override the `\u003clabel\u003e/\u003clegend\u003e` default\\n  @include font-size(inherit); // Override the `\u003clegend\u003e` default\\n  line-height: $input-line-height;\\n}\\n\\n.col-form-label-lg {\\n  padding-top: calc(#{$input-padding-y-lg} + #{$input-border-width});\\n  padding-bottom: calc(#{$input-padding-y-lg} + #{$input-border-width});\\n  @include font-size($input-font-size-lg);\\n  line-height: $input-line-height-lg;\\n}\\n\\n.col-form-label-sm {\\n  padding-top: calc(#{$input-padding-y-sm} + #{$input-border-width});\\n  padding-bottom: calc(#{$input-padding-y-sm} + #{$input-border-width});\\n  @include font-size($input-font-size-sm);\\n  line-height: $input-line-height-sm;\\n}\\n\\n\\n// Readonly controls as plain text\\n//\\n// Apply class to a readonly input to make it appear like regular plain\\n// text (without any border, background color, focus indicator)\\n\\n.form-control-plaintext {\\n  display: block;\\n  width: 100%;\\n  padding-top: $input-padding-y;\\n  padding-bottom: $input-padding-y;\\n  margin-bottom: 0; // match inputs if this class comes on inputs with default margins\\n  line-height: $input-line-height;\\n  color: $input-plaintext-color;\\n  background-color: transparent;\\n  border: solid transparent;\\n  border-width: $input-border-width 0;\\n\\n  \u0026.form-control-sm,\\n  \u0026.form-control-lg {\\n    padding-right: 0;\\n    padding-left: 0;\\n  }\\n}\\n\\n\\n// Form control sizing\\n//\\n// Build on `.form-control` with modifier classes to decrease or increase the\\n// height and font-size of form controls.\\n//\\n// Repeated in `_input_group.scss` to avoid Sass extend issues.\\n\\n.form-control-sm {\\n  height: $input-height-sm;\\n  padding: $input-padding-y-sm $input-padding-x-sm;\\n  @include font-size($input-font-size-sm);\\n  line-height: $input-line-height-sm;\\n  @include border-radius($input-border-radius-sm);\\n}\\n\\n.form-control-lg {\\n  height: $input-height-lg;\\n  padding: $input-padding-y-lg $input-padding-x-lg;\\n  @include font-size($input-font-size-lg);\\n  line-height: $input-line-height-lg;\\n  @include border-radius($input-border-radius-lg);\\n}\\n\\n// stylelint-disable-next-line no-duplicate-selectors\\nselect.form-control {\\n  \u0026[size],\\n  \u0026[multiple] {\\n    height: auto;\\n  }\\n}\\n\\ntextarea.form-control {\\n  height: auto;\\n}\\n\\n// Form groups\\n//\\n// Designed to help with the organization and spacing of vertical forms. For\\n// horizontal forms, use the predefined grid classes.\\n\\n.form-group {\\n  margin-bottom: $form-group-margin-bottom;\\n}\\n\\n.form-text {\\n  display: block;\\n  margin-top: $form-text-margin-top;\\n}\\n\\n\\n// Form grid\\n//\\n// Special replacement for our grid system's `.row` for tighter form layouts.\\n\\n.form-row {\\n  display: flex;\\n  flex-wrap: wrap;\\n  margin-right: -$form-grid-gutter-width / 2;\\n  margin-left: -$form-grid-gutter-width / 2;\\n\\n  \u003e .col,\\n  \u003e [class*=\\\"col-\\\"] {\\n    padding-right: $form-grid-gutter-width / 2;\\n    padding-left: $form-grid-gutter-width / 2;\\n  }\\n}\\n\\n\\n// Checkboxes and radios\\n//\\n// Indent the labels to position radios/checkboxes as hanging controls.\\n\\n.form-check {\\n  position: relative;\\n  display: block;\\n  padding-left: $form-check-input-gutter;\\n}\\n\\n.form-check-input {\\n  position: absolute;\\n  margin-top: $form-check-input-margin-y;\\n  margin-left: -$form-check-input-gutter;\\n\\n  \u0026:disabled ~ .form-check-label {\\n    color: $text-muted;\\n  }\\n}\\n\\n.form-check-label {\\n  margin-bottom: 0; // Override default `\u003clabel\u003e` bottom margin\\n}\\n\\n.form-check-inline {\\n  display: inline-flex;\\n  align-items: center;\\n  padding-left: 0; // Override base .form-check\\n  margin-right: $form-check-inline-margin-x;\\n\\n  // Undo .form-check-input defaults and add some `margin-right`.\\n  .form-check-input {\\n    position: static;\\n    margin-top: 0;\\n    margin-right: $form-check-inline-input-margin-x;\\n    margin-left: 0;\\n  }\\n}\\n\\n\\n// Form validation\\n//\\n// Provide feedback to users when form field values are valid or invalid. Works\\n// primarily for client-side validation via scoped `:invalid` and `:valid`\\n// pseudo-classes but also includes `.is-invalid` and `.is-valid` classes for\\n// server side validation.\\n\\n@each $state, $data in $form-validation-states {\\n  @include form-validation-state($state, map-get($data, color), map-get($data, icon));\\n}\\n\\n// Inline forms\\n//\\n// Make forms appear inline(-block) by adding the `.form-inline` class. Inline\\n// forms begin stacked on extra small (mobile) devices and then go inline when\\n// viewports reach \u003c768px.\\n//\\n// Requires wrapping inputs and labels with `.form-group` for proper display of\\n// default HTML form controls and our custom form controls (e.g., input groups).\\n\\n.form-inline {\\n  display: flex;\\n  flex-flow: row wrap;\\n  align-items: center; // Prevent shorter elements from growing to same height as others (e.g., small buttons growing to normal sized button height)\\n\\n  // Because we use flex, the initial sizing of checkboxes is collapsed and\\n  // doesn't occupy the full-width (which is what we want for xs grid tier),\\n  // so we force that here.\\n  .form-check {\\n    width: 100%;\\n  }\\n\\n  // Kick in the inline\\n  @include media-breakpoint-up(sm) {\\n    label {\\n      display: flex;\\n      align-items: center;\\n      justify-content: center;\\n      margin-bottom: 0;\\n    }\\n\\n    // Inline-block all the things for \\\"inline\\\"\\n    .form-group {\\n      display: flex;\\n      flex: 0 0 auto;\\n      flex-flow: row wrap;\\n      align-items: center;\\n      margin-bottom: 0;\\n    }\\n\\n    // Allow folks to *not* use `.form-group`\\n    .form-control {\\n      display: inline-block;\\n      width: auto; // Prevent labels from stacking above inputs in `.form-group`\\n      vertical-align: middle;\\n    }\\n\\n    // Make static controls behave like regular ones\\n    .form-control-plaintext {\\n      display: inline-block;\\n    }\\n\\n    .input-group,\\n    .custom-select {\\n      width: auto;\\n    }\\n\\n    // Remove default margin on radios/checkboxes that were used for stacking, and\\n    // then undo the floating of radios and checkboxes to match.\\n    .form-check {\\n      display: flex;\\n      align-items: center;\\n      justify-content: center;\\n      width: auto;\\n      padding-left: 0;\\n    }\\n    .form-check-input {\\n      position: relative;\\n      flex-shrink: 0;\\n      margin-top: 0;\\n      margin-right: $form-check-input-margin-x;\\n      margin-left: 0;\\n    }\\n\\n    .custom-control {\\n      align-items: center;\\n      justify-content: center;\\n    }\\n    .custom-control-label {\\n      margin-bottom: 0;\\n    }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable selector-no-qualifying-type\\n\\n//\\n// Base styles\\n//\\n\\n.btn {\\n  display: inline-block;\\n  font-family: $btn-font-family;\\n  font-weight: $btn-font-weight;\\n  color: $body-color;\\n  text-align: center;\\n  vertical-align: middle;\\n  user-select: none;\\n  background-color: transparent;\\n  border: $btn-border-width solid transparent;\\n  @include button-size($btn-padding-y, $btn-padding-x, $btn-font-size, $btn-line-height, $btn-border-radius);\\n  @include transition($btn-transition);\\n\\n  @include hover {\\n    color: $body-color;\\n    text-decoration: none;\\n  }\\n\\n  \u0026:focus,\\n  \u0026.focus {\\n    outline: 0;\\n    box-shadow: $btn-focus-box-shadow;\\n  }\\n\\n  // Disabled comes first so active can properly restyle\\n  \u0026.disabled,\\n  \u0026:disabled {\\n    opacity: $btn-disabled-opacity;\\n    @include box-shadow(none);\\n  }\\n\\n  \u0026:not(:disabled):not(.disabled):active,\\n  \u0026:not(:disabled):not(.disabled).active {\\n    @include box-shadow($btn-active-box-shadow);\\n\\n    \u0026:focus {\\n      @include box-shadow($btn-focus-box-shadow, $btn-active-box-shadow);\\n    }\\n  }\\n}\\n\\n// Future-proof disabling of clicks on `\u003ca\u003e` elements\\na.btn.disabled,\\nfieldset:disabled a.btn {\\n  pointer-events: none;\\n}\\n\\n\\n//\\n// Alternate buttons\\n//\\n\\n@each $color, $value in $theme-colors {\\n  .btn-#{$color} {\\n    @include button-variant($value, $value);\\n  }\\n}\\n\\n@each $color, $value in $theme-colors {\\n  .btn-outline-#{$color} {\\n    @include button-outline-variant($value);\\n  }\\n}\\n\\n\\n//\\n// Link buttons\\n//\\n\\n// Make a button look and behave like a link\\n.btn-link {\\n  font-weight: $font-weight-normal;\\n  color: $link-color;\\n  text-decoration: $link-decoration;\\n\\n  @include hover {\\n    color: $link-hover-color;\\n    text-decoration: $link-hover-decoration;\\n  }\\n\\n  \u0026:focus,\\n  \u0026.focus {\\n    text-decoration: $link-hover-decoration;\\n    box-shadow: none;\\n  }\\n\\n  \u0026:disabled,\\n  \u0026.disabled {\\n    color: $btn-link-disabled-color;\\n    pointer-events: none;\\n  }\\n\\n  // No need for an active state here\\n}\\n\\n\\n//\\n// Button Sizes\\n//\\n\\n.btn-lg {\\n  @include button-size($btn-padding-y-lg, $btn-padding-x-lg, $btn-font-size-lg, $btn-line-height-lg, $btn-border-radius-lg);\\n}\\n\\n.btn-sm {\\n  @include button-size($btn-padding-y-sm, $btn-padding-x-sm, $btn-font-size-sm, $btn-line-height-sm, $btn-border-radius-sm);\\n}\\n\\n\\n//\\n// Block button\\n//\\n\\n.btn-block {\\n  display: block;\\n  width: 100%;\\n\\n  // Vertically space out multiple block buttons\\n  + .btn-block {\\n    margin-top: $btn-block-spacing-y;\\n  }\\n}\\n\\n// Specificity overrides\\ninput[type=\\\"submit\\\"],\\ninput[type=\\\"reset\\\"],\\ninput[type=\\\"button\\\"] {\\n  \u0026.btn-block {\\n    width: 100%;\\n  }\\n}\\n\",","\t\t\".fade {\\n  @include transition($transition-fade);\\n\\n  \u0026:not(.show) {\\n    opacity: 0;\\n  }\\n}\\n\\n.collapse {\\n  \u0026:not(.show) {\\n    display: none;\\n  }\\n}\\n\\n.collapsing {\\n  position: relative;\\n  height: 0;\\n  overflow: hidden;\\n  @include transition($transition-collapse);\\n}\\n\",","\t\t\"// The dropdown wrapper (`\u003cdiv\u003e`)\\n.dropup,\\n.dropright,\\n.dropdown,\\n.dropleft {\\n  position: relative;\\n}\\n\\n.dropdown-toggle {\\n  white-space: nowrap;\\n\\n  // Generate the caret automatically\\n  @include caret;\\n}\\n\\n// The dropdown menu\\n.dropdown-menu {\\n  position: absolute;\\n  top: 100%;\\n  left: 0;\\n  z-index: $zindex-dropdown;\\n  display: none; // none by default, but block on \\\"open\\\" of the menu\\n  float: left;\\n  min-width: $dropdown-min-width;\\n  padding: $dropdown-padding-y 0;\\n  margin: $dropdown-spacer 0 0; // override default ul\\n  @include font-size($dropdown-font-size);\\n  color: $dropdown-color;\\n  text-align: left; // Ensures proper alignment if parent has it changed (e.g., modal footer)\\n  list-style: none;\\n  background-color: $dropdown-bg;\\n  background-clip: padding-box;\\n  border: $dropdown-border-width solid $dropdown-border-color;\\n  @include border-radius($dropdown-border-radius);\\n  @include box-shadow($dropdown-box-shadow);\\n}\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    .dropdown-menu#{$infix}-left {\\n      right: auto;\\n      left: 0;\\n    }\\n\\n    .dropdown-menu#{$infix}-right {\\n      right: 0;\\n      left: auto;\\n    }\\n  }\\n}\\n\\n// Allow for dropdowns to go bottom up (aka, dropup-menu)\\n// Just add .dropup after the standard .dropdown class and you're set.\\n.dropup {\\n  .dropdown-menu {\\n    top: auto;\\n    bottom: 100%;\\n    margin-top: 0;\\n    margin-bottom: $dropdown-spacer;\\n  }\\n\\n  .dropdown-toggle {\\n    @include caret(up);\\n  }\\n}\\n\\n.dropright {\\n  .dropdown-menu {\\n    top: 0;\\n    right: auto;\\n    left: 100%;\\n    margin-top: 0;\\n    margin-left: $dropdown-spacer;\\n  }\\n\\n  .dropdown-toggle {\\n    @include caret(right);\\n    \u0026::after {\\n      vertical-align: 0;\\n    }\\n  }\\n}\\n\\n.dropleft {\\n  .dropdown-menu {\\n    top: 0;\\n    right: 100%;\\n    left: auto;\\n    margin-top: 0;\\n    margin-right: $dropdown-spacer;\\n  }\\n\\n  .dropdown-toggle {\\n    @include caret(left);\\n    \u0026::before {\\n      vertical-align: 0;\\n    }\\n  }\\n}\\n\\n// When enabled Popper.js, reset basic dropdown position\\n// stylelint-disable-next-line no-duplicate-selectors\\n.dropdown-menu {\\n  \u0026[x-placement^=\\\"top\\\"],\\n  \u0026[x-placement^=\\\"right\\\"],\\n  \u0026[x-placement^=\\\"bottom\\\"],\\n  \u0026[x-placement^=\\\"left\\\"] {\\n    right: auto;\\n    bottom: auto;\\n  }\\n}\\n\\n// Dividers (basically an `\u003chr\u003e`) within the dropdown\\n.dropdown-divider {\\n  @include nav-divider($dropdown-divider-bg, $dropdown-divider-margin-y);\\n}\\n\\n// Links, buttons, and more within the dropdown menu\\n//\\n// `\u003cbutton\u003e`-specific styles are denoted with `// For \u003cbutton\u003es`\\n.dropdown-item {\\n  display: block;\\n  width: 100%; // For `\u003cbutton\u003e`s\\n  padding: $dropdown-item-padding-y $dropdown-item-padding-x;\\n  clear: both;\\n  font-weight: $font-weight-normal;\\n  color: $dropdown-link-color;\\n  text-align: inherit; // For `\u003cbutton\u003e`s\\n  white-space: nowrap; // prevent links from randomly breaking onto new lines\\n  background-color: transparent; // For `\u003cbutton\u003e`s\\n  border: 0; // For `\u003cbutton\u003e`s\\n\\n  // Prevent dropdown overflow if there's no padding\\n  // See https://github.com/twbs/bootstrap/pull/27703\\n  @if $dropdown-padding-y == 0 {\\n    \u0026:first-child {\\n      @include border-top-radius($dropdown-inner-border-radius);\\n    }\\n\\n    \u0026:last-child {\\n      @include border-bottom-radius($dropdown-inner-border-radius);\\n    }\\n  }\\n\\n  @include hover-focus {\\n    color: $dropdown-link-hover-color;\\n    text-decoration: none;\\n    @include gradient-bg($dropdown-link-hover-bg);\\n  }\\n\\n  \u0026.active,\\n  \u0026:active {\\n    color: $dropdown-link-active-color;\\n    text-decoration: none;\\n    @include gradient-bg($dropdown-link-active-bg);\\n  }\\n\\n  \u0026.disabled,\\n  \u0026:disabled {\\n    color: $dropdown-link-disabled-color;\\n    pointer-events: none;\\n    background-color: transparent;\\n    // Remove CSS gradients if they're enabled\\n    @if $enable-gradients {\\n      background-image: none;\\n    }\\n  }\\n}\\n\\n.dropdown-menu.show {\\n  display: block;\\n}\\n\\n// Dropdown section headers\\n.dropdown-header {\\n  display: block;\\n  padding: $dropdown-padding-y $dropdown-item-padding-x;\\n  margin-bottom: 0; // for use with heading elements\\n  @include font-size($font-size-sm);\\n  color: $dropdown-header-color;\\n  white-space: nowrap; // as with \u003e li \u003e a\\n}\\n\\n// Dropdown text\\n.dropdown-item-text {\\n  display: block;\\n  padding: $dropdown-item-padding-y $dropdown-item-padding-x;\\n  color: $dropdown-link-color;\\n}\\n\",","\t\t\"// stylelint-disable selector-no-qualifying-type\\n\\n// Make the div behave like a button\\n.btn-group,\\n.btn-group-vertical {\\n  position: relative;\\n  display: inline-flex;\\n  vertical-align: middle; // match .btn alignment given font-size hack above\\n\\n  \u003e .btn {\\n    position: relative;\\n    flex: 1 1 auto;\\n\\n    // Bring the hover, focused, and \\\"active\\\" buttons to the front to overlay\\n    // the borders properly\\n    @include hover {\\n      z-index: 1;\\n    }\\n    \u0026:focus,\\n    \u0026:active,\\n    \u0026.active {\\n      z-index: 1;\\n    }\\n  }\\n}\\n\\n// Optional: Group multiple button groups together for a toolbar\\n.btn-toolbar {\\n  display: flex;\\n  flex-wrap: wrap;\\n  justify-content: flex-start;\\n\\n  .input-group {\\n    width: auto;\\n  }\\n}\\n\\n.btn-group {\\n  // Prevent double borders when buttons are next to each other\\n  \u003e .btn:not(:first-child),\\n  \u003e .btn-group:not(:first-child) {\\n    margin-left: -$btn-border-width;\\n  }\\n\\n  // Reset rounded corners\\n  \u003e .btn:not(:last-child):not(.dropdown-toggle),\\n  \u003e .btn-group:not(:last-child) \u003e .btn {\\n    @include border-right-radius(0);\\n  }\\n\\n  \u003e .btn:not(:first-child),\\n  \u003e .btn-group:not(:first-child) \u003e .btn {\\n    @include border-left-radius(0);\\n  }\\n}\\n\\n// Sizing\\n//\\n// Remix the default button sizing classes into new ones for easier manipulation.\\n\\n.btn-group-sm \u003e .btn { @extend .btn-sm; }\\n.btn-group-lg \u003e .btn { @extend .btn-lg; }\\n\\n\\n//\\n// Split button dropdowns\\n//\\n\\n.dropdown-toggle-split {\\n  padding-right: $btn-padding-x * .75;\\n  padding-left: $btn-padding-x * .75;\\n\\n  \u0026::after,\\n  .dropup \u0026::after,\\n  .dropright \u0026::after {\\n    margin-left: 0;\\n  }\\n\\n  .dropleft \u0026::before {\\n    margin-right: 0;\\n  }\\n}\\n\\n.btn-sm + .dropdown-toggle-split {\\n  padding-right: $btn-padding-x-sm * .75;\\n  padding-left: $btn-padding-x-sm * .75;\\n}\\n\\n.btn-lg + .dropdown-toggle-split {\\n  padding-right: $btn-padding-x-lg * .75;\\n  padding-left: $btn-padding-x-lg * .75;\\n}\\n\\n\\n// The clickable button for toggling the menu\\n// Set the same inset shadow as the :active state\\n.btn-group.show .dropdown-toggle {\\n  @include box-shadow($btn-active-box-shadow);\\n\\n  // Show no shadow for `.btn-link` since it has no other button styles.\\n  \u0026.btn-link {\\n    @include box-shadow(none);\\n  }\\n}\\n\\n\\n//\\n// Vertical button groups\\n//\\n\\n.btn-group-vertical {\\n  flex-direction: column;\\n  align-items: flex-start;\\n  justify-content: center;\\n\\n  \u003e .btn,\\n  \u003e .btn-group {\\n    width: 100%;\\n  }\\n\\n  \u003e .btn:not(:first-child),\\n  \u003e .btn-group:not(:first-child) {\\n    margin-top: -$btn-border-width;\\n  }\\n\\n  // Reset rounded corners\\n  \u003e .btn:not(:last-child):not(.dropdown-toggle),\\n  \u003e .btn-group:not(:last-child) \u003e .btn {\\n    @include border-bottom-radius(0);\\n  }\\n\\n  \u003e .btn:not(:first-child),\\n  \u003e .btn-group:not(:first-child) \u003e .btn {\\n    @include border-top-radius(0);\\n  }\\n}\\n\\n\\n// Checkbox and radio options\\n//\\n// In order to support the browser's form validation feedback, powered by the\\n// `required` attribute, we have to \\\"hide\\\" the inputs via `clip`. We cannot use\\n// `display: none;` or `visibility: hidden;` as that also hides the popover.\\n// Simply visually hiding the inputs via `opacity` would leave them clickable in\\n// certain cases which is prevented by using `clip` and `pointer-events`.\\n// This way, we ensure a DOM element is visible to position the popover from.\\n//\\n// See https://github.com/twbs/bootstrap/pull/12794 and\\n// https://github.com/twbs/bootstrap/pull/14559 for more information.\\n\\n.btn-group-toggle {\\n  \u003e .btn,\\n  \u003e .btn-group \u003e .btn {\\n    margin-bottom: 0; // Override default `\u003clabel\u003e` value\\n\\n    input[type=\\\"radio\\\"],\\n    input[type=\\\"checkbox\\\"] {\\n      position: absolute;\\n      clip: rect(0, 0, 0, 0);\\n      pointer-events: none;\\n    }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable selector-no-qualifying-type\\n\\n//\\n// Base styles\\n//\\n\\n.input-group {\\n  position: relative;\\n  display: flex;\\n  flex-wrap: wrap; // For form validation feedback\\n  align-items: stretch;\\n  width: 100%;\\n\\n  \u003e .form-control,\\n  \u003e .form-control-plaintext,\\n  \u003e .custom-select,\\n  \u003e .custom-file {\\n    position: relative; // For focus state's z-index\\n    flex: 1 1 auto;\\n    // Add width 1% and flex-basis auto to ensure that button will not wrap out\\n    // the column. Applies to IE Edge+ and Firefox. Chrome does not require this.\\n    width: 1%;\\n    margin-bottom: 0;\\n\\n    + .form-control,\\n    + .custom-select,\\n    + .custom-file {\\n      margin-left: -$input-border-width;\\n    }\\n  }\\n\\n  // Bring the \\\"active\\\" form control to the top of surrounding elements\\n  \u003e .form-control:focus,\\n  \u003e .custom-select:focus,\\n  \u003e .custom-file .custom-file-input:focus ~ .custom-file-label {\\n    z-index: 3;\\n  }\\n\\n  // Bring the custom file input above the label\\n  \u003e .custom-file .custom-file-input:focus {\\n    z-index: 4;\\n  }\\n\\n  \u003e .form-control,\\n  \u003e .custom-select {\\n    \u0026:not(:last-child) { @include border-right-radius(0); }\\n    \u0026:not(:first-child) { @include border-left-radius(0); }\\n  }\\n\\n  // Custom file inputs have more complex markup, thus requiring different\\n  // border-radius overrides.\\n  \u003e .custom-file {\\n    display: flex;\\n    align-items: center;\\n\\n    \u0026:not(:last-child) .custom-file-label,\\n    \u0026:not(:last-child) .custom-file-label::after { @include border-right-radius(0); }\\n    \u0026:not(:first-child) .custom-file-label { @include border-left-radius(0); }\\n  }\\n}\\n\\n\\n// Prepend and append\\n//\\n// While it requires one extra layer of HTML for each, dedicated prepend and\\n// append elements allow us to 1) be less clever, 2) simplify our selectors, and\\n// 3) support HTML5 form validation.\\n\\n.input-group-prepend,\\n.input-group-append {\\n  display: flex;\\n\\n  // Ensure buttons are always above inputs for more visually pleasing borders.\\n  // This isn't needed for `.input-group-text` since it shares the same border-color\\n  // as our inputs.\\n  .btn {\\n    position: relative;\\n    z-index: 2;\\n\\n    \u0026:focus {\\n      z-index: 3;\\n    }\\n  }\\n\\n  .btn + .btn,\\n  .btn + .input-group-text,\\n  .input-group-text + .input-group-text,\\n  .input-group-text + .btn {\\n    margin-left: -$input-border-width;\\n  }\\n}\\n\\n.input-group-prepend { margin-right: -$input-border-width; }\\n.input-group-append { margin-left: -$input-border-width; }\\n\\n\\n// Textual addons\\n//\\n// Serves as a catch-all element for any text or radio/checkbox input you wish\\n// to prepend or append to an input.\\n\\n.input-group-text {\\n  display: flex;\\n  align-items: center;\\n  padding: $input-padding-y $input-padding-x;\\n  margin-bottom: 0; // Allow use of \u003clabel\u003e elements by overriding our default margin-bottom\\n  @include font-size($input-font-size); // Match inputs\\n  font-weight: $font-weight-normal;\\n  line-height: $input-line-height;\\n  color: $input-group-addon-color;\\n  text-align: center;\\n  white-space: nowrap;\\n  background-color: $input-group-addon-bg;\\n  border: $input-border-width solid $input-group-addon-border-color;\\n  @include border-radius($input-border-radius);\\n\\n  // Nuke default margins from checkboxes and radios to vertically center within.\\n  input[type=\\\"radio\\\"],\\n  input[type=\\\"checkbox\\\"] {\\n    margin-top: 0;\\n  }\\n}\\n\\n\\n// Sizing\\n//\\n// Remix the default form control sizing classes into new ones for easier\\n// manipulation.\\n\\n.input-group-lg \u003e .form-control:not(textarea),\\n.input-group-lg \u003e .custom-select {\\n  height: $input-height-lg;\\n}\\n\\n.input-group-lg \u003e .form-control,\\n.input-group-lg \u003e .custom-select,\\n.input-group-lg \u003e .input-group-prepend \u003e .input-group-text,\\n.input-group-lg \u003e .input-group-append \u003e .input-group-text,\\n.input-group-lg \u003e .input-group-prepend \u003e .btn,\\n.input-group-lg \u003e .input-group-append \u003e .btn {\\n  padding: $input-padding-y-lg $input-padding-x-lg;\\n  @include font-size($input-font-size-lg);\\n  line-height: $input-line-height-lg;\\n  @include border-radius($input-border-radius-lg);\\n}\\n\\n.input-group-sm \u003e .form-control:not(textarea),\\n.input-group-sm \u003e .custom-select {\\n  height: $input-height-sm;\\n}\\n\\n.input-group-sm \u003e .form-control,\\n.input-group-sm \u003e .custom-select,\\n.input-group-sm \u003e .input-group-prepend \u003e .input-group-text,\\n.input-group-sm \u003e .input-group-append \u003e .input-group-text,\\n.input-group-sm \u003e .input-group-prepend \u003e .btn,\\n.input-group-sm \u003e .input-group-append \u003e .btn {\\n  padding: $input-padding-y-sm $input-padding-x-sm;\\n  @include font-size($input-font-size-sm);\\n  line-height: $input-line-height-sm;\\n  @include border-radius($input-border-radius-sm);\\n}\\n\\n.input-group-lg \u003e .custom-select,\\n.input-group-sm \u003e .custom-select {\\n  padding-right: $custom-select-padding-x + $custom-select-indicator-padding;\\n}\\n\\n\\n// Prepend and append rounded corners\\n//\\n// These rulesets must come after the sizing ones to properly override sm and lg\\n// border-radius values when extending. They're more specific than we'd like\\n// with the `.input-group \u003e` part, but without it, we cannot override the sizing.\\n\\n\\n.input-group \u003e .input-group-prepend \u003e .btn,\\n.input-group \u003e .input-group-prepend \u003e .input-group-text,\\n.input-group \u003e .input-group-append:not(:last-child) \u003e .btn,\\n.input-group \u003e .input-group-append:not(:last-child) \u003e .input-group-text,\\n.input-group \u003e .input-group-append:last-child \u003e .btn:not(:last-child):not(.dropdown-toggle),\\n.input-group \u003e .input-group-append:last-child \u003e .input-group-text:not(:last-child) {\\n  @include border-right-radius(0);\\n}\\n\\n.input-group \u003e .input-group-append \u003e .btn,\\n.input-group \u003e .input-group-append \u003e .input-group-text,\\n.input-group \u003e .input-group-prepend:not(:first-child) \u003e .btn,\\n.input-group \u003e .input-group-prepend:not(:first-child) \u003e .input-group-text,\\n.input-group \u003e .input-group-prepend:first-child \u003e .btn:not(:first-child),\\n.input-group \u003e .input-group-prepend:first-child \u003e .input-group-text:not(:first-child) {\\n  @include border-left-radius(0);\\n}\\n\",","\t\t\"// Embedded icons from Open Iconic.\\n// Released under MIT and copyright 2014 Waybury.\\n// https://useiconic.com/open\\n\\n\\n// Checkboxes and radios\\n//\\n// Base class takes care of all the key behavioral aspects.\\n\\n.custom-control {\\n  position: relative;\\n  display: block;\\n  min-height: $font-size-base * $line-height-base;\\n  padding-left: $custom-control-gutter + $custom-control-indicator-size;\\n}\\n\\n.custom-control-inline {\\n  display: inline-flex;\\n  margin-right: $custom-control-spacer-x;\\n}\\n\\n.custom-control-input {\\n  position: absolute;\\n  z-index: -1; // Put the input behind the label so it doesn't overlay text\\n  opacity: 0;\\n\\n  \u0026:checked ~ .custom-control-label::before {\\n    color: $custom-control-indicator-checked-color;\\n    border-color: $custom-control-indicator-checked-border-color;\\n    @include gradient-bg($custom-control-indicator-checked-bg);\\n    @include box-shadow($custom-control-indicator-checked-box-shadow);\\n  }\\n\\n  \u0026:focus ~ .custom-control-label::before {\\n    // the mixin is not used here to make sure there is feedback\\n    @if $enable-shadows {\\n      box-shadow: $input-box-shadow, $input-focus-box-shadow;\\n    } @else {\\n      box-shadow: $custom-control-indicator-focus-box-shadow;\\n    }\\n  }\\n\\n  \u0026:focus:not(:checked) ~ .custom-control-label::before {\\n    border-color: $custom-control-indicator-focus-border-color;\\n  }\\n\\n  \u0026:not(:disabled):active ~ .custom-control-label::before {\\n    color: $custom-control-indicator-active-color;\\n    background-color: $custom-control-indicator-active-bg;\\n    border-color: $custom-control-indicator-active-border-color;\\n    @include box-shadow($custom-control-indicator-active-box-shadow);\\n  }\\n\\n  \u0026:disabled {\\n    ~ .custom-control-label {\\n      color: $custom-control-label-disabled-color;\\n\\n      \u0026::before {\\n        background-color: $custom-control-indicator-disabled-bg;\\n      }\\n    }\\n  }\\n}\\n\\n// Custom control indicators\\n//\\n// Build the custom controls out of pseudo-elements.\\n\\n.custom-control-label {\\n  position: relative;\\n  margin-bottom: 0;\\n  vertical-align: top;\\n\\n  // Background-color and (when enabled) gradient\\n  \u0026::before {\\n    position: absolute;\\n    top: ($font-size-base * $line-height-base - $custom-control-indicator-size) / 2;\\n    left: -($custom-control-gutter + $custom-control-indicator-size);\\n    display: block;\\n    width: $custom-control-indicator-size;\\n    height: $custom-control-indicator-size;\\n    pointer-events: none;\\n    content: \\\"\\\";\\n    background-color: $custom-control-indicator-bg;\\n    border: $custom-control-indicator-border-color solid $custom-control-indicator-border-width;\\n    @include box-shadow($custom-control-indicator-box-shadow);\\n  }\\n\\n  // Foreground (icon)\\n  \u0026::after {\\n    position: absolute;\\n    top: ($font-size-base * $line-height-base - $custom-control-indicator-size) / 2;\\n    left: -($custom-control-gutter + $custom-control-indicator-size);\\n    display: block;\\n    width: $custom-control-indicator-size;\\n    height: $custom-control-indicator-size;\\n    content: \\\"\\\";\\n    background: no-repeat 50% / #{$custom-control-indicator-bg-size};\\n  }\\n}\\n\\n\\n// Checkboxes\\n//\\n// Tweak just a few things for checkboxes.\\n\\n.custom-checkbox {\\n  .custom-control-label::before {\\n    @include border-radius($custom-checkbox-indicator-border-radius);\\n  }\\n\\n  .custom-control-input:checked ~ .custom-control-label {\\n    \u0026::after {\\n      background-image: $custom-checkbox-indicator-icon-checked;\\n    }\\n  }\\n\\n  .custom-control-input:indeterminate ~ .custom-control-label {\\n    \u0026::before {\\n      border-color: $custom-checkbox-indicator-indeterminate-border-color;\\n      @include gradient-bg($custom-checkbox-indicator-indeterminate-bg);\\n      @include box-shadow($custom-checkbox-indicator-indeterminate-box-shadow);\\n    }\\n    \u0026::after {\\n      background-image: $custom-checkbox-indicator-icon-indeterminate;\\n    }\\n  }\\n\\n  .custom-control-input:disabled {\\n    \u0026:checked ~ .custom-control-label::before {\\n      background-color: $custom-control-indicator-checked-disabled-bg;\\n    }\\n    \u0026:indeterminate ~ .custom-control-label::before {\\n      background-color: $custom-control-indicator-checked-disabled-bg;\\n    }\\n  }\\n}\\n\\n// Radios\\n//\\n// Tweak just a few things for radios.\\n\\n.custom-radio {\\n  .custom-control-label::before {\\n    // stylelint-disable-next-line property-blacklist\\n    border-radius: $custom-radio-indicator-border-radius;\\n  }\\n\\n  .custom-control-input:checked ~ .custom-control-label {\\n    \u0026::after {\\n      background-image: $custom-radio-indicator-icon-checked;\\n    }\\n  }\\n\\n  .custom-control-input:disabled {\\n    \u0026:checked ~ .custom-control-label::before {\\n      background-color: $custom-control-indicator-checked-disabled-bg;\\n    }\\n  }\\n}\\n\\n\\n// switches\\n//\\n// Tweak a few things for switches\\n\\n.custom-switch {\\n  padding-left: $custom-switch-width + $custom-control-gutter;\\n\\n  .custom-control-label {\\n    \u0026::before {\\n      left: -($custom-switch-width + $custom-control-gutter);\\n      width: $custom-switch-width;\\n      pointer-events: all;\\n      // stylelint-disable-next-line property-blacklist\\n      border-radius: $custom-switch-indicator-border-radius;\\n    }\\n\\n    \u0026::after {\\n      top: calc(#{(($font-size-base * $line-height-base - $custom-control-indicator-size) / 2)} + #{$custom-control-indicator-border-width * 2});\\n      left: calc(#{-($custom-switch-width + $custom-control-gutter)} + #{$custom-control-indicator-border-width * 2});\\n      width: $custom-switch-indicator-size;\\n      height: $custom-switch-indicator-size;\\n      background-color: $custom-control-indicator-border-color;\\n      // stylelint-disable-next-line property-blacklist\\n      border-radius: $custom-switch-indicator-border-radius;\\n      @include transition(transform .15s ease-in-out, $custom-forms-transition);\\n    }\\n  }\\n\\n  .custom-control-input:checked ~ .custom-control-label {\\n    \u0026::after {\\n      background-color: $custom-control-indicator-bg;\\n      transform: translateX($custom-switch-width - $custom-control-indicator-size);\\n    }\\n  }\\n\\n  .custom-control-input:disabled {\\n    \u0026:checked ~ .custom-control-label::before {\\n      background-color: $custom-control-indicator-checked-disabled-bg;\\n    }\\n  }\\n}\\n\\n\\n// Select\\n//\\n// Replaces the browser default select with a custom one, mostly pulled from\\n// https://primer.github.io/.\\n//\\n\\n.custom-select {\\n  display: inline-block;\\n  width: 100%;\\n  height: $custom-select-height;\\n  padding: $custom-select-padding-y ($custom-select-padding-x + $custom-select-indicator-padding) $custom-select-padding-y $custom-select-padding-x;\\n  font-family: $custom-select-font-family;\\n  @include font-size($custom-select-font-size);\\n  font-weight: $custom-select-font-weight;\\n  line-height: $custom-select-line-height;\\n  color: $custom-select-color;\\n  vertical-align: middle;\\n  background: $custom-select-background;\\n  background-color: $custom-select-bg;\\n  border: $custom-select-border-width solid $custom-select-border-color;\\n  @include border-radius($custom-select-border-radius, 0);\\n  @include box-shadow($custom-select-box-shadow);\\n  appearance: none;\\n\\n  \u0026:focus {\\n    border-color: $custom-select-focus-border-color;\\n    outline: 0;\\n    @if $enable-shadows {\\n      box-shadow: $custom-select-box-shadow, $custom-select-focus-box-shadow;\\n    } @else {\\n      box-shadow: $custom-select-focus-box-shadow;\\n    }\\n\\n    \u0026::-ms-value {\\n      // For visual consistency with other platforms/browsers,\\n      // suppress the default white text on blue background highlight given to\\n      // the selected option text when the (still closed) \u003cselect\u003e receives focus\\n      // in IE and (under certain conditions) Edge.\\n      // See https://github.com/twbs/bootstrap/issues/19398.\\n      color: $input-color;\\n      background-color: $input-bg;\\n    }\\n  }\\n\\n  \u0026[multiple],\\n  \u0026[size]:not([size=\\\"1\\\"]) {\\n    height: auto;\\n    padding-right: $custom-select-padding-x;\\n    background-image: none;\\n  }\\n\\n  \u0026:disabled {\\n    color: $custom-select-disabled-color;\\n    background-color: $custom-select-disabled-bg;\\n  }\\n\\n  // Hides the default caret in IE11\\n  \u0026::-ms-expand {\\n    display: none;\\n  }\\n}\\n\\n.custom-select-sm {\\n  height: $custom-select-height-sm;\\n  padding-top: $custom-select-padding-y-sm;\\n  padding-bottom: $custom-select-padding-y-sm;\\n  padding-left: $custom-select-padding-x-sm;\\n  @include font-size($custom-select-font-size-sm);\\n}\\n\\n.custom-select-lg {\\n  height: $custom-select-height-lg;\\n  padding-top: $custom-select-padding-y-lg;\\n  padding-bottom: $custom-select-padding-y-lg;\\n  padding-left: $custom-select-padding-x-lg;\\n  @include font-size($custom-select-font-size-lg);\\n}\\n\\n\\n// File\\n//\\n// Custom file input.\\n\\n.custom-file {\\n  position: relative;\\n  display: inline-block;\\n  width: 100%;\\n  height: $custom-file-height;\\n  margin-bottom: 0;\\n}\\n\\n.custom-file-input {\\n  position: relative;\\n  z-index: 2;\\n  width: 100%;\\n  height: $custom-file-height;\\n  margin: 0;\\n  opacity: 0;\\n\\n  \u0026:focus ~ .custom-file-label {\\n    border-color: $custom-file-focus-border-color;\\n    box-shadow: $custom-file-focus-box-shadow;\\n  }\\n\\n  \u0026:disabled ~ .custom-file-label {\\n    background-color: $custom-file-disabled-bg;\\n  }\\n\\n  @each $lang, $value in $custom-file-text {\\n    \u0026:lang(#{$lang}) ~ .custom-file-label::after {\\n      content: $value;\\n    }\\n  }\\n\\n  ~ .custom-file-label[data-browse]::after {\\n    content: attr(data-browse);\\n  }\\n}\\n\\n.custom-file-label {\\n  position: absolute;\\n  top: 0;\\n  right: 0;\\n  left: 0;\\n  z-index: 1;\\n  height: $custom-file-height;\\n  padding: $custom-file-padding-y $custom-file-padding-x;\\n  font-family: $custom-file-font-family;\\n  font-weight: $custom-file-font-weight;\\n  line-height: $custom-file-line-height;\\n  color: $custom-file-color;\\n  background-color: $custom-file-bg;\\n  border: $custom-file-border-width solid $custom-file-border-color;\\n  @include border-radius($custom-file-border-radius);\\n  @include box-shadow($custom-file-box-shadow);\\n\\n  \u0026::after {\\n    position: absolute;\\n    top: 0;\\n    right: 0;\\n    bottom: 0;\\n    z-index: 3;\\n    display: block;\\n    height: $custom-file-height-inner;\\n    padding: $custom-file-padding-y $custom-file-padding-x;\\n    line-height: $custom-file-line-height;\\n    color: $custom-file-button-color;\\n    content: \\\"Browse\\\";\\n    @include gradient-bg($custom-file-button-bg);\\n    border-left: inherit;\\n    @include border-radius(0 $custom-file-border-radius $custom-file-border-radius 0);\\n  }\\n}\\n\\n// Range\\n//\\n// Style range inputs the same across browsers. Vendor-specific rules for pseudo\\n// elements cannot be mixed. As such, there are no shared styles for focus or\\n// active states on prefixed selectors.\\n\\n.custom-range {\\n  width: 100%;\\n  height: calc(#{$custom-range-thumb-height} + #{$custom-range-thumb-focus-box-shadow-width * 2});\\n  padding: 0; // Need to reset padding\\n  background-color: transparent;\\n  appearance: none;\\n\\n  \u0026:focus {\\n    outline: none;\\n\\n    // Pseudo-elements must be split across multiple rulesets to have an effect.\\n    // No box-shadow() mixin for focus accessibility.\\n    \u0026::-webkit-slider-thumb { box-shadow: $custom-range-thumb-focus-box-shadow; }\\n    \u0026::-moz-range-thumb     { box-shadow: $custom-range-thumb-focus-box-shadow; }\\n    \u0026::-ms-thumb            { box-shadow: $custom-range-thumb-focus-box-shadow; }\\n  }\\n\\n  \u0026::-moz-focus-outer {\\n    border: 0;\\n  }\\n\\n  \u0026::-webkit-slider-thumb {\\n    width: $custom-range-thumb-width;\\n    height: $custom-range-thumb-height;\\n    margin-top: ($custom-range-track-height - $custom-range-thumb-height) / 2; // Webkit specific\\n    @include gradient-bg($custom-range-thumb-bg);\\n    border: $custom-range-thumb-border;\\n    @include border-radius($custom-range-thumb-border-radius);\\n    @include box-shadow($custom-range-thumb-box-shadow);\\n    @include transition($custom-forms-transition);\\n    appearance: none;\\n\\n    \u0026:active {\\n      @include gradient-bg($custom-range-thumb-active-bg);\\n    }\\n  }\\n\\n  \u0026::-webkit-slider-runnable-track {\\n    width: $custom-range-track-width;\\n    height: $custom-range-track-height;\\n    color: transparent; // Why?\\n    cursor: $custom-range-track-cursor;\\n    background-color: $custom-range-track-bg;\\n    border-color: transparent;\\n    @include border-radius($custom-range-track-border-radius);\\n    @include box-shadow($custom-range-track-box-shadow);\\n  }\\n\\n  \u0026::-moz-range-thumb {\\n    width: $custom-range-thumb-width;\\n    height: $custom-range-thumb-height;\\n    @include gradient-bg($custom-range-thumb-bg);\\n    border: $custom-range-thumb-border;\\n    @include border-radius($custom-range-thumb-border-radius);\\n    @include box-shadow($custom-range-thumb-box-shadow);\\n    @include transition($custom-forms-transition);\\n    appearance: none;\\n\\n    \u0026:active {\\n      @include gradient-bg($custom-range-thumb-active-bg);\\n    }\\n  }\\n\\n  \u0026::-moz-range-track {\\n    width: $custom-range-track-width;\\n    height: $custom-range-track-height;\\n    color: transparent;\\n    cursor: $custom-range-track-cursor;\\n    background-color: $custom-range-track-bg;\\n    border-color: transparent; // Firefox specific?\\n    @include border-radius($custom-range-track-border-radius);\\n    @include box-shadow($custom-range-track-box-shadow);\\n  }\\n\\n  \u0026::-ms-thumb {\\n    width: $custom-range-thumb-width;\\n    height: $custom-range-thumb-height;\\n    margin-top: 0; // Edge specific\\n    margin-right: $custom-range-thumb-focus-box-shadow-width; // Workaround that overflowed box-shadow is hidden.\\n    margin-left: $custom-range-thumb-focus-box-shadow-width;  // Workaround that overflowed box-shadow is hidden.\\n    @include gradient-bg($custom-range-thumb-bg);\\n    border: $custom-range-thumb-border;\\n    @include border-radius($custom-range-thumb-border-radius);\\n    @include box-shadow($custom-range-thumb-box-shadow);\\n    @include transition($custom-forms-transition);\\n    appearance: none;\\n\\n    \u0026:active {\\n      @include gradient-bg($custom-range-thumb-active-bg);\\n    }\\n  }\\n\\n  \u0026::-ms-track {\\n    width: $custom-range-track-width;\\n    height: $custom-range-track-height;\\n    color: transparent;\\n    cursor: $custom-range-track-cursor;\\n    background-color: transparent;\\n    border-color: transparent;\\n    border-width: $custom-range-thumb-height / 2;\\n    @include box-shadow($custom-range-track-box-shadow);\\n  }\\n\\n  \u0026::-ms-fill-lower {\\n    background-color: $custom-range-track-bg;\\n    @include border-radius($custom-range-track-border-radius);\\n  }\\n\\n  \u0026::-ms-fill-upper {\\n    margin-right: 15px; // arbitrary?\\n    background-color: $custom-range-track-bg;\\n    @include border-radius($custom-range-track-border-radius);\\n  }\\n\\n  \u0026:disabled {\\n    \u0026::-webkit-slider-thumb {\\n      background-color: $custom-range-thumb-disabled-bg;\\n    }\\n\\n    \u0026::-webkit-slider-runnable-track {\\n      cursor: default;\\n    }\\n\\n    \u0026::-moz-range-thumb {\\n      background-color: $custom-range-thumb-disabled-bg;\\n    }\\n\\n    \u0026::-moz-range-track {\\n      cursor: default;\\n    }\\n\\n    \u0026::-ms-thumb {\\n      background-color: $custom-range-thumb-disabled-bg;\\n    }\\n  }\\n}\\n\\n.custom-control-label::before,\\n.custom-file-label,\\n.custom-select {\\n  @include transition($custom-forms-transition);\\n}\\n\",","\t\t\"// Base class\\n//\\n// Kickstart any navigation component with a set of style resets. Works with\\n// `\u003cnav\u003e`s or `\u003cul\u003e`s.\\n\\n.nav {\\n  display: flex;\\n  flex-wrap: wrap;\\n  padding-left: 0;\\n  margin-bottom: 0;\\n  list-style: none;\\n}\\n\\n.nav-link {\\n  display: block;\\n  padding: $nav-link-padding-y $nav-link-padding-x;\\n\\n  @include hover-focus {\\n    text-decoration: none;\\n  }\\n\\n  // Disabled state lightens text\\n  \u0026.disabled {\\n    color: $nav-link-disabled-color;\\n    pointer-events: none;\\n    cursor: default;\\n  }\\n}\\n\\n//\\n// Tabs\\n//\\n\\n.nav-tabs {\\n  border-bottom: $nav-tabs-border-width solid $nav-tabs-border-color;\\n\\n  .nav-item {\\n    margin-bottom: -$nav-tabs-border-width;\\n  }\\n\\n  .nav-link {\\n    border: $nav-tabs-border-width solid transparent;\\n    @include border-top-radius($nav-tabs-border-radius);\\n\\n    @include hover-focus {\\n      border-color: $nav-tabs-link-hover-border-color;\\n    }\\n\\n    \u0026.disabled {\\n      color: $nav-link-disabled-color;\\n      background-color: transparent;\\n      border-color: transparent;\\n    }\\n  }\\n\\n  .nav-link.active,\\n  .nav-item.show .nav-link {\\n    color: $nav-tabs-link-active-color;\\n    background-color: $nav-tabs-link-active-bg;\\n    border-color: $nav-tabs-link-active-border-color;\\n  }\\n\\n  .dropdown-menu {\\n    // Make dropdown border overlap tab border\\n    margin-top: -$nav-tabs-border-width;\\n    // Remove the top rounded corners here since there is a hard edge above the menu\\n    @include border-top-radius(0);\\n  }\\n}\\n\\n\\n//\\n// Pills\\n//\\n\\n.nav-pills {\\n  .nav-link {\\n    @include border-radius($nav-pills-border-radius);\\n  }\\n\\n  .nav-link.active,\\n  .show \u003e .nav-link {\\n    color: $nav-pills-link-active-color;\\n    background-color: $nav-pills-link-active-bg;\\n  }\\n}\\n\\n\\n//\\n// Justified variants\\n//\\n\\n.nav-fill {\\n  .nav-item {\\n    flex: 1 1 auto;\\n    text-align: center;\\n  }\\n}\\n\\n.nav-justified {\\n  .nav-item {\\n    flex-basis: 0;\\n    flex-grow: 1;\\n    text-align: center;\\n  }\\n}\\n\\n\\n// Tabbable tabs\\n//\\n// Hide tabbable panes to start, show them when `.active`\\n\\n.tab-content {\\n  \u003e .tab-pane {\\n    display: none;\\n  }\\n  \u003e .active {\\n    display: block;\\n  }\\n}\\n\",","\t\t\"// Contents\\n//\\n// Navbar\\n// Navbar brand\\n// Navbar nav\\n// Navbar text\\n// Navbar divider\\n// Responsive navbar\\n// Navbar position\\n// Navbar themes\\n\\n\\n// Navbar\\n//\\n// Provide a static navbar from which we expand to create full-width, fixed, and\\n// other navbar variations.\\n\\n.navbar {\\n  position: relative;\\n  display: flex;\\n  flex-wrap: wrap; // allow us to do the line break for collapsing content\\n  align-items: center;\\n  justify-content: space-between; // space out brand from logo\\n  padding: $navbar-padding-y $navbar-padding-x;\\n\\n  // Because flex properties aren't inherited, we need to redeclare these first\\n  // few properties so that content nested within behave properly.\\n  \u003e .container,\\n  \u003e .container-fluid {\\n    display: flex;\\n    flex-wrap: wrap;\\n    align-items: center;\\n    justify-content: space-between;\\n  }\\n}\\n\\n\\n// Navbar brand\\n//\\n// Used for brand, project, or site names.\\n\\n.navbar-brand {\\n  display: inline-block;\\n  padding-top: $navbar-brand-padding-y;\\n  padding-bottom: $navbar-brand-padding-y;\\n  margin-right: $navbar-padding-x;\\n  @include font-size($navbar-brand-font-size);\\n  line-height: inherit;\\n  white-space: nowrap;\\n\\n  @include hover-focus {\\n    text-decoration: none;\\n  }\\n}\\n\\n\\n// Navbar nav\\n//\\n// Custom navbar navigation (doesn't require `.nav`, but does make use of `.nav-link`).\\n\\n.navbar-nav {\\n  display: flex;\\n  flex-direction: column; // cannot use `inherit` to get the `.navbar`s value\\n  padding-left: 0;\\n  margin-bottom: 0;\\n  list-style: none;\\n\\n  .nav-link:not(.btn) {\\n    padding-right: 0;\\n    padding-left: 0;\\n  }\\n\\n  .dropdown-menu {\\n    position: static;\\n    float: none;\\n  }\\n}\\n\\n\\n// Navbar text\\n//\\n//\\n\\n.navbar-text {\\n  display: inline-block;\\n  padding-top: $nav-link-padding-y;\\n  padding-bottom: $nav-link-padding-y;\\n}\\n\\n\\n// Responsive navbar\\n//\\n// Custom styles for responsive collapsing and toggling of navbar contents.\\n// Powered by the collapse Bootstrap JavaScript plugin.\\n\\n// When collapsed, prevent the toggleable navbar contents from appearing in\\n// the default flexbox row orientation. Requires the use of `flex-wrap: wrap`\\n// on the `.navbar` parent.\\n.navbar-collapse {\\n  flex-basis: 100%;\\n  flex-grow: 1;\\n  // For always expanded or extra full navbars, ensure content aligns itself\\n  // properly vertically. Can be easily overridden with flex utilities.\\n  align-items: center;\\n}\\n\\n// Button for toggling the navbar when in its collapsed state\\n.navbar-toggler {\\n  padding: $navbar-toggler-padding-y $navbar-toggler-padding-x;\\n  @include font-size($navbar-toggler-font-size);\\n  line-height: 1;\\n  background-color: transparent; // remove default button style\\n  border: $border-width solid transparent; // remove default button style\\n  @include border-radius($navbar-toggler-border-radius);\\n\\n  @include hover-focus {\\n    text-decoration: none;\\n  }\\n}\\n\\n// Keep as a separate element so folks can easily override it with another icon\\n// or image file as needed.\\n.navbar-toggler-icon {\\n  display: inline-block;\\n  width: 1.5em;\\n  height: 1.5em;\\n  vertical-align: middle;\\n  content: \\\"\\\";\\n  background: no-repeat center center;\\n  background-size: 100% 100%;\\n}\\n\\n// Generate series of `.navbar-expand-*` responsive classes for configuring\\n// where your navbar collapses.\\n.navbar-expand {\\n  @each $breakpoint in map-keys($grid-breakpoints) {\\n    $next: breakpoint-next($breakpoint, $grid-breakpoints);\\n    $infix: breakpoint-infix($next, $grid-breakpoints);\\n\\n    \u0026#{$infix} {\\n      @include media-breakpoint-down($breakpoint) {\\n        \u003e .container,\\n        \u003e .container-fluid {\\n          padding-right: 0;\\n          padding-left: 0;\\n        }\\n      }\\n\\n      @include media-breakpoint-up($next) {\\n        flex-flow: row nowrap;\\n        justify-content: flex-start;\\n\\n        .navbar-nav {\\n          flex-direction: row;\\n\\n          .dropdown-menu {\\n            position: absolute;\\n          }\\n\\n          .nav-link {\\n            padding-right: $navbar-nav-link-padding-x;\\n            padding-left: $navbar-nav-link-padding-x;\\n          }\\n        }\\n\\n        // For nesting containers, have to redeclare for alignment purposes\\n        \u003e .container,\\n        \u003e .container-fluid {\\n          flex-wrap: nowrap;\\n        }\\n\\n        .navbar-collapse {\\n          display: flex !important; // stylelint-disable-line declaration-no-important\\n\\n          // Changes flex-bases to auto because of an IE10 bug\\n          flex-basis: auto;\\n        }\\n\\n        .navbar-toggler {\\n          display: none;\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n\\n// Navbar themes\\n//\\n// Styles for switching between navbars with light or dark background.\\n\\n// Dark links against a light background\\n.navbar-light {\\n  .navbar-brand {\\n    color: $navbar-light-brand-color;\\n\\n    @include hover-focus {\\n      color: $navbar-light-brand-hover-color;\\n    }\\n  }\\n\\n  .navbar-nav {\\n    .nav-link {\\n      color: $navbar-light-color;\\n\\n      @include hover-focus {\\n        color: $navbar-light-hover-color;\\n      }\\n\\n      \u0026.disabled {\\n        color: $navbar-light-disabled-color;\\n      }\\n    }\\n\\n    .show \u003e .nav-link,\\n    .active \u003e .nav-link,\\n    .nav-link.show,\\n    .nav-link.active {\\n      color: $navbar-light-active-color;\\n    }\\n  }\\n\\n  .navbar-toggler {\\n    color: $navbar-light-color;\\n    border-color: $navbar-light-toggler-border-color;\\n  }\\n\\n  .navbar-toggler-icon {\\n    background-image: $navbar-light-toggler-icon-bg;\\n  }\\n\\n  .navbar-text {\\n    color: $navbar-light-color;\\n    a {\\n      color: $navbar-light-active-color;\\n\\n      @include hover-focus {\\n        color: $navbar-light-active-color;\\n      }\\n    }\\n  }\\n}\\n\\n// White links against a dark background\\n.navbar-dark {\\n  .navbar-brand {\\n    color: $navbar-dark-brand-color;\\n\\n    @include hover-focus {\\n      color: $navbar-dark-brand-hover-color;\\n    }\\n  }\\n\\n  .navbar-nav {\\n    .nav-link {\\n      color: $navbar-dark-color;\\n\\n      @include hover-focus {\\n        color: $navbar-dark-hover-color;\\n      }\\n\\n      \u0026.disabled {\\n        color: $navbar-dark-disabled-color;\\n      }\\n    }\\n\\n    .show \u003e .nav-link,\\n    .active \u003e .nav-link,\\n    .nav-link.show,\\n    .nav-link.active {\\n      color: $navbar-dark-active-color;\\n    }\\n  }\\n\\n  .navbar-toggler {\\n    color: $navbar-dark-color;\\n    border-color: $navbar-dark-toggler-border-color;\\n  }\\n\\n  .navbar-toggler-icon {\\n    background-image: $navbar-dark-toggler-icon-bg;\\n  }\\n\\n  .navbar-text {\\n    color: $navbar-dark-color;\\n    a {\\n      color: $navbar-dark-active-color;\\n\\n      @include hover-focus {\\n        color: $navbar-dark-active-color;\\n      }\\n    }\\n  }\\n}\\n\",","\t\t\"//\\n// Base styles\\n//\\n\\n.card {\\n  position: relative;\\n  display: flex;\\n  flex-direction: column;\\n  min-width: 0; // See https://github.com/twbs/bootstrap/pull/22740#issuecomment-305868106\\n  word-wrap: break-word;\\n  background-color: $card-bg;\\n  background-clip: border-box;\\n  border: $card-border-width solid $card-border-color;\\n  @include border-radius($card-border-radius);\\n\\n  \u003e hr {\\n    margin-right: 0;\\n    margin-left: 0;\\n  }\\n\\n  \u003e .list-group:first-child {\\n    .list-group-item:first-child {\\n      @include border-top-radius($card-border-radius);\\n    }\\n  }\\n\\n  \u003e .list-group:last-child {\\n    .list-group-item:last-child {\\n      @include border-bottom-radius($card-border-radius);\\n    }\\n  }\\n}\\n\\n.card-body {\\n  // Enable `flex-grow: 1` for decks and groups so that card blocks take up\\n  // as much space as possible, ensuring footers are aligned to the bottom.\\n  flex: 1 1 auto;\\n  padding: $card-spacer-x;\\n  color: $card-color;\\n}\\n\\n.card-title {\\n  margin-bottom: $card-spacer-y;\\n}\\n\\n.card-subtitle {\\n  margin-top: -$card-spacer-y / 2;\\n  margin-bottom: 0;\\n}\\n\\n.card-text:last-child {\\n  margin-bottom: 0;\\n}\\n\\n.card-link {\\n  @include hover {\\n    text-decoration: none;\\n  }\\n\\n  + .card-link {\\n    margin-left: $card-spacer-x;\\n  }\\n}\\n\\n//\\n// Optional textual caps\\n//\\n\\n.card-header {\\n  padding: $card-spacer-y $card-spacer-x;\\n  margin-bottom: 0; // Removes the default margin-bottom of \u003chN\u003e\\n  color: $card-cap-color;\\n  background-color: $card-cap-bg;\\n  border-bottom: $card-border-width solid $card-border-color;\\n\\n  \u0026:first-child {\\n    @include border-radius($card-inner-border-radius $card-inner-border-radius 0 0);\\n  }\\n\\n  + .list-group {\\n    .list-group-item:first-child {\\n      border-top: 0;\\n    }\\n  }\\n}\\n\\n.card-footer {\\n  padding: $card-spacer-y $card-spacer-x;\\n  background-color: $card-cap-bg;\\n  border-top: $card-border-width solid $card-border-color;\\n\\n  \u0026:last-child {\\n    @include border-radius(0 0 $card-inner-border-radius $card-inner-border-radius);\\n  }\\n}\\n\\n\\n//\\n// Header navs\\n//\\n\\n.card-header-tabs {\\n  margin-right: -$card-spacer-x / 2;\\n  margin-bottom: -$card-spacer-y;\\n  margin-left: -$card-spacer-x / 2;\\n  border-bottom: 0;\\n}\\n\\n.card-header-pills {\\n  margin-right: -$card-spacer-x / 2;\\n  margin-left: -$card-spacer-x / 2;\\n}\\n\\n// Card image\\n.card-img-overlay {\\n  position: absolute;\\n  top: 0;\\n  right: 0;\\n  bottom: 0;\\n  left: 0;\\n  padding: $card-img-overlay-padding;\\n}\\n\\n.card-img {\\n  width: 100%; // Required because we use flexbox and this inherently applies align-self: stretch\\n  @include border-radius($card-inner-border-radius);\\n}\\n\\n// Card image caps\\n.card-img-top {\\n  width: 100%; // Required because we use flexbox and this inherently applies align-self: stretch\\n  @include border-top-radius($card-inner-border-radius);\\n}\\n\\n.card-img-bottom {\\n  width: 100%; // Required because we use flexbox and this inherently applies align-self: stretch\\n  @include border-bottom-radius($card-inner-border-radius);\\n}\\n\\n\\n// Card deck\\n\\n.card-deck {\\n  display: flex;\\n  flex-direction: column;\\n\\n  .card {\\n    margin-bottom: $card-deck-margin;\\n  }\\n\\n  @include media-breakpoint-up(sm) {\\n    flex-flow: row wrap;\\n    margin-right: -$card-deck-margin;\\n    margin-left: -$card-deck-margin;\\n\\n    .card {\\n      display: flex;\\n      // Flexbugs #4: https://github.com/philipwalton/flexbugs#flexbug-4\\n      flex: 1 0 0%;\\n      flex-direction: column;\\n      margin-right: $card-deck-margin;\\n      margin-bottom: 0; // Override the default\\n      margin-left: $card-deck-margin;\\n    }\\n  }\\n}\\n\\n\\n//\\n// Card groups\\n//\\n\\n.card-group {\\n  display: flex;\\n  flex-direction: column;\\n\\n  // The child selector allows nested `.card` within `.card-group`\\n  // to display properly.\\n  \u003e .card {\\n    margin-bottom: $card-group-margin;\\n  }\\n\\n  @include media-breakpoint-up(sm) {\\n    flex-flow: row wrap;\\n    // The child selector allows nested `.card` within `.card-group`\\n    // to display properly.\\n    \u003e .card {\\n      // Flexbugs #4: https://github.com/philipwalton/flexbugs#flexbug-4\\n      flex: 1 0 0%;\\n      margin-bottom: 0;\\n\\n      + .card {\\n        margin-left: 0;\\n        border-left: 0;\\n      }\\n\\n      // Handle rounded corners\\n      @if $enable-rounded {\\n        \u0026:not(:last-child) {\\n          @include border-right-radius(0);\\n\\n          .card-img-top,\\n          .card-header {\\n            // stylelint-disable-next-line property-blacklist\\n            border-top-right-radius: 0;\\n          }\\n          .card-img-bottom,\\n          .card-footer {\\n            // stylelint-disable-next-line property-blacklist\\n            border-bottom-right-radius: 0;\\n          }\\n        }\\n\\n        \u0026:not(:first-child) {\\n          @include border-left-radius(0);\\n\\n          .card-img-top,\\n          .card-header {\\n            // stylelint-disable-next-line property-blacklist\\n            border-top-left-radius: 0;\\n          }\\n          .card-img-bottom,\\n          .card-footer {\\n            // stylelint-disable-next-line property-blacklist\\n            border-bottom-left-radius: 0;\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n\\n//\\n// Columns\\n//\\n\\n.card-columns {\\n  .card {\\n    margin-bottom: $card-columns-margin;\\n  }\\n\\n  @include media-breakpoint-up(sm) {\\n    column-count: $card-columns-count;\\n    column-gap: $card-columns-gap;\\n    orphans: 1;\\n    widows: 1;\\n\\n    .card {\\n      display: inline-block; // Don't let them vertically span multiple columns\\n      width: 100%; // Don't let their width change\\n    }\\n  }\\n}\\n\\n\\n//\\n// Accordion\\n//\\n\\n.accordion {\\n  \u003e .card {\\n    overflow: hidden;\\n\\n    \u0026:not(:first-of-type) {\\n      .card-header:first-child {\\n        @include border-radius(0);\\n      }\\n\\n      \u0026:not(:last-of-type) {\\n        border-bottom: 0;\\n        @include border-radius(0);\\n      }\\n    }\\n\\n    \u0026:first-of-type {\\n      border-bottom: 0;\\n      @include border-bottom-radius(0);\\n    }\\n\\n    \u0026:last-of-type {\\n      @include border-top-radius(0);\\n    }\\n\\n    .card-header {\\n      margin-bottom: -$card-border-width;\\n    }\\n  }\\n}\\n\",","\t\t\".breadcrumb {\\n  display: flex;\\n  flex-wrap: wrap;\\n  padding: $breadcrumb-padding-y $breadcrumb-padding-x;\\n  margin-bottom: $breadcrumb-margin-bottom;\\n  list-style: none;\\n  background-color: $breadcrumb-bg;\\n  @include border-radius($breadcrumb-border-radius);\\n}\\n\\n.breadcrumb-item {\\n  // The separator between breadcrumbs (by default, a forward-slash: \\\"/\\\")\\n  + .breadcrumb-item {\\n    padding-left: $breadcrumb-item-padding;\\n\\n    \u0026::before {\\n      display: inline-block; // Suppress underlining of the separator in modern browsers\\n      padding-right: $breadcrumb-item-padding;\\n      color: $breadcrumb-divider-color;\\n      content: $breadcrumb-divider;\\n    }\\n  }\\n\\n  // IE9-11 hack to properly handle hyperlink underlines for breadcrumbs built\\n  // without `\u003cul\u003e`s. The `::before` pseudo-element generates an element\\n  // *within* the .breadcrumb-item and thereby inherits the `text-decoration`.\\n  //\\n  // To trick IE into suppressing the underline, we give the pseudo-element an\\n  // underline and then immediately remove it.\\n  + .breadcrumb-item:hover::before {\\n    text-decoration: underline;\\n  }\\n  // stylelint-disable-next-line no-duplicate-selectors\\n  + .breadcrumb-item:hover::before {\\n    text-decoration: none;\\n  }\\n\\n  \u0026.active {\\n    color: $breadcrumb-active-color;\\n  }\\n}\\n\",","\t\t\".pagination {\\n  display: flex;\\n  @include list-unstyled();\\n  @include border-radius();\\n}\\n\\n.page-link {\\n  position: relative;\\n  display: block;\\n  padding: $pagination-padding-y $pagination-padding-x;\\n  margin-left: -$pagination-border-width;\\n  line-height: $pagination-line-height;\\n  color: $pagination-color;\\n  background-color: $pagination-bg;\\n  border: $pagination-border-width solid $pagination-border-color;\\n\\n  \u0026:hover {\\n    z-index: 2;\\n    color: $pagination-hover-color;\\n    text-decoration: none;\\n    background-color: $pagination-hover-bg;\\n    border-color: $pagination-hover-border-color;\\n  }\\n\\n  \u0026:focus {\\n    z-index: 2;\\n    outline: $pagination-focus-outline;\\n    box-shadow: $pagination-focus-box-shadow;\\n  }\\n}\\n\\n.page-item {\\n  \u0026:first-child {\\n    .page-link {\\n      margin-left: 0;\\n      @include border-left-radius($border-radius);\\n    }\\n  }\\n  \u0026:last-child {\\n    .page-link {\\n      @include border-right-radius($border-radius);\\n    }\\n  }\\n\\n  \u0026.active .page-link {\\n    z-index: 1;\\n    color: $pagination-active-color;\\n    background-color: $pagination-active-bg;\\n    border-color: $pagination-active-border-color;\\n  }\\n\\n  \u0026.disabled .page-link {\\n    color: $pagination-disabled-color;\\n    pointer-events: none;\\n    // Opinionated: remove the \\\"hand\\\" cursor set previously for .page-link\\n    cursor: auto;\\n    background-color: $pagination-disabled-bg;\\n    border-color: $pagination-disabled-border-color;\\n  }\\n}\\n\\n\\n//\\n// Sizing\\n//\\n\\n.pagination-lg {\\n  @include pagination-size($pagination-padding-y-lg, $pagination-padding-x-lg, $font-size-lg, $line-height-lg, $border-radius-lg);\\n}\\n\\n.pagination-sm {\\n  @include pagination-size($pagination-padding-y-sm, $pagination-padding-x-sm, $font-size-sm, $line-height-sm, $border-radius-sm);\\n}\\n\",","\t\t\"// Base class\\n//\\n// Requires one of the contextual, color modifier classes for `color` and\\n// `background-color`.\\n\\n.badge {\\n  display: inline-block;\\n  padding: $badge-padding-y $badge-padding-x;\\n  @include font-size($badge-font-size);\\n  font-weight: $badge-font-weight;\\n  line-height: 1;\\n  text-align: center;\\n  white-space: nowrap;\\n  vertical-align: baseline;\\n  @include border-radius($badge-border-radius);\\n  @include transition($badge-transition);\\n\\n  @at-root a#{\u0026} {\\n    @include hover-focus {\\n      text-decoration: none;\\n    }\\n  }\\n\\n  // Empty badges collapse automatically\\n  \u0026:empty {\\n    display: none;\\n  }\\n}\\n\\n// Quick fix for badges in buttons\\n.btn .badge {\\n  position: relative;\\n  top: -1px;\\n}\\n\\n// Pill badges\\n//\\n// Make them extra rounded with a modifier to replace v3's badges.\\n\\n.badge-pill {\\n  padding-right: $badge-pill-padding-x;\\n  padding-left: $badge-pill-padding-x;\\n  @include border-radius($badge-pill-border-radius);\\n}\\n\\n// Colors\\n//\\n// Contextual variations (linked badges get darker on :hover).\\n\\n@each $color, $value in $theme-colors {\\n  .badge-#{$color} {\\n    @include badge-variant($value);\\n  }\\n}\\n\",","\t\t\".jumbotron {\\n  padding: $jumbotron-padding ($jumbotron-padding / 2);\\n  margin-bottom: $jumbotron-padding;\\n  color: $jumbotron-color;\\n  background-color: $jumbotron-bg;\\n  @include border-radius($border-radius-lg);\\n\\n  @include media-breakpoint-up(sm) {\\n    padding: ($jumbotron-padding * 2) $jumbotron-padding;\\n  }\\n}\\n\\n.jumbotron-fluid {\\n  padding-right: 0;\\n  padding-left: 0;\\n  @include border-radius(0);\\n}\\n\",","\t\t\"//\\n// Base styles\\n//\\n\\n.alert {\\n  position: relative;\\n  padding: $alert-padding-y $alert-padding-x;\\n  margin-bottom: $alert-margin-bottom;\\n  border: $alert-border-width solid transparent;\\n  @include border-radius($alert-border-radius);\\n}\\n\\n// Headings for larger alerts\\n.alert-heading {\\n  // Specified to prevent conflicts of changing $headings-color\\n  color: inherit;\\n}\\n\\n// Provide class for links that match alerts\\n.alert-link {\\n  font-weight: $alert-link-font-weight;\\n}\\n\\n\\n// Dismissible alerts\\n//\\n// Expand the right padding and account for the close button's positioning.\\n\\n.alert-dismissible {\\n  padding-right: $close-font-size + $alert-padding-x * 2;\\n\\n  // Adjust close link position\\n  .close {\\n    position: absolute;\\n    top: 0;\\n    right: 0;\\n    padding: $alert-padding-y $alert-padding-x;\\n    color: inherit;\\n  }\\n}\\n\\n\\n// Alternate styles\\n//\\n// Generate contextual modifier classes for colorizing the alert.\\n\\n@each $color, $value in $theme-colors {\\n  .alert-#{$color} {\\n    @include alert-variant(theme-color-level($color, $alert-bg-level), theme-color-level($color, $alert-border-level), theme-color-level($color, $alert-color-level));\\n  }\\n}\\n\",","\t\t\"// Disable animation if transitions are disabled\\n@if $enable-transitions {\\n  @keyframes progress-bar-stripes {\\n    from { background-position: $progress-height 0; }\\n    to { background-position: 0 0; }\\n  }\\n}\\n\\n.progress {\\n  display: flex;\\n  height: $progress-height;\\n  overflow: hidden; // force rounded corners by cropping it\\n  @include font-size($progress-font-size);\\n  background-color: $progress-bg;\\n  @include border-radius($progress-border-radius);\\n  @include box-shadow($progress-box-shadow);\\n}\\n\\n.progress-bar {\\n  display: flex;\\n  flex-direction: column;\\n  justify-content: center;\\n  color: $progress-bar-color;\\n  text-align: center;\\n  white-space: nowrap;\\n  background-color: $progress-bar-bg;\\n  @include transition($progress-bar-transition);\\n}\\n\\n.progress-bar-striped {\\n  @include gradient-striped();\\n  background-size: $progress-height $progress-height;\\n}\\n\\n@if $enable-transitions {\\n  .progress-bar-animated {\\n    animation: progress-bar-stripes $progress-bar-animation-timing;\\n\\n    @media (prefers-reduced-motion: reduce) {\\n      animation: none;\\n    }\\n  }\\n}\\n\",","\t\t\".media {\\n  display: flex;\\n  align-items: flex-start;\\n}\\n\\n.media-body {\\n  flex: 1;\\n}\\n\",","\t\t\"// Base class\\n//\\n// Easily usable on \u003cul\u003e, \u003col\u003e, or \u003cdiv\u003e.\\n\\n.list-group {\\n  display: flex;\\n  flex-direction: column;\\n\\n  // No need to set list-style: none; since .list-group-item is block level\\n  padding-left: 0; // reset padding because ul and ol\\n  margin-bottom: 0;\\n}\\n\\n\\n// Interactive list items\\n//\\n// Use anchor or button elements instead of `li`s or `div`s to create interactive\\n// list items. Includes an extra `.active` modifier class for selected items.\\n\\n.list-group-item-action {\\n  width: 100%; // For `\u003cbutton\u003e`s (anchors become 100% by default though)\\n  color: $list-group-action-color;\\n  text-align: inherit; // For `\u003cbutton\u003e`s (anchors inherit)\\n\\n  // Hover state\\n  @include hover-focus {\\n    z-index: 1; // Place hover/focus items above their siblings for proper border styling\\n    color: $list-group-action-hover-color;\\n    text-decoration: none;\\n    background-color: $list-group-hover-bg;\\n  }\\n\\n  \u0026:active {\\n    color: $list-group-action-active-color;\\n    background-color: $list-group-action-active-bg;\\n  }\\n}\\n\\n\\n// Individual list items\\n//\\n// Use on `li`s or `div`s within the `.list-group` parent.\\n\\n.list-group-item {\\n  position: relative;\\n  display: block;\\n  padding: $list-group-item-padding-y $list-group-item-padding-x;\\n  // Place the border on the list items and negative margin up for better styling\\n  margin-bottom: -$list-group-border-width;\\n  color: $list-group-color;\\n  background-color: $list-group-bg;\\n  border: $list-group-border-width solid $list-group-border-color;\\n\\n  \u0026:first-child {\\n    @include border-top-radius($list-group-border-radius);\\n  }\\n\\n  \u0026:last-child {\\n    margin-bottom: 0;\\n    @include border-bottom-radius($list-group-border-radius);\\n  }\\n\\n  \u0026.disabled,\\n  \u0026:disabled {\\n    color: $list-group-disabled-color;\\n    pointer-events: none;\\n    background-color: $list-group-disabled-bg;\\n  }\\n\\n  // Include both here for `\u003ca\u003e`s and `\u003cbutton\u003e`s\\n  \u0026.active {\\n    z-index: 2; // Place active items above their siblings for proper border styling\\n    color: $list-group-active-color;\\n    background-color: $list-group-active-bg;\\n    border-color: $list-group-active-border-color;\\n  }\\n}\\n\\n\\n// Horizontal\\n//\\n// Change the layout of list group items from vertical (default) to horizontal.\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    .list-group-horizontal#{$infix} {\\n      flex-direction: row;\\n\\n      .list-group-item {\\n        margin-right: -$list-group-border-width;\\n        margin-bottom: 0;\\n\\n        \u0026:first-child {\\n          @include border-left-radius($list-group-border-radius);\\n          @include border-top-right-radius(0);\\n        }\\n\\n        \u0026:last-child {\\n          margin-right: 0;\\n          @include border-right-radius($list-group-border-radius);\\n          @include border-bottom-left-radius(0);\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n\\n// Flush list items\\n//\\n// Remove borders and border-radius to keep list group items edge-to-edge. Most\\n// useful within other components (e.g., cards).\\n\\n.list-group-flush {\\n  .list-group-item {\\n    border-right: 0;\\n    border-left: 0;\\n    @include border-radius(0);\\n\\n    \u0026:last-child {\\n      margin-bottom: -$list-group-border-width;\\n    }\\n  }\\n\\n  \u0026:first-child {\\n    .list-group-item:first-child {\\n      border-top: 0;\\n    }\\n  }\\n\\n  \u0026:last-child {\\n    .list-group-item:last-child {\\n      margin-bottom: 0;\\n      border-bottom: 0;\\n    }\\n  }\\n}\\n\\n\\n// Contextual variants\\n//\\n// Add modifier classes to change text and background color on individual items.\\n// Organizationally, this must come after the `:hover` states.\\n\\n@each $color, $value in $theme-colors {\\n  @include list-group-item-variant($color, theme-color-level($color, -9), theme-color-level($color, 6));\\n}\\n\",","\t\t\".close {\\n  float: right;\\n  @include font-size($close-font-size);\\n  font-weight: $close-font-weight;\\n  line-height: 1;\\n  color: $close-color;\\n  text-shadow: $close-text-shadow;\\n  opacity: .5;\\n\\n  // Override \u003ca\u003e's hover style\\n  @include hover {\\n    color: $close-color;\\n    text-decoration: none;\\n  }\\n\\n  \u0026:not(:disabled):not(.disabled) {\\n    @include hover-focus {\\n      opacity: .75;\\n    }\\n  }\\n}\\n\\n// Additional properties for button version\\n// iOS requires the button element instead of an anchor tag.\\n// If you want the anchor version, it requires `href=\\\"#\\\"`.\\n// See https://developer.mozilla.org/en-US/docs/Web/Events/click#Safari_Mobile\\n\\n// stylelint-disable-next-line selector-no-qualifying-type\\nbutton.close {\\n  padding: 0;\\n  background-color: transparent;\\n  border: 0;\\n  appearance: none;\\n}\\n\\n// Future-proof disabling of clicks on `\u003ca\u003e` elements\\n\\n// stylelint-disable-next-line selector-no-qualifying-type\\na.close.disabled {\\n  pointer-events: none;\\n}\\n\",","\t\t\".toast {\\n  max-width: $toast-max-width;\\n  overflow: hidden; // cheap rounded corners on nested items\\n  @include font-size($toast-font-size);\\n  color: $toast-color;\\n  background-color: $toast-background-color;\\n  background-clip: padding-box;\\n  border: $toast-border-width solid $toast-border-color;\\n  box-shadow: $toast-box-shadow;\\n  backdrop-filter: blur(10px);\\n  opacity: 0;\\n  @include border-radius($toast-border-radius);\\n\\n  \u0026:not(:last-child) {\\n    margin-bottom: $toast-padding-x;\\n  }\\n\\n  \u0026.showing {\\n    opacity: 1;\\n  }\\n\\n  \u0026.show {\\n    display: block;\\n    opacity: 1;\\n  }\\n\\n  \u0026.hide {\\n    display: none;\\n  }\\n}\\n\\n.toast-header {\\n  display: flex;\\n  align-items: center;\\n  padding: $toast-padding-y $toast-padding-x;\\n  color: $toast-header-color;\\n  background-color: $toast-header-background-color;\\n  background-clip: padding-box;\\n  border-bottom: $toast-border-width solid $toast-header-border-color;\\n}\\n\\n.toast-body {\\n  padding: $toast-padding-x; // apply to both vertical and horizontal\\n}\\n\",","\t\t\"// .modal-open      - body class for killing the scroll\\n// .modal           - container to scroll within\\n// .modal-dialog    - positioning shell for the actual modal\\n// .modal-content   - actual modal w/ bg and corners and stuff\\n\\n\\n.modal-open {\\n  // Kill the scroll on the body\\n  overflow: hidden;\\n\\n  .modal {\\n    overflow-x: hidden;\\n    overflow-y: auto;\\n  }\\n}\\n\\n// Container that the modal scrolls within\\n.modal {\\n  position: fixed;\\n  top: 0;\\n  left: 0;\\n  z-index: $zindex-modal;\\n  display: none;\\n  width: 100%;\\n  height: 100%;\\n  overflow: hidden;\\n  // Prevent Chrome on Windows from adding a focus outline. For details, see\\n  // https://github.com/twbs/bootstrap/pull/10951.\\n  outline: 0;\\n  // We deliberately don't use `-webkit-overflow-scrolling: touch;` due to a\\n  // gnarly iOS Safari bug: https://bugs.webkit.org/show_bug.cgi?id=158342\\n  // See also https://github.com/twbs/bootstrap/issues/17695\\n}\\n\\n// Shell div to position the modal with bottom padding\\n.modal-dialog {\\n  position: relative;\\n  width: auto;\\n  margin: $modal-dialog-margin;\\n  // allow clicks to pass through for custom click handling to close modal\\n  pointer-events: none;\\n\\n  // When fading in the modal, animate it to slide down\\n  .modal.fade \u0026 {\\n    @include transition($modal-transition);\\n    transform: $modal-fade-transform;\\n  }\\n  .modal.show \u0026 {\\n    transform: $modal-show-transform;\\n  }\\n}\\n\\n.modal-dialog-scrollable {\\n  display: flex; // IE10/11\\n  max-height: calc(100% - #{$modal-dialog-margin * 2});\\n\\n  .modal-content {\\n    max-height: calc(100vh - #{$modal-dialog-margin * 2}); // IE10/11\\n    overflow: hidden;\\n  }\\n\\n  .modal-header,\\n  .modal-footer {\\n    flex-shrink: 0;\\n  }\\n\\n  .modal-body {\\n    overflow-y: auto;\\n  }\\n}\\n\\n.modal-dialog-centered {\\n  display: flex;\\n  align-items: center;\\n  min-height: calc(100% - #{$modal-dialog-margin * 2});\\n\\n  // Ensure `modal-dialog-centered` extends the full height of the view (IE10/11)\\n  \u0026::before {\\n    display: block; // IE10\\n    height: calc(100vh - #{$modal-dialog-margin * 2});\\n    content: \\\"\\\";\\n  }\\n\\n  // Ensure `.modal-body` shows scrollbar (IE10/11)\\n  \u0026.modal-dialog-scrollable {\\n    flex-direction: column;\\n    justify-content: center;\\n    height: 100%;\\n\\n    .modal-content {\\n      max-height: none;\\n    }\\n\\n    \u0026::before {\\n      content: none;\\n    }\\n  }\\n}\\n\\n// Actual modal\\n.modal-content {\\n  position: relative;\\n  display: flex;\\n  flex-direction: column;\\n  width: 100%; // Ensure `.modal-content` extends the full width of the parent `.modal-dialog`\\n  // counteract the pointer-events: none; in the .modal-dialog\\n  color: $modal-content-color;\\n  pointer-events: auto;\\n  background-color: $modal-content-bg;\\n  background-clip: padding-box;\\n  border: $modal-content-border-width solid $modal-content-border-color;\\n  @include border-radius($modal-content-border-radius);\\n  @include box-shadow($modal-content-box-shadow-xs);\\n  // Remove focus outline from opened modal\\n  outline: 0;\\n}\\n\\n// Modal background\\n.modal-backdrop {\\n  position: fixed;\\n  top: 0;\\n  left: 0;\\n  z-index: $zindex-modal-backdrop;\\n  width: 100vw;\\n  height: 100vh;\\n  background-color: $modal-backdrop-bg;\\n\\n  // Fade for backdrop\\n  \u0026.fade { opacity: 0; }\\n  \u0026.show { opacity: $modal-backdrop-opacity; }\\n}\\n\\n// Modal header\\n// Top section of the modal w/ title and dismiss\\n.modal-header {\\n  display: flex;\\n  align-items: flex-start; // so the close btn always stays on the upper right corner\\n  justify-content: space-between; // Put modal header elements (title and dismiss) on opposite ends\\n  padding: $modal-header-padding;\\n  border-bottom: $modal-header-border-width solid $modal-header-border-color;\\n  @include border-top-radius($modal-content-border-radius);\\n\\n  .close {\\n    padding: $modal-header-padding;\\n    // auto on the left force icon to the right even when there is no .modal-title\\n    margin: (-$modal-header-padding-y) (-$modal-header-padding-x) (-$modal-header-padding-y) auto;\\n  }\\n}\\n\\n// Title text within header\\n.modal-title {\\n  margin-bottom: 0;\\n  line-height: $modal-title-line-height;\\n}\\n\\n// Modal body\\n// Where all modal content resides (sibling of .modal-header and .modal-footer)\\n.modal-body {\\n  position: relative;\\n  // Enable `flex-grow: 1` so that the body take up as much space as possible\\n  // when should there be a fixed height on `.modal-dialog`.\\n  flex: 1 1 auto;\\n  padding: $modal-inner-padding;\\n}\\n\\n// Footer (for actions)\\n.modal-footer {\\n  display: flex;\\n  align-items: center; // vertically center\\n  justify-content: flex-end; // Right align buttons with flex property because text-align doesn't work on flex items\\n  padding: $modal-inner-padding;\\n  border-top: $modal-footer-border-width solid $modal-footer-border-color;\\n  @include border-bottom-radius($modal-content-border-radius);\\n\\n  // Easily place margin between footer elements\\n  \u003e :not(:first-child) { margin-left: .25rem; }\\n  \u003e :not(:last-child) { margin-right: .25rem; }\\n}\\n\\n// Measure scrollbar width for padding body during modal show/hide\\n.modal-scrollbar-measure {\\n  position: absolute;\\n  top: -9999px;\\n  width: 50px;\\n  height: 50px;\\n  overflow: scroll;\\n}\\n\\n// Scale up the modal\\n@include media-breakpoint-up(sm) {\\n  // Automatically set modal's width for larger viewports\\n  .modal-dialog {\\n    max-width: $modal-md;\\n    margin: $modal-dialog-margin-y-sm-up auto;\\n  }\\n\\n  .modal-dialog-scrollable {\\n    max-height: calc(100% - #{$modal-dialog-margin-y-sm-up * 2});\\n\\n    .modal-content {\\n      max-height: calc(100vh - #{$modal-dialog-margin-y-sm-up * 2});\\n    }\\n  }\\n\\n  .modal-dialog-centered {\\n    min-height: calc(100% - #{$modal-dialog-margin-y-sm-up * 2});\\n\\n    \u0026::before {\\n      height: calc(100vh - #{$modal-dialog-margin-y-sm-up * 2});\\n    }\\n  }\\n\\n  .modal-content {\\n    @include box-shadow($modal-content-box-shadow-sm-up);\\n  }\\n\\n  .modal-sm { max-width: $modal-sm; }\\n}\\n\\n@include media-breakpoint-up(lg) {\\n  .modal-lg,\\n  .modal-xl {\\n    max-width: $modal-lg;\\n  }\\n}\\n\\n@include media-breakpoint-up(xl) {\\n  .modal-xl { max-width: $modal-xl; }\\n}\\n\",","\t\t\"// Base class\\n.tooltip {\\n  position: absolute;\\n  z-index: $zindex-tooltip;\\n  display: block;\\n  margin: $tooltip-margin;\\n  // Our parent element can be arbitrary since tooltips are by default inserted as a sibling of their target element.\\n  // So reset our font and text properties to avoid inheriting weird values.\\n  @include reset-text();\\n  @include font-size($tooltip-font-size);\\n  // Allow breaking very long words so they don't overflow the tooltip's bounds\\n  word-wrap: break-word;\\n  opacity: 0;\\n\\n  \u0026.show { opacity: $tooltip-opacity; }\\n\\n  .arrow {\\n    position: absolute;\\n    display: block;\\n    width: $tooltip-arrow-width;\\n    height: $tooltip-arrow-height;\\n\\n    \u0026::before {\\n      position: absolute;\\n      content: \\\"\\\";\\n      border-color: transparent;\\n      border-style: solid;\\n    }\\n  }\\n}\\n\\n.bs-tooltip-top {\\n  padding: $tooltip-arrow-height 0;\\n\\n  .arrow {\\n    bottom: 0;\\n\\n    \u0026::before {\\n      top: 0;\\n      border-width: $tooltip-arrow-height ($tooltip-arrow-width / 2) 0;\\n      border-top-color: $tooltip-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-tooltip-right {\\n  padding: 0 $tooltip-arrow-height;\\n\\n  .arrow {\\n    left: 0;\\n    width: $tooltip-arrow-height;\\n    height: $tooltip-arrow-width;\\n\\n    \u0026::before {\\n      right: 0;\\n      border-width: ($tooltip-arrow-width / 2) $tooltip-arrow-height ($tooltip-arrow-width / 2) 0;\\n      border-right-color: $tooltip-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-tooltip-bottom {\\n  padding: $tooltip-arrow-height 0;\\n\\n  .arrow {\\n    top: 0;\\n\\n    \u0026::before {\\n      bottom: 0;\\n      border-width: 0 ($tooltip-arrow-width / 2) $tooltip-arrow-height;\\n      border-bottom-color: $tooltip-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-tooltip-left {\\n  padding: 0 $tooltip-arrow-height;\\n\\n  .arrow {\\n    right: 0;\\n    width: $tooltip-arrow-height;\\n    height: $tooltip-arrow-width;\\n\\n    \u0026::before {\\n      left: 0;\\n      border-width: ($tooltip-arrow-width / 2) 0 ($tooltip-arrow-width / 2) $tooltip-arrow-height;\\n      border-left-color: $tooltip-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-tooltip-auto {\\n  \u0026[x-placement^=\\\"top\\\"] {\\n    @extend .bs-tooltip-top;\\n  }\\n  \u0026[x-placement^=\\\"right\\\"] {\\n    @extend .bs-tooltip-right;\\n  }\\n  \u0026[x-placement^=\\\"bottom\\\"] {\\n    @extend .bs-tooltip-bottom;\\n  }\\n  \u0026[x-placement^=\\\"left\\\"] {\\n    @extend .bs-tooltip-left;\\n  }\\n}\\n\\n// Wrapper for the tooltip content\\n.tooltip-inner {\\n  max-width: $tooltip-max-width;\\n  padding: $tooltip-padding-y $tooltip-padding-x;\\n  color: $tooltip-color;\\n  text-align: center;\\n  background-color: $tooltip-bg;\\n  @include border-radius($tooltip-border-radius);\\n}\\n\",","\t\t\".popover {\\n  position: absolute;\\n  top: 0;\\n  left: 0;\\n  z-index: $zindex-popover;\\n  display: block;\\n  max-width: $popover-max-width;\\n  // Our parent element can be arbitrary since tooltips are by default inserted as a sibling of their target element.\\n  // So reset our font and text properties to avoid inheriting weird values.\\n  @include reset-text();\\n  @include font-size($popover-font-size);\\n  // Allow breaking very long words so they don't overflow the popover's bounds\\n  word-wrap: break-word;\\n  background-color: $popover-bg;\\n  background-clip: padding-box;\\n  border: $popover-border-width solid $popover-border-color;\\n  @include border-radius($popover-border-radius);\\n  @include box-shadow($popover-box-shadow);\\n\\n  .arrow {\\n    position: absolute;\\n    display: block;\\n    width: $popover-arrow-width;\\n    height: $popover-arrow-height;\\n    margin: 0 $border-radius-lg;\\n\\n    \u0026::before,\\n    \u0026::after {\\n      position: absolute;\\n      display: block;\\n      content: \\\"\\\";\\n      border-color: transparent;\\n      border-style: solid;\\n    }\\n  }\\n}\\n\\n.bs-popover-top {\\n  margin-bottom: $popover-arrow-height;\\n\\n  \u003e .arrow {\\n    bottom: calc((#{$popover-arrow-height} + #{$popover-border-width}) * -1);\\n\\n    \u0026::before {\\n      bottom: 0;\\n      border-width: $popover-arrow-height ($popover-arrow-width / 2) 0;\\n      border-top-color: $popover-arrow-outer-color;\\n    }\\n\\n    \u0026::after {\\n      bottom: $popover-border-width;\\n      border-width: $popover-arrow-height ($popover-arrow-width / 2) 0;\\n      border-top-color: $popover-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-popover-right {\\n  margin-left: $popover-arrow-height;\\n\\n  \u003e .arrow {\\n    left: calc((#{$popover-arrow-height} + #{$popover-border-width}) * -1);\\n    width: $popover-arrow-height;\\n    height: $popover-arrow-width;\\n    margin: $border-radius-lg 0; // make sure the arrow does not touch the popover's rounded corners\\n\\n    \u0026::before {\\n      left: 0;\\n      border-width: ($popover-arrow-width / 2) $popover-arrow-height ($popover-arrow-width / 2) 0;\\n      border-right-color: $popover-arrow-outer-color;\\n    }\\n\\n    \u0026::after {\\n      left: $popover-border-width;\\n      border-width: ($popover-arrow-width / 2) $popover-arrow-height ($popover-arrow-width / 2) 0;\\n      border-right-color: $popover-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-popover-bottom {\\n  margin-top: $popover-arrow-height;\\n\\n  \u003e .arrow {\\n    top: calc((#{$popover-arrow-height} + #{$popover-border-width}) * -1);\\n\\n    \u0026::before {\\n      top: 0;\\n      border-width: 0 ($popover-arrow-width / 2) $popover-arrow-height ($popover-arrow-width / 2);\\n      border-bottom-color: $popover-arrow-outer-color;\\n    }\\n\\n    \u0026::after {\\n      top: $popover-border-width;\\n      border-width: 0 ($popover-arrow-width / 2) $popover-arrow-height ($popover-arrow-width / 2);\\n      border-bottom-color: $popover-arrow-color;\\n    }\\n  }\\n\\n  // This will remove the popover-header's border just below the arrow\\n  .popover-header::before {\\n    position: absolute;\\n    top: 0;\\n    left: 50%;\\n    display: block;\\n    width: $popover-arrow-width;\\n    margin-left: -$popover-arrow-width / 2;\\n    content: \\\"\\\";\\n    border-bottom: $popover-border-width solid $popover-header-bg;\\n  }\\n}\\n\\n.bs-popover-left {\\n  margin-right: $popover-arrow-height;\\n\\n  \u003e .arrow {\\n    right: calc((#{$popover-arrow-height} + #{$popover-border-width}) * -1);\\n    width: $popover-arrow-height;\\n    height: $popover-arrow-width;\\n    margin: $border-radius-lg 0; // make sure the arrow does not touch the popover's rounded corners\\n\\n    \u0026::before {\\n      right: 0;\\n      border-width: ($popover-arrow-width / 2) 0 ($popover-arrow-width / 2) $popover-arrow-height;\\n      border-left-color: $popover-arrow-outer-color;\\n    }\\n\\n    \u0026::after {\\n      right: $popover-border-width;\\n      border-width: ($popover-arrow-width / 2) 0 ($popover-arrow-width / 2) $popover-arrow-height;\\n      border-left-color: $popover-arrow-color;\\n    }\\n  }\\n}\\n\\n.bs-popover-auto {\\n  \u0026[x-placement^=\\\"top\\\"] {\\n    @extend .bs-popover-top;\\n  }\\n  \u0026[x-placement^=\\\"right\\\"] {\\n    @extend .bs-popover-right;\\n  }\\n  \u0026[x-placement^=\\\"bottom\\\"] {\\n    @extend .bs-popover-bottom;\\n  }\\n  \u0026[x-placement^=\\\"left\\\"] {\\n    @extend .bs-popover-left;\\n  }\\n}\\n\\n\\n// Offset the popover to account for the popover arrow\\n.popover-header {\\n  padding: $popover-header-padding-y $popover-header-padding-x;\\n  margin-bottom: 0; // Reset the default from Reboot\\n  @include font-size($font-size-base);\\n  color: $popover-header-color;\\n  background-color: $popover-header-bg;\\n  border-bottom: $popover-border-width solid darken($popover-header-bg, 5%);\\n  $offset-border-width: calc(#{$border-radius-lg} - #{$popover-border-width});\\n  @include border-top-radius($offset-border-width);\\n\\n  \u0026:empty {\\n    display: none;\\n  }\\n}\\n\\n.popover-body {\\n  padding: $popover-body-padding-y $popover-body-padding-x;\\n  color: $popover-body-color;\\n}\\n\",","\t\t\"// Notes on the classes:\\n//\\n// 1. .carousel.pointer-event should ideally be pan-y (to allow for users to scroll vertically)\\n//    even when their scroll action started on a carousel, but for compatibility (with Firefox)\\n//    we're preventing all actions instead\\n// 2. The .carousel-item-left and .carousel-item-right is used to indicate where\\n//    the active slide is heading.\\n// 3. .active.carousel-item is the current slide.\\n// 4. .active.carousel-item-left and .active.carousel-item-right is the current\\n//    slide in its in-transition state. Only one of these occurs at a time.\\n// 5. .carousel-item-next.carousel-item-left and .carousel-item-prev.carousel-item-right\\n//    is the upcoming slide in transition.\\n\\n.carousel {\\n  position: relative;\\n}\\n\\n.carousel.pointer-event {\\n  touch-action: pan-y;\\n}\\n\\n.carousel-inner {\\n  position: relative;\\n  width: 100%;\\n  overflow: hidden;\\n  @include clearfix();\\n}\\n\\n.carousel-item {\\n  position: relative;\\n  display: none;\\n  float: left;\\n  width: 100%;\\n  margin-right: -100%;\\n  backface-visibility: hidden;\\n  @include transition($carousel-transition);\\n}\\n\\n.carousel-item.active,\\n.carousel-item-next,\\n.carousel-item-prev {\\n  display: block;\\n}\\n\\n.carousel-item-next:not(.carousel-item-left),\\n.active.carousel-item-right {\\n  transform: translateX(100%);\\n}\\n\\n.carousel-item-prev:not(.carousel-item-right),\\n.active.carousel-item-left {\\n  transform: translateX(-100%);\\n}\\n\\n\\n//\\n// Alternate transitions\\n//\\n\\n.carousel-fade {\\n  .carousel-item {\\n    opacity: 0;\\n    transition-property: opacity;\\n    transform: none;\\n  }\\n\\n  .carousel-item.active,\\n  .carousel-item-next.carousel-item-left,\\n  .carousel-item-prev.carousel-item-right {\\n    z-index: 1;\\n    opacity: 1;\\n  }\\n\\n  .active.carousel-item-left,\\n  .active.carousel-item-right {\\n    z-index: 0;\\n    opacity: 0;\\n    @include transition(0s $carousel-transition-duration opacity);\\n  }\\n}\\n\\n\\n//\\n// Left/right controls for nav\\n//\\n\\n.carousel-control-prev,\\n.carousel-control-next {\\n  position: absolute;\\n  top: 0;\\n  bottom: 0;\\n  z-index: 1;\\n  // Use flex for alignment (1-3)\\n  display: flex; // 1. allow flex styles\\n  align-items: center; // 2. vertically center contents\\n  justify-content: center; // 3. horizontally center contents\\n  width: $carousel-control-width;\\n  color: $carousel-control-color;\\n  text-align: center;\\n  opacity: $carousel-control-opacity;\\n  @include transition($carousel-control-transition);\\n\\n  // Hover/focus state\\n  @include hover-focus {\\n    color: $carousel-control-color;\\n    text-decoration: none;\\n    outline: 0;\\n    opacity: $carousel-control-hover-opacity;\\n  }\\n}\\n.carousel-control-prev {\\n  left: 0;\\n  @if $enable-gradients {\\n    background: linear-gradient(90deg, rgba($black, .25), rgba($black, .001));\\n  }\\n}\\n.carousel-control-next {\\n  right: 0;\\n  @if $enable-gradients {\\n    background: linear-gradient(270deg, rgba($black, .25), rgba($black, .001));\\n  }\\n}\\n\\n// Icons for within\\n.carousel-control-prev-icon,\\n.carousel-control-next-icon {\\n  display: inline-block;\\n  width: $carousel-control-icon-width;\\n  height: $carousel-control-icon-width;\\n  background: no-repeat 50% / 100% 100%;\\n}\\n.carousel-control-prev-icon {\\n  background-image: $carousel-control-prev-icon-bg;\\n}\\n.carousel-control-next-icon {\\n  background-image: $carousel-control-next-icon-bg;\\n}\\n\\n\\n// Optional indicator pips\\n//\\n// Add an ordered list with the following class and add a list item for each\\n// slide your carousel holds.\\n\\n.carousel-indicators {\\n  position: absolute;\\n  right: 0;\\n  bottom: 0;\\n  left: 0;\\n  z-index: 15;\\n  display: flex;\\n  justify-content: center;\\n  padding-left: 0; // override \u003col\u003e default\\n  // Use the .carousel-control's width as margin so we don't overlay those\\n  margin-right: $carousel-control-width;\\n  margin-left: $carousel-control-width;\\n  list-style: none;\\n\\n  li {\\n    box-sizing: content-box;\\n    flex: 0 1 auto;\\n    width: $carousel-indicator-width;\\n    height: $carousel-indicator-height;\\n    margin-right: $carousel-indicator-spacer;\\n    margin-left: $carousel-indicator-spacer;\\n    text-indent: -999px;\\n    cursor: pointer;\\n    background-color: $carousel-indicator-active-bg;\\n    background-clip: padding-box;\\n    // Use transparent borders to increase the hit area by 10px on top and bottom.\\n    border-top: $carousel-indicator-hit-area-height solid transparent;\\n    border-bottom: $carousel-indicator-hit-area-height solid transparent;\\n    opacity: .5;\\n    @include transition($carousel-indicator-transition);\\n  }\\n\\n  .active {\\n    opacity: 1;\\n  }\\n}\\n\\n\\n// Optional captions\\n//\\n//\\n\\n.carousel-caption {\\n  position: absolute;\\n  right: (100% - $carousel-caption-width) / 2;\\n  bottom: 20px;\\n  left: (100% - $carousel-caption-width) / 2;\\n  z-index: 10;\\n  padding-top: 20px;\\n  padding-bottom: 20px;\\n  color: $carousel-caption-color;\\n  text-align: center;\\n}\\n\",","\t\t\"//\\n// Rotating border\\n//\\n\\n@keyframes spinner-border {\\n  to { transform: rotate(360deg); }\\n}\\n\\n.spinner-border {\\n  display: inline-block;\\n  width: $spinner-width;\\n  height: $spinner-height;\\n  vertical-align: text-bottom;\\n  border: $spinner-border-width solid currentColor;\\n  border-right-color: transparent;\\n  // stylelint-disable-next-line property-blacklist\\n  border-radius: 50%;\\n  animation: spinner-border .75s linear infinite;\\n}\\n\\n.spinner-border-sm {\\n  width: $spinner-width-sm;\\n  height: $spinner-height-sm;\\n  border-width: $spinner-border-width-sm;\\n}\\n\\n//\\n// Growing circle\\n//\\n\\n@keyframes spinner-grow {\\n  0% {\\n    transform: scale(0);\\n  }\\n  50% {\\n    opacity: 1;\\n  }\\n}\\n\\n.spinner-grow {\\n  display: inline-block;\\n  width: $spinner-width;\\n  height: $spinner-height;\\n  vertical-align: text-bottom;\\n  background-color: currentColor;\\n  // stylelint-disable-next-line property-blacklist\\n  border-radius: 50%;\\n  opacity: 0;\\n  animation: spinner-grow .75s linear infinite;\\n}\\n\\n.spinner-grow-sm {\\n  width: $spinner-width-sm;\\n  height: $spinner-height-sm;\\n}\\n\",","\t\t\"@import \\\"utilities/align\\\";\\n@import \\\"utilities/background\\\";\\n@import \\\"utilities/borders\\\";\\n@import \\\"utilities/clearfix\\\";\\n@import \\\"utilities/display\\\";\\n@import \\\"utilities/embed\\\";\\n@import \\\"utilities/flex\\\";\\n@import \\\"utilities/float\\\";\\n@import \\\"utilities/overflow\\\";\\n@import \\\"utilities/position\\\";\\n@import \\\"utilities/screenreaders\\\";\\n@import \\\"utilities/shadows\\\";\\n@import \\\"utilities/sizing\\\";\\n@import \\\"utilities/stretched-link\\\";\\n@import \\\"utilities/spacing\\\";\\n@import \\\"utilities/text\\\";\\n@import \\\"utilities/visibility\\\";\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n.align-baseline    { vertical-align: baseline !important; } // Browser default\\n.align-top         { vertical-align: top !important; }\\n.align-middle      { vertical-align: middle !important; }\\n.align-bottom      { vertical-align: bottom !important; }\\n.align-text-bottom { vertical-align: text-bottom !important; }\\n.align-text-top    { vertical-align: text-top !important; }\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n@each $color, $value in $theme-colors {\\n  @include bg-variant(\\\".bg-#{$color}\\\", $value);\\n}\\n\\n@if $enable-gradients {\\n  @each $color, $value in $theme-colors {\\n    @include bg-gradient-variant(\\\".bg-gradient-#{$color}\\\", $value);\\n  }\\n}\\n\\n.bg-white {\\n  background-color: $white !important;\\n}\\n\\n.bg-transparent {\\n  background-color: transparent !important;\\n}\\n\",","\t\t\"// stylelint-disable property-blacklist, declaration-no-important\\n\\n//\\n// Border\\n//\\n\\n.border         { border: $border-width solid $border-color !important; }\\n.border-top     { border-top: $border-width solid $border-color !important; }\\n.border-right   { border-right: $border-width solid $border-color !important; }\\n.border-bottom  { border-bottom: $border-width solid $border-color !important; }\\n.border-left    { border-left: $border-width solid $border-color !important; }\\n\\n.border-0        { border: 0 !important; }\\n.border-top-0    { border-top: 0 !important; }\\n.border-right-0  { border-right: 0 !important; }\\n.border-bottom-0 { border-bottom: 0 !important; }\\n.border-left-0   { border-left: 0 !important; }\\n\\n@each $color, $value in $theme-colors {\\n  .border-#{$color} {\\n    border-color: $value !important;\\n  }\\n}\\n\\n.border-white {\\n  border-color: $white !important;\\n}\\n\\n//\\n// Border-radius\\n//\\n\\n.rounded-sm {\\n  border-radius: $border-radius-sm !important;\\n}\\n\\n.rounded {\\n  border-radius: $border-radius !important;\\n}\\n\\n.rounded-top {\\n  border-top-left-radius: $border-radius !important;\\n  border-top-right-radius: $border-radius !important;\\n}\\n\\n.rounded-right {\\n  border-top-right-radius: $border-radius !important;\\n  border-bottom-right-radius: $border-radius !important;\\n}\\n\\n.rounded-bottom {\\n  border-bottom-right-radius: $border-radius !important;\\n  border-bottom-left-radius: $border-radius !important;\\n}\\n\\n.rounded-left {\\n  border-top-left-radius: $border-radius !important;\\n  border-bottom-left-radius: $border-radius !important;\\n}\\n\\n.rounded-lg {\\n  border-radius: $border-radius-lg !important;\\n}\\n\\n.rounded-circle {\\n  border-radius: 50% !important;\\n}\\n\\n.rounded-pill {\\n  border-radius: $rounded-pill !important;\\n}\\n\\n.rounded-0 {\\n  border-radius: 0 !important;\\n}\\n\",","\t\t\".clearfix {\\n  @include clearfix();\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n//\\n// Utilities for common `display` values\\n//\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    @each $value in $displays {\\n      .d#{$infix}-#{$value} { display: $value !important; }\\n    }\\n  }\\n}\\n\\n\\n//\\n// Utilities for toggling `display` in print\\n//\\n\\n@media print {\\n  @each $value in $displays {\\n    .d-print-#{$value} { display: $value !important; }\\n  }\\n}\\n\",","\t\t\"// Credit: Nicolas Gallagher and SUIT CSS.\\n\\n.embed-responsive {\\n  position: relative;\\n  display: block;\\n  width: 100%;\\n  padding: 0;\\n  overflow: hidden;\\n\\n  \u0026::before {\\n    display: block;\\n    content: \\\"\\\";\\n  }\\n\\n  .embed-responsive-item,\\n  iframe,\\n  embed,\\n  object,\\n  video {\\n    position: absolute;\\n    top: 0;\\n    bottom: 0;\\n    left: 0;\\n    width: 100%;\\n    height: 100%;\\n    border: 0;\\n  }\\n}\\n\\n@each $embed-responsive-aspect-ratio in $embed-responsive-aspect-ratios {\\n  $embed-responsive-aspect-ratio-x: nth($embed-responsive-aspect-ratio, 1);\\n  $embed-responsive-aspect-ratio-y: nth($embed-responsive-aspect-ratio, 2);\\n\\n  .embed-responsive-#{$embed-responsive-aspect-ratio-x}by#{$embed-responsive-aspect-ratio-y} {\\n    \u0026::before {\\n      padding-top: percentage($embed-responsive-aspect-ratio-y / $embed-responsive-aspect-ratio-x);\\n    }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Flex variation\\n//\\n// Custom styles for additional flex alignment options.\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    .flex#{$infix}-row            { flex-direction: row !important; }\\n    .flex#{$infix}-column         { flex-direction: column !important; }\\n    .flex#{$infix}-row-reverse    { flex-direction: row-reverse !important; }\\n    .flex#{$infix}-column-reverse { flex-direction: column-reverse !important; }\\n\\n    .flex#{$infix}-wrap         { flex-wrap: wrap !important; }\\n    .flex#{$infix}-nowrap       { flex-wrap: nowrap !important; }\\n    .flex#{$infix}-wrap-reverse { flex-wrap: wrap-reverse !important; }\\n    .flex#{$infix}-fill         { flex: 1 1 auto !important; }\\n    .flex#{$infix}-grow-0       { flex-grow: 0 !important; }\\n    .flex#{$infix}-grow-1       { flex-grow: 1 !important; }\\n    .flex#{$infix}-shrink-0     { flex-shrink: 0 !important; }\\n    .flex#{$infix}-shrink-1     { flex-shrink: 1 !important; }\\n\\n    .justify-content#{$infix}-start   { justify-content: flex-start !important; }\\n    .justify-content#{$infix}-end     { justify-content: flex-end !important; }\\n    .justify-content#{$infix}-center  { justify-content: center !important; }\\n    .justify-content#{$infix}-between { justify-content: space-between !important; }\\n    .justify-content#{$infix}-around  { justify-content: space-around !important; }\\n\\n    .align-items#{$infix}-start    { align-items: flex-start !important; }\\n    .align-items#{$infix}-end      { align-items: flex-end !important; }\\n    .align-items#{$infix}-center   { align-items: center !important; }\\n    .align-items#{$infix}-baseline { align-items: baseline !important; }\\n    .align-items#{$infix}-stretch  { align-items: stretch !important; }\\n\\n    .align-content#{$infix}-start   { align-content: flex-start !important; }\\n    .align-content#{$infix}-end     { align-content: flex-end !important; }\\n    .align-content#{$infix}-center  { align-content: center !important; }\\n    .align-content#{$infix}-between { align-content: space-between !important; }\\n    .align-content#{$infix}-around  { align-content: space-around !important; }\\n    .align-content#{$infix}-stretch { align-content: stretch !important; }\\n\\n    .align-self#{$infix}-auto     { align-self: auto !important; }\\n    .align-self#{$infix}-start    { align-self: flex-start !important; }\\n    .align-self#{$infix}-end      { align-self: flex-end !important; }\\n    .align-self#{$infix}-center   { align-self: center !important; }\\n    .align-self#{$infix}-baseline { align-self: baseline !important; }\\n    .align-self#{$infix}-stretch  { align-self: stretch !important; }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    .float#{$infix}-left  { float: left !important; }\\n    .float#{$infix}-right { float: right !important; }\\n    .float#{$infix}-none  { float: none !important; }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n@each $value in $overflows {\\n  .overflow-#{$value} { overflow: $value !important; }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Common values\\n@each $position in $positions {\\n  .position-#{$position} { position: $position !important; }\\n}\\n\\n// Shorthand\\n\\n.fixed-top {\\n  position: fixed;\\n  top: 0;\\n  right: 0;\\n  left: 0;\\n  z-index: $zindex-fixed;\\n}\\n\\n.fixed-bottom {\\n  position: fixed;\\n  right: 0;\\n  bottom: 0;\\n  left: 0;\\n  z-index: $zindex-fixed;\\n}\\n\\n.sticky-top {\\n  @supports (position: sticky) {\\n    position: sticky;\\n    top: 0;\\n    z-index: $zindex-sticky;\\n  }\\n}\\n\",","\t\t\"//\\n// Screenreaders\\n//\\n\\n.sr-only {\\n  @include sr-only();\\n}\\n\\n.sr-only-focusable {\\n  @include sr-only-focusable();\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n.shadow-sm { box-shadow: $box-shadow-sm !important; }\\n.shadow { box-shadow: $box-shadow !important; }\\n.shadow-lg { box-shadow: $box-shadow-lg !important; }\\n.shadow-none { box-shadow: none !important; }\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Width and height\\n\\n@each $prop, $abbrev in (width: w, height: h) {\\n  @each $size, $length in $sizes {\\n    .#{$abbrev}-#{$size} { #{$prop}: $length !important; }\\n  }\\n}\\n\\n.mw-100 { max-width: 100% !important; }\\n.mh-100 { max-height: 100% !important; }\\n\\n// Viewport additional helpers\\n\\n.min-vw-100 { min-width: 100vw !important; }\\n.min-vh-100 { min-height: 100vh !important; }\\n\\n.vw-100 { width: 100vw !important; }\\n.vh-100 { height: 100vh !important; }\\n\",","\t\t\"//\\n// Stretched link\\n//\\n\\n.stretched-link {\\n  \u0026::after {\\n    position: absolute;\\n    top: 0;\\n    right: 0;\\n    bottom: 0;\\n    left: 0;\\n    z-index: 1;\\n    // Just in case `pointer-events: none` is set on a parent\\n    pointer-events: auto;\\n    content: \\\"\\\";\\n    // IE10 bugfix, see https://stackoverflow.com/questions/16947967/ie10-hover-pseudo-class-doesnt-work-without-background-color\\n    background-color: rgba(0, 0, 0, 0);\\n  }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n// Margin and Padding\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    @each $prop, $abbrev in (margin: m, padding: p) {\\n      @each $size, $length in $spacers {\\n        .#{$abbrev}#{$infix}-#{$size} { #{$prop}: $length !important; }\\n        .#{$abbrev}t#{$infix}-#{$size},\\n        .#{$abbrev}y#{$infix}-#{$size} {\\n          #{$prop}-top: $length !important;\\n        }\\n        .#{$abbrev}r#{$infix}-#{$size},\\n        .#{$abbrev}x#{$infix}-#{$size} {\\n          #{$prop}-right: $length !important;\\n        }\\n        .#{$abbrev}b#{$infix}-#{$size},\\n        .#{$abbrev}y#{$infix}-#{$size} {\\n          #{$prop}-bottom: $length !important;\\n        }\\n        .#{$abbrev}l#{$infix}-#{$size},\\n        .#{$abbrev}x#{$infix}-#{$size} {\\n          #{$prop}-left: $length !important;\\n        }\\n      }\\n    }\\n\\n    // Negative margins (e.g., where `.mb-n1` is negative version of `.mb-1`)\\n    @each $size, $length in $spacers {\\n      @if $size != 0 {\\n        .m#{$infix}-n#{$size} { margin: -$length !important; }\\n        .mt#{$infix}-n#{$size},\\n        .my#{$infix}-n#{$size} {\\n          margin-top: -$length !important;\\n        }\\n        .mr#{$infix}-n#{$size},\\n        .mx#{$infix}-n#{$size} {\\n          margin-right: -$length !important;\\n        }\\n        .mb#{$infix}-n#{$size},\\n        .my#{$infix}-n#{$size} {\\n          margin-bottom: -$length !important;\\n        }\\n        .ml#{$infix}-n#{$size},\\n        .mx#{$infix}-n#{$size} {\\n          margin-left: -$length !important;\\n        }\\n      }\\n    }\\n\\n    // Some special margin utils\\n    .m#{$infix}-auto { margin: auto !important; }\\n    .mt#{$infix}-auto,\\n    .my#{$infix}-auto {\\n      margin-top: auto !important;\\n    }\\n    .mr#{$infix}-auto,\\n    .mx#{$infix}-auto {\\n      margin-right: auto !important;\\n    }\\n    .mb#{$infix}-auto,\\n    .my#{$infix}-auto {\\n      margin-bottom: auto !important;\\n    }\\n    .ml#{$infix}-auto,\\n    .mx#{$infix}-auto {\\n      margin-left: auto !important;\\n    }\\n  }\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n//\\n// Text\\n//\\n\\n.text-monospace { font-family: $font-family-monospace !important; }\\n\\n// Alignment\\n\\n.text-justify  { text-align: justify !important; }\\n.text-wrap     { white-space: normal !important; }\\n.text-nowrap   { white-space: nowrap !important; }\\n.text-truncate { @include text-truncate; }\\n\\n// Responsive alignment\\n\\n@each $breakpoint in map-keys($grid-breakpoints) {\\n  @include media-breakpoint-up($breakpoint) {\\n    $infix: breakpoint-infix($breakpoint, $grid-breakpoints);\\n\\n    .text#{$infix}-left   { text-align: left !important; }\\n    .text#{$infix}-right  { text-align: right !important; }\\n    .text#{$infix}-center { text-align: center !important; }\\n  }\\n}\\n\\n// Transformation\\n\\n.text-lowercase  { text-transform: lowercase !important; }\\n.text-uppercase  { text-transform: uppercase !important; }\\n.text-capitalize { text-transform: capitalize !important; }\\n\\n// Weight and italics\\n\\n.font-weight-light   { font-weight: $font-weight-light !important; }\\n.font-weight-lighter { font-weight: $font-weight-lighter !important; }\\n.font-weight-normal  { font-weight: $font-weight-normal !important; }\\n.font-weight-bold    { font-weight: $font-weight-bold !important; }\\n.font-weight-bolder  { font-weight: $font-weight-bolder !important; }\\n.font-italic         { font-style: italic !important; }\\n\\n// Contextual colors\\n\\n.text-white { color: $white !important; }\\n\\n@each $color, $value in $theme-colors {\\n  @include text-emphasis-variant(\\\".text-#{$color}\\\", $value);\\n}\\n\\n.text-body { color: $body-color !important; }\\n.text-muted { color: $text-muted !important; }\\n\\n.text-black-50 { color: rgba($black, .5) !important; }\\n.text-white-50 { color: rgba($white, .5) !important; }\\n\\n// Misc\\n\\n.text-hide {\\n  @include text-hide($ignore-warning: true);\\n}\\n\\n.text-decoration-none { text-decoration: none !important; }\\n\\n.text-break {\\n  word-break: break-word !important; // IE \u0026 \u003c Edge 18\\n  overflow-wrap: break-word !important;\\n}\\n\\n// Reset\\n\\n.text-reset { color: inherit !important; }\\n\",","\t\t\"// stylelint-disable declaration-no-important\\n\\n//\\n// Visibility utilities\\n//\\n\\n.visible {\\n  visibility: visible !important;\\n}\\n\\n.invisible {\\n  visibility: hidden !important;\\n}\\n\",","\t\t\"// stylelint-disable declaration-no-important, selector-no-qualifying-type\\n\\n// Source: https://github.com/h5bp/html5-boilerplate/blob/master/src/css/main.css\\n\\n// ==========================================================================\\n// Print styles.\\n// Inlined to avoid the additional HTTP request:\\n// https://www.phpied.com/delay-loading-your-print-css/\\n// ==========================================================================\\n\\n@if $enable-print-styles {\\n  @media print {\\n    *,\\n    *::before,\\n    *::after {\\n      // Bootstrap specific; comment out `color` and `background`\\n      //color: $black !important; // Black prints faster\\n      text-shadow: none !important;\\n      //background: transparent !important;\\n      box-shadow: none !important;\\n    }\\n\\n    a {\\n      \u0026:not(.btn) {\\n        text-decoration: underline;\\n      }\\n    }\\n\\n    // Bootstrap specific; comment the following selector out\\n    //a[href]::after {\\n    //  content: \\\" (\\\" attr(href) \\\")\\\";\\n    //}\\n\\n    abbr[title]::after {\\n      content: \\\" (\\\" attr(title) \\\")\\\";\\n    }\\n\\n    // Bootstrap specific; comment the following selector out\\n    //\\n    // Don't show links that are fragment identifiers,\\n    // or use the `javascript:` pseudo protocol\\n    //\\n\\n    //a[href^=\\\"#\\\"]::after,\\n    //a[href^=\\\"javascript:\\\"]::after {\\n    // content: \\\"\\\";\\n    //}\\n\\n    pre {\\n      white-space: pre-wrap !important;\\n    }\\n    pre,\\n    blockquote {\\n      border: $border-width solid $gray-500; // Bootstrap custom code; using `$border-width` instead of 1px\\n      page-break-inside: avoid;\\n    }\\n\\n    //\\n    // Printing Tables:\\n    // http://css-discuss.incutio.com/wiki/Printing_Tables\\n    //\\n\\n    thead {\\n      display: table-header-group;\\n    }\\n\\n    tr,\\n    img {\\n      page-break-inside: avoid;\\n    }\\n\\n    p,\\n    h2,\\n    h3 {\\n      orphans: 3;\\n      widows: 3;\\n    }\\n\\n    h2,\\n    h3 {\\n      page-break-after: avoid;\\n    }\\n\\n    // Bootstrap specific changes start\\n\\n    // Specify a size and min-width to make printing closer across browsers.\\n    // We don't set margin here because it breaks `size` in Chrome. We also\\n    // don't use `!important` on `size` as it breaks in Chrome.\\n    @page {\\n      size: $print-page-size;\\n    }\\n    body {\\n      min-width: $print-body-min-width !important;\\n    }\\n    .container {\\n      min-width: $print-body-min-width !important;\\n    }\\n\\n    // Bootstrap components\\n    .navbar {\\n      display: none;\\n    }\\n    .badge {\\n      border: $border-width solid $black;\\n    }\\n\\n    .table {\\n      border-collapse: collapse !important;\\n\\n      td,\\n      th {\\n        background-color: $white !important;\\n      }\\n    }\\n\\n    .table-bordered {\\n      th,\\n      td {\\n        border: 1px solid $gray-300 !important;\\n      }\\n    }\\n\\n    .table-dark {\\n      color: inherit;\\n\\n      th,\\n      td,\\n      thead th,\\n      tbody + tbody {\\n        border-color: $table-border-color;\\n      }\\n    }\\n\\n    .table .thead-dark th {\\n      color: inherit;\\n      border-color: $table-border-color;\\n    }\\n\\n    // Bootstrap specific changes end\\n  }\\n}\\n\",","\t\t\"\\n/*!\\n\\n=========================================================\\n* {{ site.product.name }} {{ site.product.name_long }} - v{{ site.product.version }}\\n=========================================================\\n\\n* Product Page: {{ site.product.download }}\\n* Copyright {{ 'now' | date: \\\"%Y\\\" }} {{ site.author }} ({{ site.website.url }})\\n* Licensed under MIT ({{ site.product.license }})\\n\\n* Coded by www.creative-tim.com\\n\\n=========================================================\\n\\n* The above copyright notice and this permission notice shall be included in all copies or substantial portions of the Software.\\n\\n*/\\n\\n// {{ site.product.name }} components\\n\\n@import \\\"functions\\\";\\n@import \\\"mixins\\\";\\n\\n@import \\\"reboot\\\";\\n@import \\\"global\\\";\\n@import \\\"utilities\\\";\\n\\n@import \\\"accordion\\\";\\n@import \\\"alert\\\";\\n@import \\\"avatar\\\";\\n@import \\\"badge\\\";\\n@import \\\"buttons\\\";\\n@import \\\"card\\\";\\n@import \\\"carousel\\\";\\n@import \\\"close\\\";\\n@import \\\"content\\\";\\n@import \\\"custom-forms\\\";\\n@import \\\"dropdown\\\";\\n@import \\\"footer\\\";\\n@import \\\"forms\\\";\\n@import \\\"grid\\\";\\n@import \\\"icons\\\";\\n@import \\\"input-group\\\";\\n@import \\\"list-group\\\";\\n@import \\\"modal\\\";\\n@import \\\"nav\\\";\\n@import \\\"navbar\\\";\\n@import \\\"pagination\\\";\\n@import \\\"popover\\\";\\n@import \\\"progress\\\";\\n@import \\\"section\\\";\\n@import \\\"separator\\\";\\n@import \\\"type\\\";\\n\\n// Vendor\\n\\n@import \\\"vendors\\\";\\n\\n// Docs\\n\\n@import \\\"docs\\\";\\n\",","\t\t\"// Retrieve color Sass maps\\n\\n@function section-color($key: \\\"primary\\\") {\\n\\t@return map-get($section-colors, $key);\\n}\\n\\n// Lines colors\\n\\n@function shapes-primary-color($key: \\\"step-1-gradient-bg\\\") {\\n\\t@return map-get($shapes-primary-colors, $key);\\n}\\n\\n@function shapes-default-color($key: \\\"step-1-gradient-bg\\\") {\\n\\t@return map-get($shapes-default-colors, $key);\\n}\\n\\n@function lines-light-color($key: \\\"step-1-gradient-bg\\\") {\\n\\t@return map-get($shapes-light-colors, $key);\\n}\\n\\n@function shapes-dark-color($key: \\\"step-1-gradient-bg\\\") {\\n\\t@return map-get($shapes-dark-colors, $key);\\n}\",","\t\t\"@import \\\"mixins/alert\\\";\\n@import \\\"mixins/badge\\\";\\n@import \\\"mixins/background-variant\\\";\\n@import \\\"mixins/buttons\\\";\\n@import \\\"mixins/forms\\\";\\n@import \\\"mixins/icon\\\";\\n@import \\\"mixins/modals\\\";\\n@import \\\"mixins/popover\\\";\\n\",","\t\t\"@mixin alert-variant($background, $border, $color) {\\n    color: color-yiq($background);\\n    @include gradient-bg($background);\\n    border-color: $border;\\n\\n    hr {\\n        border-top-color: darken($border, 5%);\\n    }\\n\\n    .alert-link {\\n        color: darken($color, 10%);\\n    }\\n}\",","\t\t\"@mixin badge-variant($bg) {\\n\\tcolor: saturate(darken($bg, 10%), 10);\\n    background-color: transparentize(lighten($bg, 25%), .5);\\n\\n  \\t\u0026[href] {\\n\\t    @include hover-focus {\\n\\t        color: color-yiq($bg);\\n\\t        text-decoration: none;\\n\\t        background-color: darken($bg, 10%);\\n\\t    }\\n\\t}\\n}\\n\",","\t\t\"// Contextual backgrounds\\n@mixin bg-variant($parent, $color) {\\n    #{$parent} {\\n        background-color: $color !important;\\n    }\\n    a#{$parent},\\n    button#{$parent} {\\n        @include hover-focus {\\n          background-color: darken($color, 10%) !important;\\n        }\\n    }\\n}\\n\\n@mixin bg-gradient-variant($parent, $color) {\\n    #{$parent} {\\n        background: linear-gradient(35deg, $color 0, adjust-hue($color, 25%) 100%) !important;\\n    }\\n}\\n\\n@mixin bg-translucent-variant($parent, $color) {\\n    #{$parent} {\\n        background-color: darken(rgba($color, $translucent-color-opacity), 7%) !important;\\n    }\\n    a#{$parent},\\n    button#{$parent} {\\n        @include hover-focus {\\n            background-color: darken(rgba($color, $translucent-color-opacity), 12%) !important;\\n        }\\n    }\\n}\\n\",","\t\t\"@mixin button-variant($background, $border, $hover-background: darken($background, 0%), $hover-border: darken($border, 0%), $active-background: darken($background, 10%), $active-border: darken($border, 0%)) {\\n    color: color-yiq($background);\\n    @include gradient-bg($background);\\n    border-color: $border;\\n    @include box-shadow($btn-box-shadow);\\n\\n    @include hover {\\n        color: color-yiq($hover-background);\\n        @include gradient-bg($hover-background);\\n        border-color: $hover-border;\\n    }\\n\\n    \u0026:focus,\\n    \u0026.focus {\\n        // Avoid using mixin so we can pass custom focus shadow properly\\n        @if $enable-shadows {\\n            box-shadow: $btn-box-shadow, 0 0 0 $btn-focus-width rgba($border, .5);\\n        }\\n        @else {\\n            box-shadow: 0 0 0 $btn-focus-width rgba($border, .5);\\n        }\\n    }\\n    // Disabled comes first so active can properly restyle\\n    \u0026.disabled,\\n    \u0026:disabled {\\n        color: color-yiq($background);\\n        background-color: $background;\\n        border-color: $border;\\n    }\\n\\n    \u0026:not(:disabled):not(.disabled):active,\\n    \u0026:not(:disabled):not(.disabled).active,\\n    .show\u003e\u0026.dropdown-toggle {\\n        color: color-yiq($active-background);\\n        background-color: $active-background;\\n        @if $enable-gradients {\\n            background-image: none; // Remove the gradient for the pressed/active state\\n        }\\n        border-color: $active-border;\\n\\n        \u0026:focus {\\n            // Avoid using mixin so we can pass custom focus shadow properly\\n            @if $enable-shadows {\\n                box-shadow: $btn-active-box-shadow, 0 0 0 $btn-focus-width rgba($border, .5);\\n            }\\n            @else {\\n                box-shadow: 0 0 0 $btn-focus-width rgba($border, .5);\\n            }\\n        }\\n    }\\n}\\n\\n@mixin button-outline-variant($color, $color-hover: color-yiq($color), $active-background: $color, $active-border: $color) {\\n    color: $color;\\n    background-color: transparent;\\n    background-image: none;\\n    border-color: $color;\\n\\n    \u0026:hover {\\n        color: $color-hover;\\n        background-color: $active-background;\\n        border-color: $active-border;\\n    }\\n\\n    \u0026:focus,\\n    \u0026.focus {\\n        box-shadow: 0 0 0 $btn-focus-width rgba($color, .5);\\n    }\\n\\n    \u0026.disabled,\\n    \u0026:disabled {\\n        color: $color;\\n        background-color: transparent;\\n    }\\n\\n    \u0026:not(:disabled):not(.disabled):active,\\n    \u0026:not(:disabled):not(.disabled).active,\\n    .show\u003e\u0026.dropdown-toggle {\\n        color: color-yiq($active-background);\\n        background-color: $active-background;\\n        border-color: $active-border;\\n\\n        \u0026:focus {\\n            // Avoid using mixin so we can pass custom focus shadow properly\\n            @if $enable-shadows and $btn-active-box-shadow !=none {\\n                box-shadow: $btn-active-box-shadow, 0 0 0 $btn-focus-width rgba($color, .5);\\n            }\\n            @else {\\n                box-shadow: 0 0 0 $btn-focus-width rgba($color, .5);\\n            }\\n        }\\n    }\\n}\\n\\n// Button sizes\\n@mixin button-size($padding-y, $padding-x, $font-size, $line-height, $border-radius) {\\n    padding: $padding-y $padding-x;\\n    font-size: $font-size;\\n    line-height: $line-height; // Manually declare to provide an override to the browser default\\n    @if $enable-rounded {\\n        border-radius: $border-radius;\\n    }\\n    @else {\\n        border-radius: 0;\\n    }\\n}\\n\",","\t\t\"@mixin form-control-focus() {  \\n  \u0026:focus {\\n    color: $input-focus-color;\\n    background-color: $input-focus-bg;\\n    border-color: $input-focus-border-color;\\n    outline: 0;\\n    // Avoid using mixin so we can pass custom focus shadow properly\\n    @if $enable-shadows {\\n      box-shadow: $input-box-shadow, $input-focus-box-shadow;\\n    } @else {\\n      box-shadow: $input-focus-box-shadow;\\n    }\\n  }\\n}\\n\\n\\n@mixin form-validation-state($state, $color) {\\n  .#{$state}-feedback {\\n    display: none;\\n    width: 100%;\\n    margin-top: $form-feedback-margin-top;\\n    font-size: $form-feedback-font-size;\\n    color: $color;\\n  }\\n\\n  .#{$state}-tooltip {\\n    position: absolute;\\n    top: 100%;\\n    z-index: 5;\\n    display: none;\\n    max-width: 100%; // Contain to parent when possible\\n    padding: .5rem;\\n    margin-top: .1rem;\\n    font-size: .875rem;\\n    line-height: 1;\\n    color: #fff;\\n    background-color: rgba($color, .8);\\n    border-radius: .2rem;\\n  }\\n\\n  .form-control,\\n  .custom-select {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      border-color: $color;\\n\\n      \u0026:focus {\\n        border-color: $color;\\n        //box-shadow: 0 1px $input-focus-width 0 rgba($color, .75);\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n    }\\n  }\\n\\n  .form-check-input {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .form-check-label {\\n        color: $color;\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n    }\\n  }\\n\\n  .custom-control-input {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .custom-control-label {\\n        color: $color;\\n\\n        \u0026::before {\\n          background-color: lighten($color, 25%);\\n          border-color: lighten($color, 25%);\\n        }\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n\\n      \u0026:checked {\\n        ~ .custom-control-label::before {\\n          @include gradient-bg(lighten($color, 10%));\\n          border-color: lighten($color, 25%);\\n        }\\n      }\\n\\n      \u0026:focus {\\n        ~ .custom-control-label::before {\\n          box-shadow: 0 0 0 1px $body-bg, 0 0 0 $input-focus-width rgba($color, .25);\\n        }\\n      }\\n    }\\n  }\\n\\n  // custom file\\n  .custom-file-input {\\n    .was-validated \u0026:#{$state},\\n    \u0026.is-#{$state} {\\n      ~ .custom-file-label {\\n        border-color: $color;\\n\\n        \u0026::before { border-color: inherit; }\\n      }\\n\\n      ~ .#{$state}-feedback,\\n      ~ .#{$state}-tooltip {\\n        display: block;\\n      }\\n\\n      \u0026:focus {\\n        ~ .custom-file-label {\\n          box-shadow: 0 0 0 $input-focus-width rgba($color, .25);\\n        }\\n      }\\n    }\\n  }\\n}\\n\\n\",","\t\t\"@mixin icon-shape-variant($color) {\\n    color: saturate(darken($color, 10%), 10);\\n    background-color: transparentize(lighten($color, 10%), .5);\\n}\",","\t\t\"@mixin modal-variant($background) {\\n\\t.modal-title {\\n\\t\\tcolor: color-yiq($background);\\n\\t}\\n\\t.modal-header,\\n\\t.modal-footer {\\n\\t\\tborder-color: rgba(color-yiq($background), .075);\\n\\t}\\n\\t.modal-content {\\n\\t\\tbackground-color: $background;\\n\\t\\tcolor: color-yiq($background);\\n\\n\\t\\t.heading {\\n\\t\\t\\tcolor: color-yiq($background);\\n\\t\\t}\\n\\t}\\n\\n\\t.close { \\n    \\t\u0026\u003espan:not(.sr-only) {\\n    \\t\\tcolor: $white;\\n    \\t}\\n    }\\n}\",","\t\t\"@mixin popover-variant($background) {\\n\\n\\tbackground-color: $background;\\n\\n\\t.popover-header {\\n\\t\\tbackground-color: $background;\\n\\t\\tcolor: color-yiq($background);\\n\\t}\\n\\n\\t.popover-body {\\n\\t\\tcolor: color-yiq($background);\\n\\t}\\n\\t.popover-header{\\n\\t\\tborder-color: rgba(color-yiq($background), .2);\\n\\t}\\n\\t\u0026.bs-popover-top {\\n\\t\\t.arrow::after {\\n\\t\\t\\tborder-top-color: $background;\\n\\t\\t}\\n\\t}\\n\\t\u0026.bs-popover-right {\\n\\t\\t.arrow::after {\\n\\t\\t\\tborder-right-color: $background;\\n\\t\\t}\\n\\t}\\n\\t\u0026.bs-popover-bottom {\\n\\t\\t.arrow::after {\\n\\t\\t\\tborder-bottom-color: $background;\\n\\t\\t}\\n\\t}\\n\\t\u0026.bs-popover-left {\\n\\t\\t.arrow::after {\\n\\t\\t\\tborder-left-color: $background;\\n\\t\\t}\\n\\t}\\n}\",","\t\t\"iframe {\\n    border: 0;\\n}\\n\\nfigcaption,\\nfigure,\\nmain {\\n    display: block;\\n}\\n\\nmain {\\n    overflow: hidden;\\n}\\n\",","\t\t\"// Nucleo icons\\n\\n.section-nucleo-icons .icons-container {\\n    position: relative;\\n    max-width: 100%;\\n    height: 360px;\\n    margin: 0 auto;\\n    z-index: 1;\\n}\\n\\n.section-nucleo-icons {\\n\\n    --icon-size: 5rem;\\n    --icon-sm-size: 3.75rem;\\n    --gutter: 7rem;\\n\\n    .icons-container {\\n        i {\\n            position: absolute;\\n            display: inline-flex;\\n            align-items: center;\\n            justify-content: center;\\n            border-radius: 50%;\\n            background: $white;\\n            z-index: 1;\\n            transform: translate(-50%, -50%);\\n            @include box-shadow($box-shadow);\\n            transition: all .2s cubic-bezier(.25,.65,.9,.75);\\n\\n            \u0026.icon {\\n                width: var(--icon-size);\\n                height: var(--icon-size);\\n                font-size: 1.7em;\\n            }\\n\\n            \u0026.icon-sm {\\n                width: var(--icon-sm-size);\\n                height: var(--icon-sm-size);\\n                font-size: 1.5em;\\n            }\\n\\n            \u0026:nth-child(1) {\\n                font-size: 42px;\\n                color: theme-color(\\\"warning\\\");\\n                z-index: 2;\\n            }\\n        }\\n\\n        \u0026:not(.on-screen) {\\n            i {\\n                transform: translate(-50%, -50%);\\n                left: 50%;\\n                top: 50%;\\n\\n                \u0026:not(:nth-child(1)) {\\n                    opacity: 0;\\n                }\\n            }\\n        }\\n\\n        \u0026.on-screen {\\n\\n            i {\\n                opacity: 1;\\n\\n                \u0026:nth-child(1) {\\n                    left: 50%;\\n                    top: 50%;\\n                    font-size: 42px;\\n                    color: theme-color(\\\"warning\\\");\\n                }\\n\\n                \u0026:nth-child(2) {\\n                    left: calc(50% + (var(--gutter) * 1.7));\\n                    top: 50%;\\n                }\\n\\n                \u0026:nth-child(3) {\\n                    left: calc(50% + var(--gutter));\\n                    top: calc(50% + var(--gutter));\\n                }\\n\\n                \u0026:nth-child(4) {\\n                    left: calc(50% + var(--gutter));\\n                    top: calc(50% - var(--gutter));\\n                }\\n\\n                \u0026:nth-child(5) {\\n                    left: calc(50% + (var(--gutter) * 3));\\n                    top: 50%;\\n                }\\n\\n                \u0026:nth-child(6) {\\n                    left: calc(50% + (var(--gutter) * 2.7));\\n                    top: calc(50% + (var(--gutter) * 1.5));\\n                }\\n\\n                \u0026:nth-child(7) {\\n                    left: calc(50% + (var(--gutter) * 2.7));\\n                    top: calc(50% - (var(--gutter) * 1.5));\\n                }\\n\\n                \u0026:nth-child(8) {\\n                    left: calc(50% - (var(--gutter) * 1.7));\\n                    top: 50%;\\n                }\\n\\n                \u0026:nth-child(9) {\\n                    left: calc(50% - var(--gutter));\\n                    top: calc(50% + var(--gutter));\\n                }\\n\\n                \u0026:nth-child(10) {\\n                    left: calc(50% - var(--gutter));\\n                    top: calc(50% - var(--gutter));\\n                }\\n\\n                \u0026:nth-child(11) {\\n                    left: calc(50% - (var(--gutter) * 4));\\n                    top: 50%;\\n                }\\n\\n                \u0026:nth-child(12) {\\n                    left: calc(50% - (var(--gutter) * 2.7));\\n                    top: calc(50% + (var(--gutter) * 1.5));\\n                }\\n\\n                \u0026:nth-child(13) {\\n                    left: calc(50% - (var(--gutter) * 2.7));\\n                    top: calc(50% - (var(--gutter) * 1.5));\\n                }\\n            }\\n\\n        }\\n    }\\n\\n    @include media-breakpoint-down(md) {\\n      overflow: hidden;\\n    }\\n}\\n\\n\\n// Blurable sections\\n\\n.blur--hover {\\n    position: relative;\\n\\n    .blur-item {\\n        transition: 1s cubic-bezier(.19,1,.22,1);\\n        will-change: transform;\\n        filter: blur(0);\\n        opacity: 1;\\n    }\\n\\n    .blur-hidden {\\n        position: absolute;\\n        top: calc(50% + 7px);\\n        left: 50%;\\n        transform: translate(-50%, -50%);\\n        opacity: 0;\\n        transition: $transition-base;\\n        z-index: 100;\\n    }\\n    \u0026:hover {\\n        .blur-item {\\n            opacity: .8;\\n            filter: blur(10px);\\n            transform: scale(.95);\\n            z-index: 1;\\n        }\\n        .blur-hidden {\\n            opacity: 1;\\n            top: 50%;\\n        }\\n    }\\n}\\n\\n.info .info-title{\\n  margin: 25px 0 15px;\\n  font-weight: 600;\\n}\\n\",","\t\t\"@import \\\"utilities/backgrounds\\\";\\n@import \\\"utilities/floating\\\";\\n@import \\\"utilities/helper\\\";\\n@import \\\"utilities/position\\\";\\n@import \\\"utilities/sizing\\\";\\n@import \\\"utilities/spacing\\\";\\n@import \\\"utilities/shadows\\\";\\n@import \\\"utilities/text\\\";\\n@import \\\"utilities/transform\\\";\\n\",","\t\t\"@each $color, $value in $colors {\\n\\t@include bg-variant(\\\".bg-#{$color}\\\", $value);\\n}\\n\\n@each $color, $value in $theme-colors {\\n\\t@include bg-gradient-variant(\\\".bg-gradient-#{$color}\\\", $value);\\n}\\n\\n@each $color, $value in $colors { \\n\\t@include bg-gradient-variant(\\\".bg-gradient-#{$color}\\\", $value);\\n}\\n\\n// Background colors with transparency\\n@each $color, $value in $theme-colors {\\n    @include bg-translucent-variant(\\\".bg-translucent-#{$color}\\\", $value);\\n}\\n\\n\\n// Sections\\n\\n@each $color, $value in $section-colors {\\n    @include bg-variant(\\\".section-#{$color}\\\", $value);\\n}\\n\\n@each $color, $value in $theme-colors {\\n    @include bg-gradient-variant(\\\".bg-gradient-#{$color}\\\", $value);\\n}\\n\\n\\n// Shape (svg) fill colors\\n\\n@each $color, $value in $theme-colors {\\n    .fill-#{$color}  {\\n        fill: $value;\\n    }\\n\\n    .stroke-#{$color}  {\\n        stroke: $value;\\n    }\\n}\\n\\n.fill-opacity-8 {\\n\\tfill-opacity: .8;\\n}\",","\t\t\".floating {\\n\\tanimation: floating 3s ease infinite;\\n\\twill-change: transform;\\n\\n\\t\u0026:hover {\\n        animation-play-state: paused;\\n    }\\n}\\n\\n.floating-lg {\\n\\tanimation: floating-lg 3s ease infinite;\\n}\\n\\n.floating-sm {\\n\\tanimation: floating-sm 3s ease infinite;\\n}\\n\\n// Keyframes\\n\\n@keyframes floating-lg {\\n    0% {\\n        transform: translateY(0px)\\n    }\\n    50% {\\n        transform: translateY(15px)\\n    }\\n    100% {\\n        transform: translateY(0px)\\n    }\\n}\\n\\n@keyframes floating {\\n    0% {\\n        transform: translateY(0px)\\n    }\\n    50% {\\n        transform: translateY(10px)\\n    }\\n    100% {\\n        transform: translateY(0px)\\n    }\\n}\\n\\n@keyframes floating-sm {\\n    0% {\\n        transform: translateY(0px)\\n    }\\n    50% {\\n        transform: translateY(5px)\\n    }\\n    100% {\\n        transform: translateY(0px)\\n    }\\n}\",","\t\t\"// Image\\n\\n.img-center {\\n    display: block;\\n    margin-left: auto;\\n    margin-right: auto;\\n}\\n\\n// Clearfix\\n\\n.floatfix {\\n    \u0026:before,\\n    \u0026:after {\\n        content: '';\\n        display: table;\\n    }\\n    \u0026:after {\\n        clear: both;\\n    }\\n}\\n\\n// Overflows\\n\\n.overflow-visible {\\n    overflow: visible !important;\\n}\\n.overflow-hidden {\\n    overflow: hidden !important;\\n}\\n\\n// Opacity classes\\n\\n.opacity-1 {\\n    opacity: .1 !important;\\n}\\n.opacity-2 {\\n    opacity: .2 !important;\\n}\\n.opacity-3 {\\n    opacity: .3 !important;\\n}\\n.opacity-4 {\\n    opacity: .4 !important;\\n}\\n.opacity-5 {\\n    opacity: .5 !important;\\n}\\n.opacity-6 {\\n    opacity: .6 !important;\\n}\\n.opacity-7 {\\n    opacity: .7 !important;\\n}\\n.opacity-8 {\\n    opacity: .8 !important;\\n}\\n.opacity-9 {\\n    opacity: .9 !important;\\n}\\n.opacity-10 {\\n    opacity: 1 !important;\\n}\\n\",","\t\t\"@each $size, $value in $spacers {\\n\\t.top-#{$size} {\\n\\t\\ttop: $value;\\n\\t}\\n\\t.right-#{$size} {\\n\\t\\tright: $value;\\n\\t}\\n\\t.bottom-#{$size} {\\n\\t\\tbottom: $value;\\n\\t}\\n\\t.left-#{$size} {\\n\\t\\tleft: $value;\\n\\t}\\n}\\n\\n.center {\\n\\tleft: 50%;\\n\\ttransform: translateX(-50%);\\n}\",","\t\t\"// Height values in vh\\n\\n.h-100vh {\\n\\theight: 100vh !important;\\n}\\n\",","\t\t\"// Spacing columns vertically\\n\\n.row.row-grid \u003e [class*=\\\"col-\\\"] + [class*=\\\"col-\\\"] {\\n    margin-top: 3rem;\\n}\\n\\n@include media-breakpoint-up(lg) {\\n    .row.row-grid \u003e [class*=\\\"col-lg-\\\"] + [class*=\\\"col-lg-\\\"] {\\n        margin-top: 0;\\n    }\\n}\\n@include media-breakpoint-up(md) {\\n    .row.row-grid \u003e [class*=\\\"col-md-\\\"] + [class*=\\\"col-md-\\\"] {\\n        margin-top: 0;\\n    }\\n}\\n@include media-breakpoint-up(sm) {\\n    .row.row-grid \u003e [class*=\\\"col-sm-\\\"] + [class*=\\\"col-sm-\\\"] {\\n        margin-top: 0;\\n    }\\n}\\n\\n.row-grid + .row-grid {\\n    margin-top: 3rem;\\n}\\n\\n// Negative margins and paddings\\n\\n@media(min-width: 992px) {\\n    [class*=\\\"mt--\\\"],\\n    [class*=\\\"mr--\\\"],\\n    [class*=\\\"mb--\\\"],\\n    [class*=\\\"ml--\\\"] {\\n        position: relative;\\n        z-index: 5;\\n    }\\n\\n\\n    // Large negative margins in pixels\\n\\n    .mt--100 {\\n        margin-top: -100px !important;\\n    }\\n    .mr--100 {\\n        margin-right: -100px !important;\\n    }\\n    .mb--100 {\\n        margin-bottom: -100px !important;\\n    }\\n    .ml--100 {\\n        margin-left: -100px !important;\\n    }\\n    .mt--150 {\\n        margin-top: -150px !important;\\n    }\\n    .mb--150 {\\n        margin-bottom: -150px !important;\\n    }\\n    .mt--200 {\\n        margin-top: -200px !important;\\n    }\\n    .mb--200 {\\n        margin-bottom: -200px !important;\\n    }\\n    .mt--300 {\\n        margin-top: -300px !important;\\n    }\\n    .mb--300 {\\n        margin-bottom: -300px !important;\\n    }\\n\\n\\n    // Large margins in pixels\\n\\n    .pt-100 {\\n        padding-top: 100px !important;\\n    }\\n    .pb-100 {\\n        padding-bottom: 100px !important;\\n    }\\n    .pt-150 {\\n        padding-top: 150px !important;\\n    }\\n    .pb-150 {\\n        padding-bottom: 150px !important;\\n    }\\n    .pt-200 {\\n        padding-top: 200px !important;\\n    }\\n    .pb-200 {\\n        padding-bottom: 200px !important;\\n    }\\n    .pt-250 {\\n        padding-top: 250px !important;\\n    }\\n    .pb-250 {\\n        padding-bottom: 250px !important;\\n    }\\n    .pt-300 {\\n        padding-top: 300px!important;\\n    }\\n    .pb-300 {\\n        padding-bottom: 300px!important;\\n    }\\n}\\n\",","\t\t\"[class*=\\\"shadow\\\"] {\\n\\t@if $enable-transitions {\\n        transition: $transition-base;\\n    }\\n}\\n\\n.shadow-sm--hover:hover { box-shadow: $box-shadow-sm !important; }\\n.shadow--hover:hover { box-shadow: $box-shadow !important; }\\n.shadow-lg--hover:hover { box-shadow: $box-shadow-lg !important; }\\n.shadow-none--hover:hover { box-shadow: none !important; }\\n\",","\t\t\"// Weight and italics\\n\\n.font-weight-300 { font-weight: 300 !important; }\\n.font-weight-400 { font-weight: 400 !important; }\\n.font-weight-500 { font-weight: 500 !important; }\\n.font-weight-600 { font-weight: 600 !important; } \\n.font-weight-700 { font-weight: 700 !important; }\\n.font-weight-800 { font-weight: 800 !important; }\\n.font-weight-900 { font-weight: 900 !important; }\\n\\n\\n// Text decorations\\n\\n.text-underline { text-decoration: underline; }\\n.text-through { text-decoration: line-through; }\\n\\n\\n// Line heights\\n\\n.lh-100 { line-height: 1; }\\n.lh-110 { line-height: 1.1; }\\n.lh-120 { line-height: 1.2; }\\n.lh-130 { line-height: 1.3; }\\n.lh-140 { line-height: 1.4; }\\n.lh-150 { line-height: 1.5; }\\n.lh-160 { line-height: 1.6; }\\n.lh-170 { line-height: 1.7; }\\n.lh-180 { line-height: 1.8; }\\n\\n\\n// Letter spacings\\n\\n.ls-1 { letter-spacing: .0625rem; }\\n.ls-15 { letter-spacing: .09375rem; }\\n.ls-2 { letter-spacing: 0.125rem; }\\n\\n// Color variations\\n\\n@each $color, $value in $colors {\\n\\t@include text-emphasis-variant(\\\".text-#{$color}\\\", $value);\\n}\",","\t\t\"@include media-breakpoint-up(lg) {\\n\\t.transform-perspective-right {\\n\\t\\ttransform: scale(1) perspective(1040px) rotateY(-11deg) rotateX(2deg) rotate(2deg);\\n\\t}\\n\\t.transform-perspective-left{\\n\\t\\ttransform: scale(1) perspective(2000px) rotateY(11deg) rotateX(2deg) rotate(-2deg)\\n\\t}\\n}\\n\",","\t\t\"\",","\t\t\".alert {\\n    padding: $alert-padding-y $alert-padding-x;\\n    border: 0;\\n    font-size: $font-size-sm;\\n    @include border-radius($alert-border-radius);\\n\\n    .alert-inner--icon {\\n        font-size: 1.25rem;\\n        margin-right: 1.25rem;\\n        display: inline-block; \\n        vertical-align: middle;\\n\\n        i.ni {\\n            position: relative;\\n            top: 1px;\\n        }\\n    }\\n    .alert-inner--text {\\n        display: inline-block;\\n        vertical-align: middle;\\n    }\\n}\\n\\n.alert:not(.alert-secondary) {\\n    color: $white;\\n}\\n\\n[class*=\\\"alert-\\\"] {\\n    .alert-link {\\n        color: $white; \\n        border-bottom: 1px dotted rgba($white, .5);\\n    }\\n}\\n\\n.alert-heading {\\n    font-weight: $font-weight-bold;\\n    font-size: $h4-font-size;\\n    margin-top: .15rem; \\n} \\n\\n.alert-dismissible {\\n    .close { \\n        top: 50%;\\n        right: $alert-padding-x;\\n        padding: 0;\\n        transform: translateY(-50%);\\n        color: rgba($white, .6);\\n        opacity: 1;\\n\\n        \u0026:hover,\\n        \u0026:focus {\\n            color: rgba($white, .9);\\n            opacity: 1 !important;\\n        }\\n\\n        @include media-breakpoint-down(xs) {\\n            top: 1rem;\\n            right: .5rem;\\n        }\\n\\n        \u0026\u003espan:not(.sr-only) {\\n            font-size: 1.5rem;\\n            background-color: transparent;\\n            color: rgba($white, .6);\\n        }\\n\\n        \u0026:hover,\\n        \u0026:focus {\\n            \u0026\u003espan:not(.sr-only) {\\n                background-color: transparent;\\n                color: rgba($white, .9);\\n            }\\n        }\\n    }\\n}\\n\",","\t\t\".avatar {\\n\\tcolor: $white;\\n\\tbackground-color: $gray-500;\\n\\tdisplay: inline-flex;\\n\\talign-items: center;\\n\\tjustify-content: center;\\n\\tfont-size: 1rem;\\n\\tborder-radius: 50%;\\n\\theight: 48px;\\n\\twidth: 48px;\\n}\\n\\n.avatar img {\\n\\twidth: 100%;\\n\\tborder-radius: 50%;\\n}\\n\\n.avatar + .avatar-content {\\n\\tdisplay: inline-block;\\n\\tmargin-left: .75rem;\\n}\\n.avatar-lg {\\n\\twidth: 58px;\\n\\theight: 58px;\\n\\tfont-size: $font-size-sm;\\n}\\n\\n.avatar-sm {\\n\\twidth: 38px;\\n\\theight: 38px;\\n\\tfont-size: $font-size-sm;\\n}\\n\\n// Overlapped avatars\\n\\n.avatar-group {\\n\\t.avatar {\\n\\t\\tposition: relative;\\n\\t\\tz-index: 2;\\n\\t\\tborder: 2px solid $card-bg;\\n\\n\\t\\t\u0026:hover {\\n\\t\\t\\tz-index: 3;\\n\\t\\t}\\n\\t}\\n\\n\\t.avatar + .avatar {\\n\\t\\tmargin-left: -1rem;\\n\\n\\t}\\n}\\n\",","\t\t\".badge {\\n    text-transform: $badge-text-transfom;\\n\\n    a {\\n        color: #FFF;\\n    }\\n}\\n\\n// Variations\\n.badge-pill {\\n    padding-right: $badge-pill-padding-x;\\n    padding-left: $badge-pill-padding-x;\\n}\\n\\n.badge-circle {\\n    text-align: center;\\n    display: inline-flex;\\n    align-items: center;\\n    justify-content: center;\\n    border-radius: 50%;\\n    width: 2rem;\\n    height: 2rem;\\n    font-size: .875rem;\\n}\\n\\n// Multiple inline badges\\n.badge-inline {\\n    margin-right: .625rem;\\n}\\n\\n.badge-inline + span {\\n    top: 2px;\\n    position: relative;\\n}\\n\\n.badge-inline + span \u003e a {\\n    text-decoration: underline;\\n} \\n\\n// Sizes\\n.badge-md {\\n    padding: .65em 1em;\\n}\\n\\n.badge-lg {\\n    padding: .85em 1.375em;\\n}\\n\\n\\n// Color variations\\n\\n.badge-secondary {\\n    color: $gray-800;\\n}\\n\\n// Link badges\\n\\n.btn {\\n    .badge {\\n        \u0026:not(:first-child) {\\n            margin-left: .5rem;\\n        }\\n        \u0026:not(:last-child) {\\n            margin-right: .5rem;\\n        }\\n    }\\n}\",","\t\t\"// General\\n\\n.btn {\\n  position: relative;\\n  text-transform: $btn-text-transform;\\n  will-change: transform;\\n  letter-spacing: $btn-letter-spacing;\\n  font-size: $input-btn-font-size;\\n\\n  \u0026:hover {\\n    @include box-shadow($btn-hover-box-shadow);\\n    transform: translateY(-1px);\\n  }\\n\\n  \u0026:not(:last-child) {\\n    margin-right: .5rem;\\n  }\\n\\n}\\n\\n.btn-group,\\n.input-group {\\n  .btn {\\n    margin-right: 0;\\n    transform: translateY(0);\\n  }\\n}\\n\\n// Sizes\\n\\n.btn-sm {\\n  font-size: $input-btn-font-size-sm;\\n\\n  \u0026.btn-icon-only {\\n    width: 35px;\\n    height: 35px;\\n  }\\n\\n  .btn-inner--icon {\\n    font-size: 0.5rem;;\\n  }\\n}\\n\\n.btn-lg {\\n  \u0026.btn-icon-only {\\n    width: 52px;\\n    height: 52px;\\n  }\\n\\n  .btn-inner--icon {\\n    font-size: 1.2rem;\\n    position: relative;\\n    top: 2px;\\n  }\\n}\\n\\n// Fixes\\n\\n[class*=\\\"btn-outline-\\\"] {\\n  border-width: 1px;\\n}\\n.btn-outline-secondary {\\n  color: darken(theme-color(\\\"secondary\\\"), 50%);\\n}\\n\\n.btn-inner--icon {\\n  i:not(.fa) {\\n    position: relative;\\n  }\\n}\\n\\n.btn-link {\\n  font-weight: $btn-font-weight;\\n  box-shadow: none;\\n\\n  \u0026:hover {\\n    box-shadow: none;\\n    transform: none;\\n  }\\n\\n  \u0026.text-secondary {\\n    color: darken(theme-color(\\\"secondary\\\"), 50%) !important;\\n  }\\n}\\n\\n.btn-neutral {\\n  color: theme-color(\\\"primary\\\");\\n}\\n\\n// Icons\\n\\n.btn svg:not(:first-child),\\n.btn i:not(:first-child) {\\n  margin-left: 0.5rem;\\n}\\n\\n.btn svg:not(:last-child),\\n.btn i:not(:last-child) {\\n  margin-right: 0.5rem;\\n}\\n\\n// Icon labels\\n\\n.btn-icon-label {\\n  position: relative;\\n\\n    .btn-inner--icon {\\n      position: absolute;\\n      height: 100%;\\n      line-height: 1;\\n      border-radius: 0;\\n      text-align: center;\\n      margin: 0;\\n      width: 3em;\\n      background-color: rgba(0, 0, 0, .1);\\n    }\\n    .btn-inner--icon:not(:first-child) {\\n        right: 0;\\n        top: 0;\\n        border-top-right-radius: inherit;\\n        border-bottom-right-radius: inherit;\\n    }\\n    .btn-inner--icon:not(:last-child) {\\n        left: 0;\\n        top: 0;\\n        border-top-left-radius: inherit;\\n        border-bottom-left-radius: inherit;\\n    }\\n    .btn-inner--icon svg {\\n        position: relative;\\n        top: 50%;\\n        transform: translateY(-50%);\\n    }\\n\\n    .btn-inner--text:not(:first-child) {\\n        padding-left: 3em;\\n    }\\n    .btn-inner--text:not(:last-child) {\\n        padding-right: 3em;\\n    }\\n}\\n\\n\\n// Icons\\n\\n.btn-icon {\\n    .btn-inner--icon {\\n        img {\\n            width: 20px;\\n        }\\n    }\\n    .btn-inner--text:not(:first-child) {\\n        margin-left: .75em;\\n    }\\n    .btn-inner--text:not(:last-child) {\\n        margin-right: .75em;\\n    }\\n}\\n\\n.btn-icon-only {\\n    width: 2.375rem;\\n    height: 2.375rem;\\n    padding: 0;\\n}\\na.btn-icon-only {\\n    line-height: 2.5;\\n}\\n.btn-icon-only.btn-sm {\\n    width: 2rem;\\n    height: 2rem;\\n}\\n\\n\\n// Brand buttons\\n\\n@each $color,\\n$value in $brand-colors {\\n    .btn-#{$color} {\\n        @include button-variant($value, $value);\\n    }\\n}\\n\",","\t\t\"\\n.card {\\n  position: relative;\\n\\n  \u0026.card-plain {\\n    background: transparent;\\n    box-shadow: none;\\n    border: none;\\n  }\\n}\\n\\n.profile-page {\\n    .card-profile {\\n        margin-top: -150px;\\n\\n        .card-profile-image {\\n            position: relative;\\n            //min-height: 130px;\\n\\n            img {\\n                max-width: 180px;\\n                border-radius: $border-radius;\\n                @extend .shadow;\\n                transform: translate(-50%,-30%);\\n                position: absolute;\\n                left: 50%;\\n                transition: $transition-base;\\n\\n                \u0026:hover {\\n                    transform: translate(-50%, -33%);\\n                }\\n            }\\n        }\\n\\n        .card-profile-stats {\\n            padding: 1rem 0;\\n\\n            \u003e div {\\n                text-align: center;\\n                margin-right: 1rem;\\n                padding: .875rem;\\n\\n                \u0026:last-child {\\n                    margin-right: 0;\\n                }\\n\\n                .heading {\\n                    font-size: 1.1rem;\\n                    font-weight: bold;\\n                    display: block;\\n                }\\n                .description {\\n                    font-size: .875rem;\\n                    color: $gray-500;\\n                }\\n            }\\n        }\\n\\n        .card-profile-actions {\\n            padding: .875rem;\\n        }\\n\\n        @include media-breakpoint-down(xs) {\\n            .card-profile-actions {\\n                margin-top: 110px;\\n            }\\n        }\\n\\n        @include media-breakpoint-between(sm, md) {\\n            .card-profile-stats {\\n                margin-top: 30px;\\n            }\\n        }\\n    }\\n}\\n\\n// Card with blockquotes\\n\\n.card {\\n  .card-blockquote {\\n    padding: 2rem;\\n    position: relative;\\n\\n    .svg-bg {\\n        display: block;\\n        width: 100%;\\n        height: 95px;\\n        position: absolute;\\n        top: -94px;\\n        left: 0;\\n    }\\n  }\\n}\\n\\n// Animated cards\\n\\n.card-lift--hover {\\n    \u0026:hover {\\n        transform: translateY(-20px);\\n        @include transition($transition-base);\\n    }\\n}\\n\",","\t\t\"// Bootstrap carousel\\n\",","\t\t\".close { \\n    @if $enable-transitions {\\n        transition: $transition-base;\\n    } \\n    \u0026\u003espan:not(.sr-only) {\\n        background-color: $close-bg;\\n        color: $close-color;\\n        line-height: 17px;\\n        height: 1.25rem;\\n        width: 1.25rem; \\n        border-radius: 50%;\\n        font-size: 1.25rem;\\n        display: block;\\n        @if $enable-transitions {\\n            transition: $transition-base;\\n        } \\n    } \\n\\n    \u0026:hover,\\n    \u0026:focus {\\n        background-color: $close-hover-bg;\\n        color: $close-hover-color;\\n        outline: none;\\n        \\n        span:not(.sr-only) {\\n            background-color: $close-hover-bg;\\n        }\\n    }\\n}\\n\",","\t\t\"\",","\t\t\".custom-control-label {\\n    // Background-color and (when enabled) gradient\\n    \u0026::before {\\n        border: $custom-control-indicator-border-width solid $custom-control-indicator-border-color;\\n        @if $enable-transitions {\\n            transition: all .3s ease;;\\n        }\\n    }\\n\\n    span {\\n        position: relative;\\n        top: 2px;\\n    }\\n}\\n\\n.custom-control {\\n  padding-left: 1.7rem !important;\\n}\\n\\n.custom-control-label {\\n  margin-bottom: 0;\\n\\n  \u0026:before,\\n  \u0026:after {\\n    left: -1.75rem;\\n  }\\n}\\n\\n.custom-control-input {\\n    \u0026:active~.custom-control-label::before {\\n        border-color: $custom-control-indicator-active-border-color;\\n    }\\n}\\n\\n// Alternative custom control\\n.custom-control-alternative {\\n    .custom-control-label {\\n        // Background-color and (when enabled) gradient\\n        \u0026::before {\\n            border: 0;\\n            box-shadow: $input-alternative-box-shadow;\\n        }\\n    }\\n\\n    .custom-control-input {\\n        \u0026:checked {\\n            ~ .custom-control-label {\\n                \u0026::before {\\n                    box-shadow: $input-focus-alternative-box-shadow;\\n                }\\n            }\\n        }\\n\\n        \u0026:active~.custom-control-label::before,\\n        \u0026:focus~.custom-control-label::before {\\n            box-shadow: $input-alternative-box-shadow;\\n        }\\n    }\\n}\\n\\n\\n// Checkboxes\\n.custom-checkbox {\\n    .custom-control-input~.custom-control-label {\\n        cursor: pointer;\\n        font-size: $font-size-sm;\\n    }\\n\\n    .custom-control-input {\\n        \u0026:checked {\\n            ~ .custom-control-label {\\n                \u0026::before {\\n                    border-color: $custom-control-indicator-checked-border-color;\\n                }\\n                \u0026::after {\\n                    background-image: $custom-checkbox-indicator-icon-checked;\\n                }\\n            }\\n        }\\n\\n        \u0026:disabled {\\n            ~ .custom-control-label {\\n                \u0026::before {\\n                    border-color: $custom-control-indicator-disabled-bg;\\n                }\\n            }\\n\\n            \u0026:checked {\\n                \u0026::before {\\n                    border-color: $custom-control-indicator-checked-disabled-bg;\\n                }\\n            }\\n        }\\n    }\\n}\\n\\n// Radios\\n.custom-radio {\\n    .custom-control-input~.custom-control-label {\\n        cursor: pointer;\\n        font-size: $font-size-sm;\\n    }\\n\\n    .custom-control-input {\\n        \u0026:checked {\\n            ~ .custom-control-label {\\n                \u0026::before {\\n                    border-color: $custom-control-indicator-checked-border-color;\\n                }\\n                \u0026::after {\\n                    background-image: $custom-radio-indicator-icon-checked;\\n                }\\n            }\\n        }\\n\\n        \u0026:disabled {\\n            ~ .custom-control-label {\\n                \u0026::before {\\n                    border-color: $custom-control-indicator-disabled-bg;\\n                }\\n            }\\n\\n            \u0026:checked {\\n                \u0026::before {\\n                    border-color: $custom-control-indicator-checked-disabled-bg;\\n                }\\n            }\\n        }\\n    }\\n\\n}\\n\\n// Toggles\\n.custom-toggle {\\n    position: relative;\\n    display: inline-block;\\n    width: 50px;\\n    height: 1.5rem;\\n\\n    input {\\n        display: none;\\n\\n        \u0026:checked {\\n             + .custom-toggle-slider {\\n                border: $custom-control-indicator-border-width solid $custom-control-indicator-checked-border-color;\\n\\n                \u0026:before {\\n                    background: $custom-toggle-checked-bg;\\n                    transform: translateX(1.625rem);\\n                }\\n            }\\n        }\\n\\n        \u0026:disabled {\\n            + .custom-toggle-slider {\\n                border: $custom-control-indicator-border-width solid $custom-control-indicator-disabled-bg;\\n            }\\n\\n            \u0026:checked {\\n                + .custom-toggle-slider {\\n                    border: $custom-control-indicator-border-width solid $custom-control-indicator-disabled-bg;\\n\\n                    \u0026:before {\\n                        background-color: lighten($custom-control-indicator-checked-bg, 10%);\\n                    }\\n                }\\n            }\\n        }\\n    }\\n}\\n\\n.custom-toggle-slider {\\n    position: absolute;\\n    cursor: pointer;\\n    top: 0;\\n    left: 0;\\n    right: 0;\\n    bottom: 0;\\n    border: $custom-control-indicator-border-width solid $input-border-color;\\n    border-radius: 34px !important;\\n    background-color: transparent;\\n\\n\\n    \u0026:before {\\n        position: absolute;\\n        content: \\\"\\\";\\n        height: 18px;\\n        width: 18px;\\n        left: 2px;\\n        bottom: 2px;\\n        border-radius: 50% !important;\\n        background-color: $custom-toggle-slider-bg;\\n        transition: $input-transition;\\n    }\\n}\\n\",","\t\t\".dropdown,\\n.dropup,\\n.dropright,\\n.dropleft {\\n  display: inline-block;\\n}\\n\\n.dropdown-menu {\\n  min-width: 12rem;\\n\\n  .dropdown-item {\\n    padding: 1rem;\\n    font-size: $font-size-sm;\\n    \u003e i,\\n    \u003e svg {\\n      margin-right: 1rem;\\n      font-size: 1rem;\\n      vertical-align: -17%;\\n    }\\n  }\\n}\\n\\n.dropdown-header {\\n  padding-left: 1rem;\\n  padding-right: 1rem;\\n  color: $gray-100;\\n  font-size: .625rem;\\n  text-transform: uppercase;\\n  font-weight: 700;\\n}\\n\\n\\n// Dropdown elements\\n\\n.dropdown-menu {\\n  a.media {\\n    \u003e div {\\n      \u0026:first-child {\\n        line-height: 1;\\n      }\\n      }\\n\\n    p {\\n      color: $gray-600;\\n    }\\n    \u0026:hover {\\n      .heading, p {\\n        color: theme-color(\\\"default\\\") !important;\\n      }\\n    }\\n  }\\n}\\n\\n// Dropown: Sizes\\n\\n.dropdown-menu-sm {\\n    min-width: 100px;\\n    border: $border-radius-lg;\\n}\\n\\n.dropdown-menu-lg {\\n    min-width: 260px;\\n    border-radius: $border-radius-lg;\\n}\\n\\n.dropdown-menu-xl {\\n    min-width: 450px;\\n    border-radius: $border-radius-lg;\\n}\\n\",","\t\t\".footer {\\n    background: $secondary;\\n    padding: 1.5rem 0;\\n\\n    .col-footer {\\n        .heading {\\n            color: $footer-heading-color;\\n            letter-spacing: 0;\\n            font-size: $footer-heading-font-size;\\n            text-transform: uppercase;\\n            font-weight: $font-weight-bold;\\n            margin-bottom: 1rem;\\n        }\\n    }\\n\\n    .nav .nav-item .nav-link,\\n    .footer-link {\\n        color: $footer-link-color !important;\\n\\n        \u0026:hover {\\n            color: $footer-link-hover-color !important;\\n        }\\n    }\\n\\n    .list-unstyled li a {\\n        display: inline-block;\\n        padding: .125rem 0;\\n        color: $footer-link-color;\\n        font-size: $footer-link-font-size;\\n\\n        \u0026:hover {\\n            color: $footer-link-hover-color;\\n        }\\n    }\\n\\n    .copyright {\\n        font-size: $font-size-sm;\\n    }\\n\\n    .dropdown {\\n      .btn:not(:disabled):not(.disabled):active:focus,\\n      .btn:not(:disabled):not(.disabled).active:focus {\\n        box-shadow: none;\\n      }\\n    }\\n}\\n\\n.footer-dark {\\n    .col-footer .heading {\\n        color: $white;\\n    }\\n}\\n\\n.footer.has-cards {\\n    overflow: hidden;\\n    padding-top: 500px;\\n    margin-top: -420px;\\n    position: relative;\\n    background: transparent;\\n    pointer-events: none;\\n\\n    \u0026:before {\\n        content: \\\"\\\";\\n        position: absolute;\\n        left: 0;\\n        right: 0;\\n        top: 600px;\\n        height: 2000px;\\n        background: theme-color(\\\"secondary\\\");\\n        transform: skew(0,-8deg);\\n    }\\n\\n    .container {\\n        pointer-events: auto;\\n        position: relative;\\n    }\\n}\\n\\n.nav-footer {\\n    .nav-link {\\n        font-size: $font-size-sm;\\n    }\\n\\n    .nav-item:last-child {\\n        .nav-link {\\n            padding-right: 0;\\n        }\\n    }\\n}\\n\",","\t\t\"/* Form controls */\\n\\nlabel {\\n    font-size: $font-size-sm;\\n}\\n\\n.form-control {\\n    font-size: $input-btn-font-size;\\n    transition: $transition-base;\\n\\n    \u0026:focus {\\n        \u0026::placeholder {\\n            color: $input-focus-placeholder-color;\\n        }\\n    }\\n\\n    \u0026.is-valid,\\n    \u0026.is-invalid {\\n      background-image: none;\\n    }\\n}\\n\\n\\n/* Textareas */\\n\\ntextarea[resize=\\\"none\\\"] {\\n    resize: none!important;\\n}\\n\\ntextarea[resize=\\\"both\\\"] {\\n    resize: both!important;\\n}\\n\\ntextarea[resize=\\\"vertical\\\"] {\\n    resize: vertical!important;\\n}\\n\\ntextarea[resize=\\\"horizontal\\\"] {\\n    resize: horizontal!important;\\n}\\n\\n\\n/* Alternative styles */\\n\\n.form-control-muted {\\n    background-color: $input-muted-bg;\\n    border-color: $input-muted-bg;\\n    box-shadow: none;\\n\\n    \u0026:focus {\\n      background-color: $input-muted-bg;\\n    }\\n}\\n\\n.form-control-alternative {\\n  box-shadow: $input-alternative-box-shadow;\\n  border: 0;\\n  transition: box-shadow .15s ease;\\n\\n  \u0026:focus {\\n    box-shadow: $input-focus-alternative-box-shadow;\\n  }\\n}\\n\\n// Sizes\\n\\n.form-control-lg {\\n  font-size: $font-size-base;\\n}\\n\\n// Validation\\n\\n.has-success,\\n.has-danger {\\n  position: relative;\\n\\n  \u0026:after {\\n    width: 19px;\\n    height: 19px;\\n    line-height: 19px;\\n    text-align: center;\\n    font-family: 'NucleoIcons';\\n    display: inline-block;\\n    position: absolute;\\n    right: 15px;\\n    top: 2px;\\n    transform: translateY(50%);\\n    border-radius: 50%;\\n    font-size: 9px;\\n    opacity: 1;\\n  }\\n\\n  .form-control-alternative {\\n    \u0026.is-valid,\\n    \u0026.is-invalid {\\n      \u0026:focus {\\n        box-shadow: $input-focus-alternative-box-shadow !important;\\n      }\\n    }\\n  }\\n}\\n\\n.has-success {\\n  \u0026:after {\\n    content: \\\"\\\\ea26\\\";\\n    color: daken($form-feedback-valid-color, 18%);\\n    background-color: $form-feedback-valid-bg;\\n  }\\n  .form-control {\\n    background-color: $input-focus-bg;\\n\\n    \u0026:focus {\\n      border-color: $input-focus-border-color;\\n    }\\n\\n    // Placeholder\\n    \u0026::placeholder {\\n      color: $form-feedback-valid-color;\\n    }\\n  }\\n}\\n\\n.has-danger {\\n    \u0026:after {\\n      content: \\\"\\\\ea53\\\";\\n      color: daken($form-feedback-invalid-color, 18%);\\n      background-color: $form-feedback-invalid-bg;\\n    }\\n    .form-control {\\n      background-color: $input-focus-bg;\\n\\n      \u0026:focus {\\n        border-color: $input-focus-border-color;\\n      }\\n\\n      // Placeholder\\n      \u0026::placeholder {\\n        color: $form-feedback-invalid-color;\\n      }\\n    }\\n}\\n\",","\t\t\"@include media-breakpoint-up(lg) {\\n\\t.container-lg {\\n\\t\\tmax-width: 1160px;\\n\\t}\\n}\",","\t\t\".icon {\\n\\twidth: $icon-size;\\n\\theight: $icon-size;\\n\\n\\ti, svg {\\n\\t\\tfont-size: $icon-size - .75;\\n\\t}\\n}\\n\\n.icon + .icon-text {\\n\\tpadding-left: 1rem;\\n\\twidth: calc(100% - #{$icon-size} - 1);\\n}\\n\\n.icon-xl {\\n\\twidth: $icon-size-xl;\\n\\theight: $icon-size-xl;\\n\\n\\ti, svg {\\n\\t\\tfont-size: $icon-size-xl - .75;\\n\\t}\\n}\\n\\n.icon-xl + .icon-text {\\n\\twidth: calc(100% - $icon-size-xl - 1);\\n}\\n\\n.icon-lg {\\n\\twidth: $icon-size-lg;\\n\\theight: $icon-size-lg;\\n\\n\\ti, svg {\\n\\t\\tfont-size: $icon-size-lg - .75;\\n\\t}\\n}\\n\\n.icon-lg + .icon-text {\\n\\twidth: calc(100% - $icon-size-lg - 1);\\n}\\n\\n.icon-sm {\\n\\twidth: $icon-size-sm;\\n\\theight: $icon-size-sm;\\n\\n\\ti, svg {\\n\\t\\tfont-size: $icon-size-sm - .75;\\n\\t}\\n}\\n\\n.icon-sm + .icon-text {\\n\\twidth: calc(100% - $icon-size-sm - 1);\\n}\\n\\n// Extra Small icon\\n\\n.icon-xs {\\n\\twidth: $icon-size-xs;\\n\\theight: $icon-size-xs;\\n\\n\\ti, svg {\\n\\t\\tfont-size: $icon-size-xs - .75 !important;\\n\\t}\\n\\n    + .icon-text {\\n    \\twidth: calc(100% - $icon-size-xs - 1);\\n    }\\n}\\n\\n\\n// Icons included in shapes\\n.icon-shape {\\n\\tpadding: 12px;\\n\\ttext-align: center;\\n\\tdisplay: inline-flex;\\n\\talign-items: center;\\n\\tjustify-content: center;\\n\\tborder-radius: 50%;\\n\\n\\n\\ti, svg {\\n\\t\\tfont-size: 1.25rem;\\n\\t}\\n\\n\\t\u0026.icon-lg {\\n\\t\\ti, svg {\\n\\t\\t\\tfont-size: 1.625rem;\\n\\t\\t}\\n\\t}\\n\\n\\t\u0026.icon-sm {\\n\\t\\ti, svg {\\n\\t\\t\\tfont-size: .875rem;\\n\\t\\t}\\n\\t}\\n\\n\\tsvg {\\n\\t\\twidth: 30px;\\n\\t\\theight: 30px;\\n\\t}\\n\\n}\\n\\n@each $color, $value in $theme-colors {\\n\\t.icon-shape-#{$color} {\\n\\t\\t@include icon-shape-variant(theme-color($color));\\n\\t}\\n}\\n\",","\t\t\".input-group {\\n\\tbox-shadow: $input-box-shadow;\\n\\tborder-radius: $input-border-radius;\\n\\ttransition: $transition-base;\\n\\n\\t.form-control {\\n\\t\\tbox-shadow: none;\\n\\n\\t\\t\u0026:not(:first-child) {\\n\\t\\t    border-left: 0;\\n\\t\\t    padding-left: 0;\\n\\t\\t}\\n\\t\\t\u0026:not(:last-child) {\\n\\t\\t\\tborder-right: 0;\\n\\t\\t\\tpadding-right: 0;\\n\\t\\t}\\n\\t\\t\u0026:focus {\\n\\t\\t\\tbox-shadow: none;\\n\\t\\t}\\n\\t}\\n\\n  .input-group-prepend {\\n    margin-right: 0;\\n\\n    .input-group-text {\\n      border-right: none;\\n    }\\n  }\\n}\\n\\n.input-group-text {\\n  transition: $transition-base;\\n}\\n\\n.input-group-alternative {\\n    box-shadow: $input-alternative-box-shadow;\\n    border: 0;\\n    transition: box-shadow .15s ease;\\n\\n    .form-control,\\n    .input-group-text {\\n        border: 0;\\n        box-shadow: none;\\n    }\\n}\\n\\n.focused {\\n\\t.input-group-alternative {\\n    box-shadow: $input-focus-alternative-box-shadow !important;\\n  }\\n}\\n\\n\\n// .focus class is applied dinamycally from theme.js\\n\\n.focused {\\n\\t.input-group {\\n\\t\\tbox-shadow: $input-focus-box-shadow;\\n\\t}\\n\\n\\t.input-group-text {\\n    color: $input-group-addon-focus-color;\\n    background-color: $input-group-addon-focus-bg;\\n    border-color: $primary;\\n\\t}\\n\\n\\t.form-control {\\n\\t\\tborder-color: $primary;\\n\\t}\\n}\\n\",","\t\t\"// Space list items\\n\\n.list-group-space {\\n    .list-group-item {\\n        margin-bottom: 1.5rem;\\n        @include border-radius($list-group-border-radius);\\n    }\\n}\\n\\n\\n// List group components\\n\\n.list-group-img {\\n    width: 3rem;\\n    height: 3rem;\\n    border-radius: 50%;\\n    vertical-align: top;\\n    margin: -.1rem 1.2rem 0 -.2rem;\\n}\\n.list-group-content {\\n    -webkit-box-flex: 1;\\n    -ms-flex: 1;\\n    flex: 1;\\n    min-width: 0;\\n}\\n.list-group-content \u003e p {\\n    color: $gray-500;\\n    line-height: 1.5;\\n    margin: .2rem 0 0;\\n}\\n.list-group-heading {\\n    font-size: $font-size-base;\\n    color: $gray-800;\\n}\\n.list-group-heading \u003e small {\\n    float: right;\\n    color: $gray-500;\\n    font-weight: 500;\\n}\\n\",","\t\t\".modal-content {\\n    border: 0;\\n    @if $enable-rounded {\\n        border-radius: $modal-content-border-radius;\\n    } @else {\\n        border-radius: 0;\\n    }  \\n}\\n\\n\\n.modal-fluid {\\n    .modal-dialog {\\n        margin-top: 0;\\n        margin-bottom: 0;\\n    }\\n    .modal-content {\\n        border-radius: 0;\\n    }\\n}\\n\\n@each $color, $value in $theme-colors {\\n    .modal-#{$color} {\\n        @include modal-variant($value);\\n    }\\n}\\n\\n\",","\t\t\".nav-link {\\n    color: $nav-link-color;\\n\\n    \u0026:hover,\\n    \u0026.active {\\n      color: theme-color(\\\"primary\\\");\\n    }\\n\\n    i:not(.fa) {\\n        position: relative;\\n        top: 2px;\\n    }\\n}\\n\\n// Pills\\n\\n.nav-pills {\\n    .nav-item:not(:last-child) {\\n        padding-right: $nav-pills-space-x;\\n    }\\n\\n    .nav-link {\\n    \\tpadding: $nav-pills-padding-y $nav-pills-padding-x;\\n        color: $nav-pills-link-color;\\n        font-weight: 500;\\n        font-size: $font-size-sm;\\n        box-shadow: $nav-pills-box-shadow;\\n        background-color: $nav-pills-bg;\\n        transition: $transition-base;\\n\\n        \u0026:hover {\\n        \\tcolor: $nav-pills-link-hover-color;\\n        }\\n    }\\n\\n    .nav-link.active,\\n    .show \u003e .nav-link {\\n        color: $nav-pills-link-active-color;\\n        background-color: $nav-pills-link-active-bg;\\n    }\\n\\n    @include media-breakpoint-down(xs) {\\n        .nav-item {\\n            margin-bottom: $spacer;\\n        }\\n    }\\n}\\n\\n@include media-breakpoint-down(sm) {\\n    .nav-pills:not(.nav-pills-circle) {\\n        .nav-item {\\n            padding-right: 0;\\n        }\\n    }\\n}\\n\\n// Nav pills circle\\n\\n.nav-pills-circle {\\n    .nav-link {\\n        text-align: center;\\n        height: 60px;\\n        width: 60px;\\n        padding: 0;\\n        line-height: 60px;\\n        border-radius: 50%;\\n    }\\n\\n    .nav-link-icon {\\n        i, svg {\\n            font-size: 1rem;\\n        }\\n    }\\n}\\n\\n// Nav wrapper\\n.nav-wrapper {\\n    padding: 1rem 0;\\n    @include border-top-radius($card-border-radius);\\n\\n    + .card {\\n        @include border-top-radius(0);\\n        @include border-bottom-radius($card-border-radius);\\n    }\\n}\\n\",","\t\t\".navbar {\\n  \u0026.navbar-absolute{\\n    position: absolute;\\n    z-index: 1050;\\n    width: 100%;\\n  }\\n}\\n\\n.navbar-nav {\\n    .nav-link {\\n        font-size: $navbar-nav-link-font-size;\\n        font-family: $navbar-nav-link-font-family;\\n        font-weight: $navbar-nav-link-font-weight;\\n        text-transform: $navbar-nav-link-text-transform;\\n        letter-spacing: $navbar-nav-link-letter-spacing;\\n        @include transition($navbar-transition);\\n\\n        .nav-link-inner--text {\\n            margin-left: .25rem;\\n        }\\n    }\\n}\\n\\n.navbar-brand {\\n    font-size: $font-size-sm;\\n    font-weight: 600;\\n    text-transform: uppercase;\\n    font-size: .875rem;\\n    letter-spacing: .05px;\\n\\n    img {\\n        height: 30px;\\n    }\\n}\\n\\n.navbar-dark {\\n    .navbar-brand {\\n        color: $white;\\n    }\\n}\\n\\n.navbar-light {\\n    .navbar-brand {\\n        color: $gray-800;\\n    }\\n}\\n\\n.navbar-nav {\\n  .nav-item {\\n    .media:not(:last-child){\\n      margin-bottom: 1.5rem;\\n    }\\n  }\\n}\\n\\n@include media-breakpoint-up(lg) {\\n    // .navbar-main {\\n    //     padding: 1rem 0;\\n    // }\\n\\n    .navbar-nav {\\n        .nav-item {\\n            margin-right: .5rem;\\n\\n            [data-toggle=\\\"dropdown\\\"]::after {\\n                transition: $transition-base;\\n            }\\n\\n            \u0026.show {\\n                [data-toggle=\\\"dropdown\\\"]::after {\\n                    transform: rotate(180deg);\\n                }\\n            }\\n        }\\n        .nav-link {\\n            padding-top: $navbar-nav-link-padding-y;\\n            padding-bottom: $navbar-nav-link-padding-y;\\n            border-radius: $navbar-nav-link-border-radius;\\n\\n            i {\\n                margin-right: .625rem;\\n            }\\n        }\\n\\n        .nav-link-icon {\\n            padding-left: .5rem !important;\\n            padding-right: .5rem !important;\\n            font-size: 1rem;\\n            border-radius: $navbar-nav-link-border-radius;\\n\\n            i {\\n                margin-right: 0;\\n            }\\n        }\\n\\n        // Dropdown menu\\n        .dropdown-menu {\\n            opacity: 0;\\n            pointer-events: none;\\n            margin: 0;\\n\\n            \u0026:before {\\n                background: $dropdown-bg;\\n                box-shadow: none;\\n                content: '';\\n                display: block;\\n                height: 16px;\\n                width: 16px;\\n                left: 5px;\\n                position: absolute;\\n                bottom: 100%;\\n                transform: rotate(-45deg) translateY(1rem);\\n                z-index: -5;\\n                border-radius: $border-radius-sm;\\n            }\\n        }\\n\\n        .dropdown-menu-right {\\n            \u0026:before {\\n                right: 20px;\\n                left: auto;\\n            }\\n        }\\n\\n        \u0026:not(.navbar-nav-hover) {\\n            .dropdown-menu {\\n                \u0026.show {\\n                    opacity: 1;\\n                    pointer-events: auto;\\n                    animation: show-navbar-dropdown .25s ease forwards;\\n                }\\n\\n                \u0026.close {\\n                    display: block;\\n                    animation: hide-navbar-dropdown .15s ease backwards;\\n                }\\n            }\\n        }\\n\\n        \u0026.navbar-nav-hover {\\n          .dropdown-menu {\\n            opacity: 0;\\n            display: block;\\n            pointer-events: none;\\n            transform: translate(0, 10px) perspective(200px) rotateX(-2deg);\\n            transition: visibility 0.25s, opacity 0.25s, transform 0.25s;\\n            animation: none;\\n          }\\n\\n          .nav-item.dropdown:hover \u003e .dropdown-menu {\\n            display: block;\\n            opacity: 1;\\n            pointer-events: auto;\\n            visibility: visible;\\n            transform: translate(0, 0);\\n            animation: none;\\n          }\\n\\n          .nav-item.dropdown \u003e .dropdown-menu {\\n            .dropdown-item.open + .dropdown-menu {\\n              display: block;\\n              opacity: 1;\\n              pointer-events: auto;\\n              visibility: visible;\\n              transform: translate(0, 0);\\n              animation: none;\\n            }\\n            .dropdown-item + .dropdown-menu {\\n              margin-left: 10px;\\n\\n              \u0026:before {\\n                left: -16px;\\n                top: 4px;\\n              }\\n            }\\n          }\\n        }\\n\\n        .dropdown-menu-inner {\\n            position: relative;\\n            padding: 1rem;\\n        }\\n    }\\n}\\n\\n// Transparent navbar\\n\\n.navbar-transparent {\\n  position: absolute;\\n  top: 0;\\n  width: 100%;\\n  z-index: 100;\\n  background-color: transparent !important;\\n  border: 0;\\n  box-shadow: none;\\n\\n  .navbar-brand {\\n    color: rgba(255, 255, 255, 1);\\n  }\\n\\n  .navbar-toggler {\\n    color: rgba(255, 255, 255, 1);\\n  }\\n\\n  .navbar-toggler-icon {\\n    background-image: $navbar-dark-toggler-icon-bg;\\n  }\\n}\\n\\n.bg-white {\\n  .navbar-toggler-icon {\\n    background-image: $navbar-light-toggler-icon-bg\\n\\n  }\\n}\\n\\n@include media-breakpoint-up(md) {\\n    .navbar-transparent {\\n        .navbar-nav {\\n            .nav-link {\\n                color: $navbar-dark-color;\\n\\n                @include hover-focus {\\n                    color: $navbar-dark-hover-color;\\n                }\\n\\n                \u0026.disabled {\\n                    color: $navbar-dark-disabled-color;\\n                }\\n            }\\n\\n            .show \u003e .nav-link,\\n            .active \u003e .nav-link,\\n            .nav-link.show,\\n            .nav-link.active {\\n                color: $navbar-dark-active-color;\\n            }\\n        }\\n\\n        .navbar-brand {\\n            color: $navbar-dark-color;\\n\\n            @include hover-focus {\\n                color: $navbar-dark-color;\\n            }\\n        }\\n    }\\n}\\n\\n// Collapse\\n\\n.navbar-collapse-header {\\n    display: none;\\n}\\n\\n@include media-breakpoint-down(md) {\\n    .navbar-nav {\\n        .nav-link {\\n            padding: .625rem 0;\\n            color: theme-color(\\\"default\\\") !important;\\n        }\\n\\n        .dropdown-menu {\\n            box-shadow: none;\\n            min-width: auto;\\n\\n            .media {\\n                svg {\\n                    width: 30px;\\n                }\\n            }\\n        }\\n    }\\n\\n    .navbar-collapse {\\n        width: calc(100% - 1.4rem);\\n        position: absolute;\\n        top: 0;\\n        left: 0;\\n        right: 0;\\n        z-index: 1050;\\n        margin: .7rem;\\n        overflow-y: auto;\\n        height: auto !important;\\n        opacity: 0;\\n\\n        .navbar-toggler {\\n            width: 20px;\\n            height: 20px;\\n            position: relative;\\n            cursor: pointer;\\n            display: inline-block;\\n            padding: 0;\\n\\n            span {\\n                display: block;\\n                position: absolute;\\n                width: 100%;\\n                height: 2px;\\n                border-radius: 2px;\\n                opacity: 1;\\n                background: #283448;\\n            }\\n\\n            :nth-child(1) {\\n                transform: rotate(135deg);\\n            }\\n\\n            :nth-child(2) {\\n                transform: rotate(-135deg);\\n            }\\n        }\\n\\n        .navbar-collapse-header {\\n            display: block;\\n            padding-bottom: 1rem;\\n            margin-bottom: 1rem;\\n            border-bottom: 1px solid rgba(0, 0, 0, .1);\\n        }\\n\\n        .collapse-brand {\\n            img {\\n                height: 36px;\\n            }\\n        }\\n\\n        .collapse-close {\\n            text-align: right;\\n        }\\n    }\\n\\n    .navbar-collapse.collapsing,\\n    .navbar-collapse.show {\\n        padding: 1.5rem;\\n        border-radius: $border-radius;\\n        background: #FFF;\\n        box-shadow: 0 50px 100px rgba(50,50,93,.1),0 15px 35px rgba(50,50,93,.15),0 5px 15px rgba(0,0,0,.1);\\n        animation: show-navbar-collapse .2s ease forwards;\\n    }\\n\\n    .navbar-collapse.collapsing-out {\\n        animation: hide-navbar-collapse .2s ease forwards;\\n    }\\n}\\n\\n// Keyframes\\n\\n@keyframes show-navbar-collapse {\\n    0% {\\n        opacity: 0;\\n        transform: scale(.95);\\n        transform-origin: 100% 0;\\n    }\\n\\n    100% {\\n        opacity: 1;\\n        transform: scale(1);\\n    }\\n}\\n\\n@keyframes hide-navbar-collapse {\\n    from {\\n        opacity: 1;\\n        transform: scale(1);\\n        transform-origin: 100% 0;\\n    }\\n\\n    to {\\n        opacity: 0;\\n        transform: scale(.95);\\n    }\\n}\\n\\n@keyframes show-navbar-dropdown {\\n    0% {\\n        opacity: 0;\\n        transform: translate(0, 10px) perspective(200px) rotateX(-2deg);\\n        transition: visibility 0.25s, opacity 0.25s, transform 0.25s;\\n    }\\n\\n    100% {\\n        transform: translate(0, 0);\\n        opacity: 1;\\n    }\\n}\\n\\n@keyframes hide-navbar-dropdown {\\n    from {\\n        opacity: 1;\\n    }\\n\\n    to {\\n        opacity: 0;\\n        transform: translate(0, 10px);\\n    }\\n}\\n\",","\t\t\".page-item {\\n    \u0026.active .page-link {\\n        box-shadow: $pagination-active-box-shadow;\\n    }\\n\\n    .page-link,\\n    span {\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        padding: 0;\\n        margin: 0 3px;\\n        border-radius: 50% !important;\\n        width: 36px;\\n\\t\\theight: 36px;\\n\\t\\tfont-size: $font-size-sm;\\n    }\\n}\\n\\n.pagination-lg {\\n    .page-item {\\n        .page-link,\\n        span {\\n            width: 46px;\\n            height: 46px;\\n            line-height: 46px;\\n        }\\n    }\\n}\\n\\n.pagination-sm {\\n    .page-item {\\n        .page-link,\\n        span {\\n            width: 30px;\\n            height: 30px;\\n            line-height: 30px;\\n        }\\n    }\\n}\",","\t\t\".popover {\\n    border: 0;\\n}\\n\\n.popover-header {\\n\\tfont-weight: $font-weight-bold;\\n}\\n\\n// Alternative colors\\n@each $color, $value in $theme-colors {\\n    .popover-#{$color} {\\n        @include popover-variant($value);\\n    }\\n}\\n\",","\t\t\".progress-wrapper {\\n    position: relative;\\n    padding-top: 1.5rem;\\n}\\n.progress {\\n    height: 8px;\\n    margin-bottom: $spacer;\\n    overflow: hidden;\\n    border-radius: $border-radius-sm;\\n    background-color: $progress-bg;\\n    -webkit-box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.1);\\n    box-shadow: inset 0 1px 2px rgba(0, 0, 0, 0.1);\\n}\\n.progress .sr-only {\\n    width: auto;\\n    height: 20px;\\n    margin: 0 0 0 30px;\\n    left: 0;\\n    clip: auto;\\n    line-height: 20px;\\n    font-size: 13px;\\n}\\n\\n.progress-heading {\\n    font-size: 14px;\\n    font-weight: 500;\\n    margin: 0 0 2px;\\n    padding: 0;\\n}\\n.progress-bar {\\n    box-shadow: none;\\n    border-radius: 0;\\n    height: auto;\\n}\\n\\n.progress-label {\\n    span {\\n        display: inline-block;\\n        color: $default;\\n        font-size: .625rem;\\n        font-weight: 600;\\n        text-transform: uppercase;\\n        padding: .25rem 0rem;\\n    