\n}\\n\\n.noUi-connect {\\n    background: $noui-slider-connect-bg;\\n}\\n\\n.noUi-draggable {\\n    cursor: ew-resize;\\n}\\n\\n.noUi-vertical .noUi-draggable {\\n    cursor: ns-resize;\\n}\\n\\n.noUi-handle {\\n    border: 1px solid #D9D9D9;\\n    border-radius: 3px;\\n    background: #FFF;\\n    cursor: default;\\n    box-shadow: inset 0 0 1px #FFF, inset 0 1px 7px #EBEBEB, 0 3px 6px -3px #BBB;\\n    outline: none;\\n}\\n\\n.noUi-active {\\n    outline: none;\\n    //box-shadow: inset 0 0 1px #FFF, inset 0 1px 7px #DDD, 0 3px 6px -3px #BBB;\\n}\\n\\n\\n/* Disabled state;\\n */\\n\\n[disabled] .noUi-connect {\\n    background: #B8B8B8;\\n}\\n\\n[disabled].noUi-target,\\n[disabled].noUi-handle,\\n[disabled] .noUi-handle {\\n    cursor: not-allowed;\\n}\\n\\n\\n/* Base;\\n *\\n */\\n\\n.noUi-pips,\\n.noUi-pips * {\\n    -moz-box-sizing: border-box;\\n    box-sizing: border-box;\\n}\\n\\n.noUi-pips {\\n    position: absolute;\\n    color: #999;\\n}\\n\\n\\n/* Values;\\n *\\n */\\n\\n.noUi-value {\\n    position: absolute;\\n    white-space: nowrap;\\n    text-align: center;\\n}\\n\\n.noUi-value-sub {\\n    color: #ccc;\\n    font-size: 10px;\\n}\\n\\n\\n/* Markings;\\n *\\n */\\n\\n.noUi-marker {\\n    position: absolute;\\n    background: #CCC;\\n}\\n\\n.noUi-marker-sub {\\n    background: #AAA;\\n}\\n\\n.noUi-marker-large {\\n    background: #AAA;\\n}\\n\\n\\n/* Horizontal layout;\\n *\\n */\\n\\n.noUi-pips-horizontal {\\n    padding: 10px 0;\\n    height: 80px;\\n    top: 100%;\\n    left: 0;\\n    width: 100%;\\n}\\n\\n.noUi-value-horizontal {\\n  -webkit-transform: translate(-50%, 50%);\\n    transform: translate(-50%, 50%);\\n}\\n\\n.noUi-rtl .noUi-value-horizontal {\\n  -webkit-transform: translate(50%, 50%);\\n  transform: translate(50%, 50%);\\n}\\n\\n.noUi-marker-horizontal.noUi-marker {\\n    margin-left: -1px;\\n    width: 2px;\\n    height: 5px;\\n}\\n\\n.noUi-marker-horizontal.noUi-marker-sub {\\n    height: 10px;\\n}\\n\\n.noUi-marker-horizontal.noUi-marker-large {\\n    height: 15px;\\n}\\n\\n\\n/* Vertical layout;\\n *\\n */\\n\\n.noUi-pips-vertical {\\n    padding: 0 10px;\\n    height: 100%;\\n    top: 0;\\n    left: 100%;\\n}\\n\\n.noUi-value-vertical {\\n    -webkit-transform: translate(0, -50%);\\n    transform: translate(0, -50%, 0);\\n    padding-left: 25px;\\n}\\n\\n.noUi-rtl .noUi-value-vertical {\\n    -webkit-transform: translate(0, 50%);\\n    transform: translate(0, 50%);\\n}\\n\\n.noUi-marker-vertical.noUi-marker {\\n    width: 5px;\\n    height: 2px;\\n    margin-top: -1px;\\n}\\n\\n.noUi-marker-vertical.noUi-marker-sub {\\n    width: 10px;\\n}\\n\\n.noUi-marker-vertical.noUi-marker-large {\\n    width: 15px;\\n}\\n\\n.noUi-tooltip {\\n    display: block;\\n    position: absolute;\\n    border: 1px solid #D9D9D9;\\n    border-radius: 3px;\\n    background: #fff;\\n    color: #000;\\n    padding: 5px;\\n    text-align: center;\\n    white-space: nowrap;\\n}\\n\\n.noUi-horizontal .noUi-tooltip {\\n    -webkit-transform: translate(-50%, 0);\\n    transform: translate(-50%, 0);\\n    left: 50%;\\n    bottom: 120%;\\n}\\n\\n.noUi-vertical .noUi-tooltip {\\n    -webkit-transform: translate(0, -50%);\\n    transform: translate(0, -50%);\\n    top: 50%;\\n    right: 120%;\\n}\\n\\n\\n//  Custom styles\\n\\n.noUi-target {\\n    background: $noui-target-bg;\\n    border-radius: $noui-target-border-radius;\\n    border: 0;\\n    box-shadow: $noui-target-box-shadow;\\n    margin: 15px 0;\\n    cursor: pointer;\\n}\\n\\n.noUi-horizontal {\\n    height: $noui-target-thickness;\\n}\\n\\nhtml:not([dir=\\\"rtl\\\"]) .noUi-horizontal .noUi-handle {\\n    right: -10px;\\n}\\n\\n.noUi-vertical {\\n    width: $noui-target-thickness;\\n}\\n\\n.noUi-connect {\\n    background: theme-color(\\\"primary\\\");\\n    box-shadow: none;\\n}\\n\\n.noUi-handle {\\n\\n}\\n\\n.noUi-horizontal .noUi-handle,\\n.noUi-vertical .noUi-handle {\\n    top: -$noui-target-thickness;\\n    width: $noui-handle-width;\\n    height: $noui-handle-width;\\n    border-radius: 100%;\\n    box-shadow: none;\\n    cursor: pointer;\\n    background-color: $noui-handle-bg;\\n    border: $noui-handle-border;\\n    transition: box-shadow .15s, transform .15s;\\n}\\n\\n\\n.noUi-horizontal .noUi-handle.noUi-active,\\n.noUi-vertical .noUi-handle.noUi-active {\\n    transform: scale(1.2);\\n}\\n\\n.noUi-horizontal .noUi-active,\\n.noUi-vertical .noUi-active {\\n    //box-shadow: 0 0 3px 1px rgba(0, 0, 0, .1);\\n}\\n\\n.input-slider--cyan .noUi-connect {\\n    background: $cyan;\\n}\\n\\n.input-slider--cyan.noUi-horizontal .noUi-handle,\\n.input-slider--cyan.noUi-vertical .noUi-handle {\\n    background-color: $cyan;\\n}\\n\\n.input-slider--red .noUi-connect {\\n    background: $red;\\n}\\n\\n.input-slider--red.noUi-horizontal .noUi-handle,\\n.input-slider--red.noUi-vertical .noUi-handle {\\n    background-color: $red;\\n}\\n\\n.input-slider--green .noUi-connect {\\n    background: $green;\\n}\\n\\n.input-slider--green.noUi-horizontal .noUi-handle,\\n.input-slider--green.noUi-vertical .noUi-handle {\\n    background-color: $green;\\n}\\n\\n.input-slider--yellow .noUi-connect {\\n    background: $yellow;\\n}\\n\\n.input-slider--yellow.noUi-horizontal .noUi-handle,\\n.input-slider--yellow.noUi-vertical .noUi-handle {\\n    background-color: $yellow;\\n}\\n\\n.input-slider--pink .noUi-connect {\\n    background: $pink;\\n}\\n\\n.input-slider--pink.noUi-horizontal .noUi-handle,\\n.input-slider--pink.noUi-vertical .noUi-handle {\\n    background-color: $pink;\\n}\\n/* Disabled state */\\n[disabled] .noUi-connect,\\n[disabled].noUi-connect {\\n    background: $noui-slider-connect-disabled-bg;\\n}\\n\\n[disabled] .noUi-handle,\\n[disabled].noUi-origin {\\n    cursor: not-allowed;\\n}\\n\\n/* Range slider value labels */\\n.range-slider-value {\\n    font-size: $font-size-xs;\\n    font-weight: 500;\\n    background-color: rgba($dark, .7);\\n    color: color-yiq($dark);\\n    border-radius: 10px;\\n    padding: .4em .8em .3em .85em;\\n}\\n\\n.range-slider-wrapper .upper-info {\\n    font-weight: 400;\\n    margin-bottom: 5px;\\n}\\n\\n.input-slider-value-output {\\n    background: #333;\\n    color: #fff;\\n    padding: 4px 8px;\\n    position: relative;\\n    top: 12px;\\n    font-size: 11px;\\n    border-radius: 2px;\\n}\\n\\n.input-slider-value-output:after {\\n    bottom: 100%;\\n    left: 10px;\\n    border: solid transparent;\\n    content: \\\" \\\";\\n    height: 0;\\n    width: 0;\\n    position: absolute;\\n    pointer-events: none;\\n    border-color: rgba(136, 183, 213, 0);\\n    border-bottom-color: #333;\\n    border-width: 4px;\\n    margin-left: -4px;\\n}\\n\\n.input-slider-value-output.left:after {\\n    left: 10px;\\n    right: auto;\\n}\\n\\n.input-slider-value-output.right:after {\\n    right: 10px;\\n    left: auto;\\n}\\n\",","\t\t\".headroom {\\n    will-change: transform;\\n    background-color: inherit;\\n    @include transition($transition-base);\\n}\\n.headroom--pinned {\\n\\t@extend .position-fixed;\\n    transform: translateY(0%);\\n}\\n.headroom--unpinned {\\n\\t@extend .position-fixed;\\n    transform: translateY(-100%);\\n}\\n\\n.headroom--not-top {\\n\\tpadding-top: .5rem;\\n\\tpadding-bottom: .5rem;\\n    background-color: theme-color(\\\"default\\\") !important;\\n    box-shadow: 0 1px 10px rgba(130, 130, 134, 0.1);\\n}\\n\",","\t\t\"\\n@import \\\"docs/variables\\\";\\n@import \\\"docs/clipboard-js\\\";\\n@import \\\"docs/component-examples\\\";\\n@import \\\"docs/content\\\";\\n@import \\\"docs/footer\\\";\\n@import \\\"docs/nav\\\";\\n@import \\\"docs/prism\\\";\\n@import \\\"docs/sidebar\\\";\\n\",","\t\t\"// Local docs variables\\n$ct-primary:        theme-color(\\\"primary\\\") !default;\\n$ct-primary-bright: lighten(saturate($ct-primary, 5%), 15%) !default;\\n$ct-primary-light:  rgba(255, 255, 255, .9) !default;\\n$ct-dark:          \\t#2a2730 !default;\\n$ct-download:      \\t#ffe484 !default;\\n$ct-info:          \\t#5bc0de !default;\\n$ct-warning:       \\t#f0ad4e !default;\\n$ct-danger:        \\t#d9534f !default;\\n\\n$ct-sidebar-bg:\\t#f5f7f9;\\n$ct-sidebar-border-color: #e6ecf1;\\n\\n\",","\t\t\"// clipboard.js\\n//\\n// JS-based `Copy` buttons for code snippets.\\n\\n.ct-clipboard {\\n  position: relative;\\n  display: none;\\n  float: right;\\n\\n  + .highlight {\\n    margin-top: 0;\\n  }\\n}\\n\\n.btn-clipboard {\\n  position: absolute;\\n  top: 1rem;\\n  right: 1rem;\\n  z-index: 10;\\n  display: block;\\n  padding: .25rem .5rem;\\n  font-size: 75%;\\n  cursor: pointer;\\n  background-color: transparent;\\n  border: 0;\\n  border-radius: .25rem;\\n  color: #fff;\\n  background-color: $ct-primary;\\n\\n  \u0026:hover {\\n    color: #fff;\\n    background-color: darken($ct-primary, 10%);\\n  }\\n}\\n\\n@media (min-width: 768px) {\\n  .ct-clipboard {\\n    display: block;\\n  }\\n}\\n\",","\t\t\"// stylelint-disable no-duplicate-selectors, selector-no-qualifying-type\\n\\n//\\n// Grid examples\\n//\\n\\n.ct-example-row {\\n  .row {\\n    \u003e .col,\\n    \u003e [class^=\\\"col-\\\"] {\\n      span {\\n        display: block;\\n        padding: .75rem;\\n        color: rgb(57, 63, 73);\\n        background-color: rgb(255, 255, 255);\\n        box-shadow: rgba(0, 0, 0, 0.1) 0px 0px 0px 1px, rgba(0, 0, 0, 0.1) 0px 4px 16px;\\n        font-size: $font-size-sm;\\n        border-radius: .25rem;\\n        margin: 1rem 0;\\n      }\\n    }\\n  }\\n\\n  .no-gutters {\\n    \u003e .col,\\n    \u003e [class^=\\\"col-\\\"] {\\n      span {\\n        border-radius: 0;\\n      }\\n    }\\n  }\\n\\n  .flex-items-top,\\n  .flex-items-middle,\\n  .flex-items-bottom {\\n    min-height: 6rem;\\n    background-color: rgba(255, 0, 0, .1);\\n  }\\n}\\n\\n.ct-example-row-flex-cols .row {\\n  min-height: 10rem;\\n  background-color: rgba(255, 0, 0, .1);\\n\\n  \u0026 + .row {\\n    margin-top: 1rem;\\n  }\\n}\\n\\n.ct-highlight {\\n  background-color: rgba($ct-primary, .15);\\n  border: 1px solid rgba($ct-primary, .15);\\n}\\n\\n// Grid mixins\\n.example-container {\\n  width: 800px;\\n  @include make-container();\\n}\\n\\n.example-row {\\n  @include make-row();\\n}\\n\\n.example-content-main {\\n  @include make-col-ready();\\n\\n  @include media-breakpoint-up(sm) {\\n    @include make-col(6);\\n  }\\n\\n  @include media-breakpoint-up(lg) {\\n    @include make-col(8);\\n  }\\n}\\n\\n.example-content-secondary {\\n  @include make-col-ready();\\n\\n  @include media-breakpoint-up(sm) {\\n    @include make-col(6);\\n  }\\n\\n  @include media-breakpoint-up(lg) {\\n    @include make-col(4);\\n  }\\n}\\n\\n\\n//\\n// Container illustrations\\n//\\n\\n.ct-example-container {\\n  min-width: 16rem;\\n  max-width: 25rem;\\n  margin-right: auto;\\n  margin-left: auto;\\n}\\n\\n.ct-example-container-header {\\n  height: 3rem;\\n  margin-bottom: .5rem;\\n  background-color: lighten($blue, 50%);\\n  border-radius: .25rem;\\n}\\n\\n.ct-example-container-sidebar {\\n  float: right;\\n  width: 4rem;\\n  height: 8rem;\\n  background-color: lighten($blue, 25%);\\n  border-radius: .25rem;\\n}\\n\\n.ct-example-container-body {\\n  height: 8rem;\\n  margin-right: 4.5rem;\\n  background-color: lighten($ct-primary, 25%);\\n  border-radius: .25rem;\\n}\\n\\n.ct-example-container-fluid {\\n  max-width: none;\\n}\\n\\n\\n//\\n// Docs examples\\n//\\n\\n.ct-example {\\n  position: relative;\\n  margin: 1rem (-$grid-gutter-width / 2) 0;\\n  @include clearfix();\\n\\n  @include media-breakpoint-up(sm) {\\n    margin-right: 0;\\n    margin-left: 0;\\n  }\\n\\n  + .highlight,\\n  + .clipboard + .highlight {\\n    margin-top: 0;\\n  }\\n\\n  + p {\\n    margin-top: 2rem;\\n  }\\n\\n  .pos-f-t {\\n    position: relative;\\n    margin: -1rem;\\n\\n    @include media-breakpoint-up(sm) {\\n      margin: -1.5rem;\\n    }\\n  }\\n\\n  .custom-file-input:lang(es) ~ .custom-file-label::after {\\n    content: \\\"Elegir\\\";\\n  }\\n\\n  \u003e .form-control {\\n    + .form-control {\\n      margin-top: .5rem;\\n    }\\n  }\\n\\n  \u003e .nav + .nav,\\n  \u003e .alert + .alert,\\n  \u003e .navbar + .navbar,\\n  \u003e .progress + .progress,\\n  \u003e .progress + .btn,\\n  .badge,\\n  .btn {\\n    margin-top: .5rem;\\n    margin-bottom: .5rem;\\n  }\\n\\n  .btn-group {\\n    margin-top: .5rem;\\n    margin-bottom: .5rem;\\n    .btn {\\n      margin: 0;\\n    }\\n  }\\n\\n  .alert {\\n    margin: 0;\\n\\n    + .alert {\\n      margin-top: 1.25rem;\\n    }\\n  }\\n\\n  .badge {\\n    margin-right: .5rem;\\n  }\\n\\n  \u003e .dropdown-menu:first-child {\\n    position: static;\\n    display: block;\\n  }\\n\\n  \u003e .form-group:last-child {\\n    margin-bottom: 0;\\n  }\\n\\n  \u003e .close {\\n    float: none;\\n  }\\n}\\n\\n// Typography\\n.ct-example-type {\\n  .table {\\n    .type-info {\\n      color: #999;\\n      vertical-align: middle;\\n    }\\n    td {\\n      padding: 1rem 0;\\n      border-color: #eee;\\n    }\\n    tr:first-child td {\\n      border-top: 0;\\n    }\\n  }\\n\\n  h1,\\n  h2,\\n  h3,\\n  h4,\\n  h5,\\n  h6 {\\n    margin-top: 0;\\n    margin-bottom: 0;\\n  }\\n}\\n\\n// Contextual background colors\\n.ct-example-bg-classes p {\\n  padding: 1rem;\\n}\\n\\n// Images\\n.ct-example \u003e img {\\n  + img {\\n    margin-left: .5rem;\\n  }\\n}\\n\\n// Buttons\\n.ct-example {\\n  \u003e .btn-group {\\n    margin-top: .25rem;\\n    margin-bottom: .25rem;\\n  }\\n  \u003e .btn-toolbar + .btn-toolbar {\\n    margin-top: .5rem;\\n  }\\n}\\n\\n// Forms\\n.ct-example-control-sizing select,\\n.ct-example-control-sizing input[type=\\\"text\\\"] + input[type=\\\"text\\\"] {\\n  margin-top: .5rem;\\n}\\n.ct-example-form .input-group {\\n  margin-bottom: .5rem;\\n}\\n.ct-example \u003e textarea.form-control {\\n  resize: vertical;\\n}\\n\\n// List groups\\n.ct-example \u003e .list-group {\\n  max-width: 400px;\\n}\\n\\n// Navbars\\n.ct-example {\\n  .fixed-top,\\n  .sticky-top {\\n    position: static;\\n    margin: -1rem -1rem 1rem;\\n  }\\n  .fixed-bottom {\\n    position: static;\\n    margin: 1rem -1rem -1rem;\\n  }\\n\\n  @include media-breakpoint-up(sm) {\\n    .fixed-top,\\n    .sticky-top {\\n      margin: -1.5rem -1.5rem 1rem;\\n    }\\n    .fixed-bottom {\\n      margin: 1rem -1.5rem -1.5rem;\\n    }\\n  }\\n}\\n\\n// Pagination\\n.ct-example .pagination {\\n  margin-top: .5rem;\\n  margin-bottom: .5rem;\\n}\\n\\n// Example modals\\n.modal {\\n  z-index: 1072;\\n\\n  .tooltip,\\n  .popover {\\n    z-index: 1073;\\n  }\\n}\\n\\n.modal-backdrop {\\n  z-index: 1071;\\n}\\n\\n.ct-example-modal {\\n  background-color: #fafafa;\\n\\n  .modal {\\n    position: relative;\\n    top: auto;\\n    right: auto;\\n    bottom: auto;\\n    left: auto;\\n    z-index: 1;\\n    display: block;\\n  }\\n\\n  .modal-dialog {\\n    left: auto;\\n    margin-right: auto;\\n    margin-left: auto;\\n  }\\n}\\n\\n// Example tabbable tabs\\n.ct-example-tabs .nav-tabs {\\n  margin-bottom: 1rem;\\n}\\n\\n// Popovers\\n.ct-example-popover-static {\\n  padding-bottom: 1.5rem;\\n  background-color: #f9f9f9;\\n\\n  .popover {\\n    position: relative;\\n    display: block;\\n    float: left;\\n    width: 260px;\\n    margin: 1.25rem;\\n  }\\n}\\n\\n// Tooltips\\n.tooltip-demo a {\\n  white-space: nowrap;\\n}\\n\\n.ct-example-tooltip-static .tooltip {\\n  position: relative;\\n  display: inline-block;\\n  margin: 10px 20px;\\n  opacity: 1;\\n}\\n\\n// Scrollspy demo on fixed height div\\n.scrollspy-example {\\n  position: relative;\\n  height: 200px;\\n  margin-top: .5rem;\\n  overflow: auto;\\n}\\n\\n.scrollspy-example-2 {\\n  position: relative;\\n  height: 350px;\\n  overflow: auto;\\n}\\n\\n.ct-example-border-utils {\\n  [class^=\\\"border\\\"] {\\n    display: inline-block;\\n    width: 5rem;\\n    height: 5rem;\\n    margin: .25rem;\\n    background-color: #f5f5f5;\\n  }\\n}\\n\\n.ct-example-border-utils-0 {\\n  [class^=\\\"border\\\"] {\\n    border: 1px solid $border-color;\\n  }\\n}\\n\\n//\\n// Code snippets\\n//\\n\\n.highlight {\\n  padding: 0;\\n  margin-top: 1rem;\\n  //margin-bottom: 3rem;\\n  //background-color: $gray-100;\\n  -ms-overflow-style: -ms-autohiding-scrollbar;\\n\\n  @include media-breakpoint-up(sm) {\\n    padding: 0;\\n  }\\n}\\n\\n.ct-content .highlight {\\n  margin-right: (-$grid-gutter-width / 2);\\n  margin-left: (-$grid-gutter-width / 2);\\n\\n  @include media-breakpoint-up(sm) {\\n    margin-right: 0;\\n    margin-left: 0;\\n  }\\n}\\n\\n//\\n// Component-Code tabs\\n//\\n\\n.ct-example {\\n  margin-bottom: 2rem;\\n  padding-bottom: 2rem;\\n  border-bottom: 1px solid $gray-200;\\n\\n  .tab-content {\\n    .tab-example-result {\\n        background-color: #f5f7f9;\\n        border: 1px solid #e6ecf1;\\n        padding: 1.25rem;\\n        border-radius: .25rem;\\n    }\\n  }\\n\\n  .nav-tabs-code {\\n    margin-bottom: .375rem;\\n\\n    .nav-link {\\n      font-size: .875rem;\\n\\n      \u0026:active,\\n      \u0026.active {\\n        color: $ct-primary;\\n      }\\n    }\\n  }\\n}\\n\\n// Icon examples\\n.icon-examples {\\n  margin-top: 1rem;\\n}\\n.btn-icon-clipboard {\\n  margin: 0px;\\n  padding: 24px;\\n  font-size: 16px;\\n  font-weight: 400;\\n  line-height: 1.25;\\n  color: rgb(57, 63, 73);\\n  background-color: rgb(248, 249, 250);\\n  border-radius: 4px;\\n  border: 0px none;\\n  text-align: left;\\n  font-family: inherit;\\n  display: inline-block;\\n  vertical-align: middle;\\n  text-decoration: none;\\n  -moz-appearance: none;\\n  cursor: pointer;\\n  width: 100%;\\n  margin: .5rem 0;\\n\\n  \u0026:hover {\\n    background-color: rgb(255, 255, 255);\\n    box-shadow: rgba(0, 0, 0, 0.1) 0px 0px 0px 1px, rgba(0, 0, 0, 0.1) 0px 4px 16px;\\n  }\\n\\n  \u003e div {\\n    align-items: center;\\n    display: flex;\\n  }\\n\\n  i {\\n    box-sizing: content-box;\\n    color: rgb(57, 63, 73);\\n    vertical-align: middle;\\n    font-size: 1.5rem;\\n  }\\n\\n  span {\\n    display: inline-block;\\n    font-size: .875rem;\\n    line-height: 1.5;\\n    color: rgb(57, 63, 73);\\n    margin-left: 16px;\\n    overflow: hidden;\\n    white-space: nowrap;\\n    text-overflow: ellipsis;\\n    vertical-align: middle;\\n  }\\n}\\n\",","\t\t\".docs {\\n    background: #FFF;\\n\\n    h6 {\\n        font-size: 1rem;\\n        font-weight: $font-weight-bold;\\n    }\\n}\\n\\n.ct-content {\\n    order: 1;\\n\\n    \u003eh2[id],\\n    \u003eh3[id],\\n    \u003eh4[id] {\\n        pointer-events: none;\\n\\n        \u003ediv,\\n        \u003ea {\\n            pointer-events: auto;\\n        }\\n\\n        \u0026::before {\\n            display: block;\\n            height: 6rem;\\n            margin-top: -6rem;\\n            visibility: hidden;\\n            content: \\\"\\\";\\n        }\\n    }\\n\\n    \u003etable {\\n        width: 100%;\\n        max-width: 100%;\\n        margin-bottom: 1rem;\\n\\n        @include media-breakpoint-down(md) {\\n            display: block;\\n            overflow-x: auto;\\n            -ms-overflow-style: -ms-autohiding-scrollbar; // See https://github.com/twbs/bootstrap/pull/10057\\n            \u0026.table-bordered {\\n                border: 0;\\n            }\\n        } // Cells\\n        \u003ethead,\\n        \u003etbody,\\n        \u003etfoot {\\n            \u003etr {\\n                \u003eth,\\n                \u003etd {\\n                    padding: $table-cell-padding;\\n                    vertical-align: top;\\n                    border: 1px solid $table-border-color;\\n\\n                    \u003ep:last-child {\\n                        margin-bottom: 0;\\n                    }\\n                }\\n            }\\n        } // Prevent breaking of code (e.g., Grunt tasks list)\\n        td:first-child\u003ecode {\\n            white-space: nowrap;\\n        }\\n    }\\n}\\n\\n//\\n// Docs sections\\n//\\n.ct-content {\\n    \u003eh2:not(:first-child) {\\n        margin-top: 3rem;\\n        font-size: 1.5rem;\\n        font-weight: $font-weight-bold;\\n    }\\n\\n    \u003eh3 {\\n        margin-top: 2.5rem;\\n        font-size: 1.25rem;\\n        font-weight: $font-weight-bold;\\n    }\\n\\n    \u003eul li,\\n    \u003eol li {\\n        margin-bottom: .25rem;\\n    }\\n\\n    @include media-breakpoint-up(lg) {\\n        \u003eul,\\n        \u003eol,\\n        \u003ep {\\n            max-width: 80%;\\n        }\\n    }\\n}\\n\\n.ct-page-title {\\n    padding-left: 1.25rem;\\n    border-left: 2px solid $ct-primary;\\n    margin-bottom: 1.5rem;\\n}\\n\\n.ct-title {\\n    margin-top: 1rem;\\n    margin-bottom: .5rem;\\n    font-weight: 300;\\n\\n    @include media-breakpoint-up(sm) {\\n        font-size: 1.5rem;\\n        font-weight: $font-weight-bold;\\n    }\\n}\\n\\n.ct-lead {\\n    color: rgb(59, 69, 78);\\n    font-weight: 500;\\n\\n    @include media-breakpoint-up(sm) {\\n        max-width: 80%;\\n        margin-bottom: 1rem;\\n        font-size: .875rem;\\n    }\\n}\\n\\n.ct-text-purple {\\n    color: $ct-primary;\\n}\\n\\n.ct-text-purple-bright {\\n    color: $ct-primary-bright;\\n}\\n\\n// Docs code example tabs\\n.ct-tabs-example {\\n    .nav-link i {\\n        margin-right: 5px;\\n    }\\n}\\n\\n// Color swatches\\n.color-swatch {\\n    margin: 1rem 0;\\n    border-radius: .25rem;\\n    background-color: #F4F5F7;\\n}\\n\\n.color-swatch:after {\\n    content: \\\" \\\";\\n    display: table;\\n    clear: both;\\n}\\n\\n.color-swatch-header {\\n    position: relative;\\n    height: 0;\\n    padding-bottom: 50%;\\n    border-radius: .25rem .25rem 0 0;\\n    border: 1px solid transparent;\\n}\\n\\n.color-swatch-header.is-light {\\n    border-color: #C1C7D0;\\n}\\n\\n.color-swatch-header .pass-fail {\\n    position: absolute;\\n    width: 100%;\\n    bottom: 0;\\n}\\n\\n.color-swatch-header .pass-fail-item-wrap {\\n    position: relative;\\n    float: left;\\n    left: 50%;\\n    -webkit-transform: translateX(-50%);\\n    -ms-transform: translateX(-50%);\\n    transform: translateX(-50%);\\n}\\n\\n.color-swatch-header .pass-fail-item-group {\\n    display: inline-block;\\n    padding: 0 5px;\\n}\\n\\n.color-swatch-header .pass-fail-item {\\n    float: left;\\n    display: inline-block;\\n    text-align: center;\\n    padding: 2px;\\n}\\n\\n.color-swatch-header .pass-fail-item.white .example {\\n    color: #fff;\\n}\\n\\n.color-swatch-header .pass-fail-item.small .example {\\n    font-size: 10px;\\n}\\n\\n.color-swatch-header .pass-fail-item .lozenge {\\n    font-size: 11px;\\n    text-transform: uppercase;\\n    font-weight: 600;\\n    background: #000;\\n    color: #fff;\\n    padding: 2px 4px;\\n    line-height: 10px;\\n    border-radius: 4px;\\n    letter-spacing: 0.05em;\\n}\\n\\n.color-swatch-body {\\n    position: relative;\\n    left: 50%;\\n    float: left;\\n    padding: 10px 0;\\n    -webkit-transform: translateX(-50%);\\n    -ms-transform: translateX(-50%);\\n    transform: translateX(-50%);\\n}\\n\\n.color-swatch-body .prop-item-wrap {\\n    float: left;\\n    padding: 0 15px;\\n    min-width: 65px;\\n}\\n\\n.color-swatch-body .prop-item {\\n    padding: 15px 0;\\n}\\n\\n.color-swatch-body .prop-item .label {\\n    font-size: 11px;\\n    color: #62748C;\\n    text-transform: uppercase;\\n    line-height: 16px;\\n}\\n\\n.color-swatch-body .prop-item .value {\\n    font-size: 14px;\\n}\\n\\n.table-colors {\\n    font-weight: 600;\\n    font-size: 16px;\\n    width: 100%;\\n}\\n\\n.table-colors td,\\n.table-colors:first-child td,\\n.table-colors td:first-child,\\n.table-colors:first-child td:first-child,\\n.table-colors td:last-child,\\n.table-colors:first-child td:last-child {\\n    background: $ct-primary-light;\\n    border-bottom: 1px solid rgba(0, 0, 0, .1);\\n    padding: 10px;\\n}\\n\\n.table-colors tr:last-child td,\\n.table-colors:first-child tr:last-child td {\\n    border-bottom: none;\\n}\\n\\n.table-colors td:nth-child(1),\\n.table-colors:first-child td:nth-child(1) {\\n    line-height: 40px;\\n}\\n\\n.table-colors .swatch,\\n.table-colors:first-child .swatch {\\n    float: left;\\n    height: 40px;\\n    width: 40px;\\n    margin-right: 20px;\\n    display: inline-block;\\n    border-radius: 4px;\\n    border: 1px solid transparent;\\n}\\n\\n.table-colors .swatch.is-light,\\n.table-colors:first-child .swatch.is-light {\\n    border-color: #C1C7D0;\\n}\\n\\n.table-colors .lozenge,\\n.table-colors:first-child .lozenge {\\n    float: left;\\n    margin: 5px 10px 0 0;\\n    font-size: 10px;\\n    display: inline-block;\\n    text-transform: uppercase;\\n    font-weight: 600;\\n    background: #97A0AF;\\n    color: #042A53;\\n    padding: 2px 4px;\\n    line-height: 10px;\\n    border-radius: 4px;\\n    letter-spacing: 0.05em;\\n}\\n\\n\\n\\n#tags-component.tab-pane {\\n  .choices__inner {\\n    height: 60px;\\n  }\\n}\\n\\n.highlight pre {\\n  overflow: auto;\\n  margin: 0;\\n  padding: 1.25rem;\\n  font-family: Consolas,Menlo,Monaco,'Andale Mono WT','Andale Mono','Lucida Console','Lucida Sans Typewriter','DejaVu Sans Mono','Bitstream Vera Sans Mono','Liberation Mono','Nimbus Mono L','Courier New',Courier,monospace;\\n  font-size: 14px;\\n  line-height: 1.375;\\n  text-align: left;\\n  white-space: pre;\\n  word-spacing: normal;\\n  word-break: normal;\\n  -moz-tab-size: 4;\\n  -o-tab-size: 4;\\n  tab-size: 4;\\n  -webkit-hyphens: none;\\n  hyphens: none;\\n  color: #5e6687;\\n  border-radius: .25rem;\\n  background: #f5f7ff;\\n  direction: ltr;\\n  -ms-hyphens: none;\\n\\n  code {\\n    font-size: 87.5%;\\n    word-break: break-word;\\n    color: #5e6687;\\n  }\\n\\n  pre code {\\n    font-size: inherit;\\n    word-break: normal;\\n    color: inherit;\\n  }\\n  code, kbd, pre, samp {\\n    font-family: SFMono-Regular,Menlo,Monaco,Consolas,'Liberation Mono','Courier New',monospace;\\n    font-size: 1em;\\n  }\\n  .nt {\\n    color: #3d8fd1;\\n  }\\n  .na {\\n    color: #c76b29;\\n  }\\n  .s,\\n  .token.control,\\n  .token.directive,\\n  .token.keyword,\\n  .token.unit {\\n    color: #ac9739;\\n  }\\n  .token.punctuation {\\n    color: #5e6687;\\n  }\\n\\n}\\n.btn-clipboard {\\n  top: 3.5rem;\\n}\\n\\n.offline-doc .page-header{\\n  height: 100vh;\\n  display: flex;\\n  justify-content: center;\\n  align-items: center;\\n}\\n\",","\t\t\"//\\n// Footer\\n//\\n.ct-footer {\\n    font-size: 85%;\\n    text-align: center;\\n    background-color: #f7f7f7;\\n\\n    a {\\n        font-weight: 500;\\n        color: $gray-700;\\n\\n        \u0026:hover,\\n        \u0026:focus {\\n            color: $link-color;\\n        }\\n    }\\n\\n    p {\\n        margin-bottom: 0;\\n    }\\n\\n    @include media-breakpoint-up(sm) {\\n        text-align: left;\\n    }\\n}\\n\\n.ct-footer-links {\\n    padding-left: 0;\\n    margin-bottom: 1rem;\\n\\n    li {\\n        display: inline-block;\\n\\n        +li {\\n            margin-left: 1rem;\\n        }\\n    }\\n}\",","\t\t\"//\\n// Main navbar\\n//\\n.ct-navbar {\\n    background-color: $ct-primary;\\n    box-shadow: rgba(116, 129, 141, 0.1) 0px 1px 1px 0px;\\n    padding-top: .5rem;\\n    padding-bottom: .5rem;\\n    \\n    @include media-breakpoint-down(md) {\\n        padding-right: .5rem;\\n        padding-left: .5rem;\\n\\n        .navbar-nav-scroll {\\n            max-width: 100%;\\n            height: 2.5rem;\\n            margin-top: .25rem;\\n            overflow: hidden;\\n            font-size: .875rem;\\n\\n            .navbar-nav {\\n                padding-bottom: 2rem;\\n                overflow-x: auto;\\n                white-space: nowrap;\\n                -webkit-overflow-scrolling: touch;\\n            }\\n        }\\n    }\\n\\n    @include media-breakpoint-up(md) {\\n        @supports (position: sticky) {\\n            position: sticky;\\n            top: 0;\\n            z-index: 1071; // over everything in bootstrap\\n        }\\n    }\\n\\n    .navbar-nav {\\n        .nav-link {\\n            padding-right: .5rem;\\n            padding-left: .5rem;\\n            color: $ct-primary-light !important;\\n\\n            \u0026.active,\\n            \u0026:hover {\\n                color: #fff !important;\\n                background-color: transparent !important;\\n            }\\n\\n            \u0026.active {\\n                font-weight: 500;\\n            }\\n        }\\n    }\\n\\n    .navbar-nav-svg {\\n        display: inline-block;\\n        width: 1rem;\\n        height: 1rem;\\n        vertical-align: text-top;\\n    }\\n\\n    .dropdown-menu {\\n        font-size: .875rem;\\n    }\\n\\n    .dropdown-item.active {\\n        font-weight: 500;\\n        color: $gray-900;\\n        background-color: transparent;\\n        background-image: url(\\\"data:image/svg+xml;charset=utf8,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 8 8'%3E%3Cpath fill='%23292b2c' d='M2.3 6.73L.6 4.53c-.4-1.04.46-1.4 1.1-.8l1.1 1.4 3.4-3.8c.6-.63 1.6-.27 1.2.7l-4 4.6c-.43.5-.8.4-1.1.1z'/%3E%3C/svg%3E\\\");\\n        background-repeat: no-repeat;\\n        background-position: .4rem .87rem;\\n        background-size: .75rem .75rem;\\n        padding-left: 25px;\\n    }\\n}\\n\\n// Github corner\\n.github-corner {\\n    position: fixed;\\n    right: 0;\\n    z-index: 1080;\\n\\n    \u0026:hover {\\n        .octo-arm {\\n            animation: octocat-wave 560ms ease-in-out\\n        }\\n    }\\n\\n    svg {\\n        fill: $white;\\n        color: $ct-primary;\\n    }\\n}\\n\\n@keyframes octocat-wave {\\n    0%,\\n    100% {\\n        transform: rotate(0)\\n    }\\n    20%,\\n    60% {\\n        transform: rotate(-25deg)\\n    }\\n    40%,\\n    80% {\\n        transform: rotate(10deg)\\n    }\\n}\\n\",","\t\t\"code[class*=\\\"language-\\\"],\\npre[class*=\\\"language-\\\"] {\\n    font-family: Consolas, Menlo, Monaco, \\\"Andale Mono WT\\\", \\\"Andale Mono\\\", \\\"Lucida Console\\\", \\\"Lucida Sans Typewriter\\\", \\\"DejaVu Sans Mono\\\", \\\"Bitstream Vera Sans Mono\\\", \\\"Liberation Mono\\\", \\\"Nimbus Mono L\\\", \\\"Courier New\\\", Courier, monospace;\\n    font-size: 14px;\\n    line-height: 1.375;\\n    direction: ltr;\\n    text-align: left;\\n    white-space: pre;\\n    word-spacing: normal;\\n    word-break: normal;\\n    -moz-tab-size: 4;\\n    -o-tab-size: 4;\\n    tab-size: 4;\\n    -webkit-hyphens: none;\\n    -moz-hyphens: none;\\n    -ms-hyphens: none;\\n    hyphens: none;\\n    background: #f5f7ff;\\n    color: #5e6687;\\n    border-radius: .25rem;\\n}\\n\\npre[class*=\\\"language-\\\"]::-moz-selection,\\npre[class*=\\\"language-\\\"] ::-moz-selection,\\ncode[class*=\\\"language-\\\"]::-moz-selection,\\ncode[class*=\\\"language-\\\"] ::-moz-selection {\\n    text-shadow: none;\\n    background: #dfe2f1;\\n}\\n\\npre[class*=\\\"language-\\\"]::selection,\\npre[class*=\\\"language-\\\"] ::selection,\\ncode[class*=\\\"language-\\\"]::selection,\\ncode[class*=\\\"language-\\\"] ::selection {\\n    text-shadow: none;\\n    background: #dfe2f1;\\n}\\n\\n\\n/* Code blocks */\\n\\npre[class*=\\\"language-\\\"] {\\n    padding: 1.25rem;\\n    margin: 0;\\n    overflow: auto;\\n}\\n\\n\\n/* Inline code */\\n\\n:not(pre)\u003ecode[class*=\\\"language-\\\"] {\\n    padding: .1em;\\n    border-radius: .3em;\\n}\\n\\n.token.comment,\\n.token.prolog,\\n.token.doctype,\\n.token.cdata {\\n    color: #898ea4;\\n}\\n\\n.token.punctuation {\\n    color: #5e6687;\\n}\\n\\n.token.namespace {\\n    opacity: .7;\\n}\\n\\n.token.operator,\\n.token.boolean,\\n.token.number {\\n    color: #c76b29;\\n}\\n\\n.token.property {\\n    color: #c08b30;\\n}\\n\\n.token.tag {\\n    color: #3d8fd1;\\n}\\n\\n.token.string {\\n    color: #22a2c9;\\n}\\n\\n.token.selector {\\n    color: #6679cc;\\n}\\n\\n.token.attr-name {\\n    color: #c76b29;\\n}\\n\\n.token.entity,\\n.token.url,\\n.language-css .token.string,\\n.style .token.string {\\n    color: #22a2c9;\\n}\\n\\n.token.attr-value,\\n.token.keyword,\\n.token.control,\\n.token.directive,\\n.token.unit {\\n    color: #ac9739;\\n}\\n\\n.token.statement,\\n.token.regex,\\n.token.atrule {\\n    color: #22a2c9;\\n}\\n\\n.token.placeholder,\\n.token.variable {\\n    color: #3d8fd1;\\n}\\n\\n.token.deleted {\\n    text-decoration: line-through;\\n}\\n\\n.token.inserted {\\n    border-bottom: 1px dotted #202746;\\n    text-decoration: none;\\n}\\n\\n.token.italic {\\n    font-style: italic;\\n}\\n\\n.token.important,\\n.token.bold {\\n    font-weight: bold;\\n}\\n\\n.token.important {\\n    color: #c94922;\\n}\\n\\n.token.entity {\\n    cursor: help;\\n}\\n\\npre\u003ecode.highlight {\\n    outline: 0.4em solid #c94922;\\n    outline-offset: .4em;\\n}\\n\\n\\n/* overrides color-values for the Line Numbers plugin\\n * http://prismjs.com/plugins/line-numbers/\\n */\\n\\n.line-numbers .line-numbers-rows {\\n    border-right-color: #dfe2f1;\\n}\\n\\n.line-numbers-rows\u003espan:before {\\n    color: #979db4;\\n}\\n\\n\\n/* overrides color-values for the Line Highlight plugin\\n * http://prismjs.com/plugins/line-highlight/\\n */\\n\\n.line-highlight {\\n    background: rgba(107, 115, 148, 0.2);\\n    background: -webkit-linear-gradient(left, rgba(107, 115, 148, 0.2) 70%, rgba(107, 115, 148, 0));\\n    background: linear-gradient(to right, rgba(107, 115, 148, 0.2) 70%, rgba(107, 115, 148, 0));\\n}\",","\t\t\"// stylelint-disable declaration-no-important\\n//\\n// Right side table of contents\\n//\\n.ct-toc {\\n    @supports (position: sticky) {\\n        position: sticky;\\n        top: 4rem;\\n        height: calc(100vh - 4rem);\\n        overflow-y: auto;\\n    }\\n    order: 2;\\n    padding-top: 2rem;\\n    padding-bottom: 1.5rem;\\n    font-size: .875rem;\\n}\\n\\n.section-nav {\\n    padding-left: 0;\\n    border-left: 1px solid #eee;\\n\\n    ul {\\n        padding-left: 1rem;\\n\\n        ul {\\n            display: none;\\n        }\\n    }\\n}\\n\\n.toc-entry {\\n    display: block;\\n    font-size: 1rem;\\n\\n    a {\\n        display: block;\\n        padding: .125rem 1.5rem;\\n        color: #99979c;\\n        font-size: 90%;\\n\\n        \u0026:hover {\\n            color: $blue;\\n            text-decoration: none;\\n        }\\n    }\\n}\\n\\n//\\n// Left side navigation\\n//\\n.ct-sidebar {\\n    order: 0; // background-color: #f5f2f9;\\n    border-bottom: 1px solid $ct-sidebar-border-color;\\n    background-color: $ct-sidebar-bg;\\n\\n    @include media-breakpoint-up(md) {\\n        @supports (position: sticky) {\\n            position: sticky;\\n            top: 4rem;\\n            z-index: 1000;\\n            height: calc(100vh - 4rem);\\n        }\\n        border-right: 1px solid $ct-sidebar-border-color;\\n    }\\n\\n    @include media-breakpoint-up(xl) {\\n        flex: 0 1 320px;\\n    }\\n}\\n\\n.ct-links {\\n    padding-top: 2rem;\\n    padding-bottom: 1rem;\\n    margin-right: -15px;\\n    margin-left: -15px;\\n\\n    @include media-breakpoint-up(md) {\\n        @supports (position: sticky) {\\n            max-height: calc(100vh - 5rem);\\n            overflow-y: auto;\\n        }\\n    } // Override collapse behaviors\\n    @include media-breakpoint-up(md) {\\n        display: block !important;\\n    }\\n}\\n\\n.ct-search {\\n    position: relative; // To contain the Algolia search\\n    padding: 1rem 15px;\\n    margin-right: -15px;\\n    margin-left: -15px;\\n    border-bottom: 1px solid rgba(0, 0, 0, .05);\\n\\n    .form-control:focus {\\n        border-color: $ct-primary-bright;\\n        box-shadow: 0 0 0 3px rgba($ct-primary-bright, .25);\\n    }\\n}\\n\\n.ct-search-docs-toggle {\\n    line-height: 1;\\n    color: $gray-900;\\n}\\n\\n.ct-sidenav {\\n    display: none;\\n}\\n\\n.ct-toc-link {\\n    display: block;\\n    padding: .25rem 1.5rem;\\n    font-weight: 600;\\n    font-size: .875rem;\\n    color: #0d2b3e;\\n\\n    \u0026:hover {\\n        color: rgba(0, 0, 0, .85);\\n        text-decoration: none;\\n    }\\n}\\n\\n.ct-toc-item {\\n    \u0026.active {\\n        margin-bottom: 1rem;\\n\\n        \u0026:not(:first-child) {\\n            margin-top: 1rem;\\n        }\\n\\n        \u003e.ct-toc-link {\\n            color: rgba(0, 0, 0, .85);\\n\\n            \u0026:hover {\\n                background-color: transparent;\\n            }\\n        }\\n\\n        \u003e.ct-sidenav {\\n            display: block;\\n        }\\n    }\\n}\\n\\n// All levels of nav\\n.ct-sidebar .nav\u003eli\u003ea {\\n    display: block;\\n    padding: .25rem 1.5rem;\\n    font-size: 84%;\\n    color: #4c555a;\\n}\\n\\n.ct-sidebar .nav\u003eli\u003ea:hover {\\n    color: rgba(0, 0, 0, .85);\\n    text-decoration: none;\\n    background-color: transparent;\\n}\\n\\n.ct-sidebar .nav\u003e.active\u003ea {\\n    font-weight: 500;\\n    color: #0099e5;\\n    background-color: transparent;\\n    padding-left: 2rem;\\n    position: relative;\\n\\n    \u0026:before {\\n        content: '';\\n        position: absolute;\\n        height: 16px;\\n        width: 2px;\\n        background-color: #0099e5;\\n        top: 50%;\\n        left: 1.5rem;\\n        transform: translateY(-50%);\\n    }\\n}\\n\\n.ct-sidebar .nav\u003e.active:hover\u003ea {\\n    color: #0099e5\\n}\\n\\n\\n.scrollbar-inner {\\n    height: 100%;\\n\\n    \u0026:not(:hover) .scroll-element {\\n        opacity: 0;\\n    }\\n\\n    .scroll-element {\\n        transition: opacity 300ms;\\n        margin-right: 2px;\\n\\n        .scroll-bar,\\n        .scroll-element_track {\\n            transition: background-color 300ms;\\n        }\\n\\n        .scroll-element_track {\\n            background-color: transparent;\\n        }\\n    }\\n\\n    .scroll-element.scroll-y {\\n        width: 3px;\\n        right: 0;\\n    }\\n\\n    .scroll-element.scroll-x {\\n        height: 3px;\\n        bottom: 0;\\n    }\\n}\\n\"","\t],","\t\"names\": [],","\t\"mappings\": \"AAAA;;;;;;;;;;;;;;GAcG;AGdH;;;;;GAKG;AoCLH,AAAA,KAAK,CAAC;EAGF,MAAW,CAAE,QAAC;EAAd,QAAW,CAAE,QAAC;EAAd,QAAW,CAAE,QAAC;EAAd,MAAW,CAAE,QAAC;EAAd,KAAW,CAAE,QAAC;EAAd,QAAW,CAAE,QAAC;EAAd,QAAW,CAAE,QAAC;EAAd,OAAW,CAAE,QAAC;EAAd,MAAW,CAAE,QAAC;EAAd,MAAW,CAAE,QAAC;EAAd,OAAW,CAAE,KAAC;EAAd,MAAW,CAAE,QAAC;EAAd,WAAW,CAAE,QAAC;EAAd,OAAW,CAAE,QAAC;EAAd,SAAW