s/docs/footer.scss&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC155" class="react-file-line html-div" data-testid="code-cell" data-line-number="155" style="position:relative">		&quot;../scss/docs/nav.scss&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC156" class="react-file-line html-div" data-testid="code-cell" data-line-number="156" style="position:relative">		&quot;../scss/docs/prism.scss&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC157" class="react-file-line html-div" data-testid="code-cell" data-line-number="157" style="position:relative">		&quot;../scss/docs/sidebar.scss&quot;</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC158" class="react-file-line html-div" data-testid="code-cell" data-line-number="158" style="position:relative">	],</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC159" class="react-file-line html-div" data-testid="code-cell" data-line-number="159" style="position:relative">	&quot;sourcesContent&quot;: [</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC160" class="react-file-line html-div" data-testid="code-cell" data-line-number="160" style="position:relative">		&quot;/*!\n=========================================================\n*  Argon Design System  - v 1.2.0\n=========================================================\n\n* Product Page:  https://www.creative-tim.com/product/argon-design-system\n* Copyright  2020  Creative Tim (http://www.creative-tim.com)\n\nCoded by www.creative-tim.com\n\n=========================================================\n\n* The above copyright notice and this permission notice shall be included in all copies or substantial portions of the Software.\n\n */\n\n// Bootstrap Functions\n@import \&quot;bootstrap/functions\&quot;;\n\n// Theme Variables\n@import \&quot;variables\&quot;;\n\n// Bootstrap Core\n@import \&quot;bootstrap/bootstrap\&quot;;\n\n// Theme Core\n@import \&quot;theme\&quot;;\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC161" class="react-file-line html-div" data-testid="code-cell" data-line-number="161" style="position:relative">		&quot;// Bootstrap functions\n//\n// Utility mixins and functions for evaluating source code across our variables, maps, and mixins.\n\n// Ascending\n// Used to evaluate Sass maps like our grid breakpoints.\n@mixin _assert-ascending($map, $map-name) {\n  $prev-key: null;\n  $prev-num: null;\n  @each $key, $num in $map {\n    @if $prev-num == null or unit($num) == \&quot;%\&quot; {\n      // Do nothing\n    } @else if not comparable($prev-num, $num) {\n      @warn \&quot;Potentially invalid value for #{$map-name}: This map must be in ascending order, but key &#039;#{$key}&#039; has value #{$num} whose unit makes it incomparable to #{$prev-num}, the value of the previous key &#039;#{$prev-key}&#039; !\&quot;;\n    } @else if $prev-num &gt;= $num {\n      @warn \&quot;Invalid value for #{$map-name}: This map must be in ascending order, but key &#039;#{$key}&#039; has value #{$num} which isn&#039;t greater than #{$prev-num}, the value of the previous key &#039;#{$prev-key}&#039; !\&quot;;\n    }\n    $prev-key: $key;\n    $prev-num: $num;\n  }\n}\n\n// Starts at zero\n// Used to ensure the min-width of the lowest breakpoint starts at 0.\n@mixin _assert-starts-at-zero($map, $map-name: \&quot;$grid-breakpoints\&quot;) {\n  $values: map-values($map);\n  $first-value: nth($values, 1);\n  @if $first-value != 0 {\n    @warn \&quot;First breakpoint in #{$map-name} must start at 0, but starts at #{$first-value}.\&quot;;\n  }\n}\n\n// Replace `$search` with `$replace` in `$string`\n// Used on our SVG icon backgrounds for custom forms.\n//\n// @author Hugo Giraudel\n// @param {String} $string - Initial string\n// @param {String} $search - Substring to replace\n// @param {String} $replace (&#039;&#039;) - New value\n// @return {String} - Updated string\n@function str-replace($string, $search, $replace: \&quot;\&quot;) {\n  $index: str-index($string, $search);\n\n  @if $index {\n    @return str-slice($string, 1, $index - 1) + $replace + str-replace(str-slice($string, $index + str-length($search)), $search, $replace);\n  }\n\n  @return $string;\n}\n\n// Color contrast\n@function color-yiq($color, $dark: $yiq-text-dark, $light: $yiq-text-light) {\n  $r: red($color);\n  $g: green($color);\n  $b: blue($color);\n\n  $yiq: (($r * 299) + ($g * 587) + ($b * 114)) / 1000;\n\n  @if ($yiq &gt;= $yiq-contrasted-threshold) {\n    @return $dark;\n  } @else {\n    @return $light;\n  }\n}\n\n// Retrieve color Sass maps\n@function color($key: \&quot;blue\&quot;) {\n  @return map-get($colors, $key);\n}\n\n@function theme-color($key: \&quot;primary\&quot;) {\n  @return map-get($theme-colors, $key);\n}\n\n@function gray($key: \&quot;100\&quot;) {\n  @return map-get($grays, $key);\n}\n\n// Request a theme color level\n@function theme-color-level($color-name: \&quot;primary\&quot;, $level: 0) {\n  $color: theme-color($color-name);\n  $color-base: if($level &gt; 0, $black, $white);\n  $level: abs($level);\n\n  @return mix($color-base, $color, $level * $theme-color-interval);\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC162" class="react-file-line html-div" data-testid="code-cell" data-line-number="162" style="position:relative">		&quot;\n// Global settings\n\n$enable-caret:              true !default;\n$enable-rounded:            true !default;\n$enable-shadows:            true !default;\n$enable-gradients:          false !default;\n$enable-transitions:        true !default;\n$enable-grid-classes:       true !default;\n$enable-print-styles:       true !default;\n\n\n// Color system\n\n$white:    #fff !default;\n$gray-100: #f6f9fc !default;\n$gray-200: #e9ecef !default;\n$gray-300: #dee2e6 !default;\n$gray-400: #ced4da !default;\n$gray-500: #adb5bd !default;\n$gray-600: #8898aa !default;   // Line footer color\n$gray-700: #525f7f !default;   // Line p color\n$gray-800: #32325d !default;   // Line heading color\n$gray-900: #212529 !default;\n$black:    #000 !default;\n\n$grays: () !default;\n$grays: map-merge((\n  \&quot;100\&quot;: $gray-100,\n  \&quot;200\&quot;: $gray-200,\n  \&quot;300\&quot;: $gray-300,\n  \&quot;400\&quot;: $gray-400,\n  \&quot;500\&quot;: $gray-500,\n  \&quot;600\&quot;: $gray-600,\n  \&quot;700\&quot;: $gray-700,\n  \&quot;800\&quot;: $gray-800,\n  \&quot;900\&quot;: $gray-900\n), $grays);\n\n$blue:    #5e72e4 !default;\n$indigo:  #5603ad !default;\n$purple:  #8965e0 !default;\n$pink:    #f3a4b5 !default;\n$red:     #f5365c !default;\n$orange:  #fb6340 !default;\n$yellow:  #ffd600 !default;\n$green:   #2dce89 !default;\n$teal:    #11cdef !default;\n$cyan:    #2bffc6 !default;\n\n$colors: () !default;\n$colors: map-merge((\n  \&quot;blue\&quot;:       $blue,\n  \&quot;indigo\&quot;:     $indigo,\n  \&quot;purple\&quot;:     $purple,\n  \&quot;pink\&quot;:       $pink,\n  \&quot;red\&quot;:        $red,\n  \&quot;orange\&quot;:     $orange,\n  \&quot;yellow\&quot;:     $yellow,\n  \&quot;green\&quot;:      $green,\n  \&quot;teal\&quot;:       $teal,\n  \&quot;cyan\&quot;:       $cyan,\n  \&quot;white\&quot;:      $white,\n  \&quot;gray\&quot;:       $gray-600,\n  \&quot;light\&quot;:      $gray-400,\n  \&quot;lighter\&quot;:    $gray-200,\n  \&quot;gray-dark\&quot;:  $gray-800\n), $colors);\n\n$default:       #172b4d !default;\n$primary:       #5e72e4 !default;\n$secondary:     #f4f5f7 !default;\n$success:       $green !default;\n$info:          $teal !default;\n$warning:       $orange !default;\n$danger:        $red !default;\n$light:         $gray-500 !default;\n$dark:          $gray-900 !default;\n$darker:        darken($gray-900, 15%) !default;\n\n$facebook:      #3b5999 !default;\n$twitter:       #1da1f2 !default;\n$google-plus:   #dd4b39 !default;\n$instagram:     #e4405f !default;\n$pinterest:     #bd081c !default;\n$youtube:       #cd201f !default;\n$slack:         #3aaf85 !default;\n$dribbble:      #ea4c89 !default;\n$github:        #222222 !default;\n\n$theme-colors: () !default;\n$theme-colors: map-merge((\n  \&quot;default\&quot;:      $default,\n  \&quot;primary\&quot;:      $primary,\n  \&quot;secondary\&quot;:    $secondary,\n  \&quot;success\&quot;:      $success,\n  \&quot;info\&quot;:         $info,\n  \&quot;warning\&quot;:      $warning,\n  \&quot;danger\&quot;:       $danger,\n  \&quot;white\&quot;:        $white,\n  \&quot;neutral\&quot;:      $white,\n  \&quot;dark\&quot;:         $dark,\n  \&quot;darker\&quot;:       $darker\n), $theme-colors);\n\n$brand-colors: () !default;\n$brand-colors: map-merge((\n  \&quot;facebook\&quot;:     $facebook,\n  \&quot;twitter\&quot;:      $twitter,\n  \&quot;google-plus\&quot;:  $google-plus,\n  \&quot;instagram\&quot;:    $instagram,\n  \&quot;pinterest\&quot;:    $pinterest,\n  \&quot;youtube\&quot;:      $youtube,\n  \&quot;slack\&quot;:        $slack,\n  \&quot;dribbble\&quot;:     $dribbble,\n  \&quot;github\&quot;:       $github\n), $brand-colors);\n\n$shape-colors: () !default;\n$shape-colors: map-merge((\n  \&quot;default\&quot;:      #32325d,\n  \&quot;primary\&quot;:      #5533ff,\n  \&quot;secondary\&quot;:    #24b47e,\n  \&quot;neutral\&quot;:      #e9ecef,\n  \&quot;blue-gray\&quot;:    #b2cbe1,\n\n), $shape-colors);\n\n$shapes-primary-colors: () !default;\n$shapes-primary-colors: map-merge((\n  \&quot;step-1-gradient-bg\&quot;:         #281483,\n  \&quot;step-2-gradient-bg\&quot;:         #8f6ed5,\n  \&quot;step-3-gradient-bg\&quot;:         #d782d9,\n  \&quot;span-1-bg\&quot;:                  #53f,\n  \&quot;span-2-bg\&quot;:                  #4553ff,\n  \&quot;span-3-bg\&quot;:                  #4f40ff,\n  \&quot;span-4-bg\&quot;:                  #25ddf5,\n  \&quot;span-5-bg\&quot;:                  #1fa2ff\n), $shapes-primary-colors);\n\n$shapes-default-colors: () !default;\n$shapes-default-colors: map-merge((\n  \&quot;step-1-gradient-bg\&quot;:         #7795f8,\n  \&quot;step-2-gradient-bg\&quot;:         #6772e5,\n  \&quot;step-3-gradient-bg\&quot;:         #555abf,\n  \&quot;span-1-bg\&quot;:                  #7795f8,\n  \&quot;span-2-bg\&quot;:                  #7b9aff,\n  \&quot;span-3-bg\&quot;:                  #6f8ff8,\n  \&quot;span-4-bg\&quot;:                  #76eea7,\n  \&quot;span-5-bg\&quot;:                  #6adaff\n), $shapes-default-colors);\n\n$shapes-light-colors: () !default;\n$shapes-light-colors: map-merge((\n  \&quot;step-1-gradient-bg\&quot;:         #b2cbe1,\n  \&quot;step-2-gradient-bg\&quot;:         #f6f9fc,\n  \&quot;step-3-gradient-bg\&quot;:         #f6f9fc,\n  \&quot;span-1-bg\&quot;:                  #b4cce1,\n  \&quot;span-2-bg\&quot;:                  #c5dbef,\n  \&quot;span-3-bg\&quot;:                  #b9d5ed,\n  \&quot;span-4-bg\&quot;:                  #74e4a2,\n  \&quot;span-5-bg\&quot;:                  #008169\n), $shapes-light-colors);\n\n$shapes-dark-colors: () !default;\n$shapes-dark-colors: map-merge((\n  \&quot;step-1-gradient-bg\&quot;:         #32325d,\n  \&quot;step-2-gradient-bg\&quot;:         #32325d,\n  \&quot;step-3-gradient-bg\&quot;:         #32325d,\n  \&quot;span-1-bg\&quot;:                  #2e2e57,\n  \&quot;span-2-bg\&quot;:                  #2b2b58,\n  \&quot;span-3-bg\&quot;:                  #25254d,\n  \&quot;span-4-bg\&quot;:                  #d782d9,\n  \&quot;span-5-bg\&quot;:                  #008169\n), $shapes-dark-colors);\n\n\n// Translucent color variations\n$translucent-color-opacity: .6;\n\n// Set a specific jump point for requesting color jumps\n$theme-color-interval:      8% !default;\n\n// The yiq lightness value that determines when the lightness of color changes from \&quot;dark\&quot; to \&quot;light\&quot;. Acceptable values are between 0 and 255.\n$yiq-contrasted-threshold:  200 !default;\n\n// Customize the light and dark text colors for use in our YIQ color contrast function.\n$yiq-text-dark:             $gray-900 !default;\n$yiq-text-light:            $white !default;\n\n// Action colors\n\n$star-rating-color: $gray-400 !default;\n$star-rating-color-active: $yellow !default;\n\n$favorite-color: $yellow !default;\n$like-color: $blue !default;\n$love-color: $red !default;\n\n\n// Body\n\n$body-bg: $white !default;\n$body-color: $gray-700 !default;\n\n\n// Sections\n\n$section-colors: () !default;\n$section-colors: map-merge((\n  \&quot;primary\&quot;:      $body-bg,\n  \&quot;secondary\&quot;:    $secondary,\n  \&quot;light\&quot;:        $gray-400,\n  \&quot;dark\&quot;:         $dark,\n  \&quot;darker\&quot;:       $darker\n), $section-colors);\n\n// Links\n\n$link-color:                $primary !default;\n$link-decoration:           none !default;\n$link-hover-color:          darken($link-color, 15%);\n$link-hover-decoration:     none !default;\n\n// Grid breakpoints\n\n$grid-breakpoints: (\n  xs: 0,\n  sm: 576px,\n  md: 768px,\n  lg: 992px,\n  xl: 1200px\n);\n\n@include _assert-ascending($grid-breakpoints, \&quot;$grid-breakpoints\&quot;);\n@include _assert-starts-at-zero($grid-breakpoints);\n\n\n// Grid containers\n//\n// Define the maximum width of `.container` for different screen sizes.\n\n$container-max-widths: (\n  sm: 540px,\n  md: 720px,\n  lg: 960px,\n  xl: 1040px\n);\n\n@include _assert-ascending($container-max-widths, \&quot;$container-max-widths\&quot;);\n\n\n// Spacing\n\n$spacer: 1rem !default;\n$spacers: () !default;\n$spacers: map-merge((\n  -9: -($spacer * 10),\n  -8: -($spacer * 8),\n  -7: -($spacer * 6),\n  -6: -($spacer * 4.5),\n  -5: -($spacer * 3),\n  -4: -($spacer * 1.5),\n  -3: -$spacer,\n  -2: -($spacer * .5),\n  -1: -($spacer * .25),\n  0: 0,\n  1: ($spacer * .25),\n  2: ($spacer * .5),\n  3: $spacer,\n  4: ($spacer * 1.5),\n  5: ($spacer * 3),\n  6: ($spacer * 4.5),\n  7: ($spacer * 6),\n  8: ($spacer * 8),\n  9: ($spacer * 10)\n), $spacers);\n\n\n// This variable affects the `.h-*` and `.w-*` classes.\n\n$sizes: () !default;\n$sizes: map-merge((\n  25: 25%,\n  50: 50%,\n  75: 75%,\n  100: 100%\n), $sizes);\n\n// Components\n\n$shape-height-xl:              1.5 !default;\n$shape-height-lg:              1.5 !default;\n$shape-height-sm:              1.5 !default;\n\n$border-width:                .0625rem !default;\n$border-color:                $gray-200 !default;\n\n$border-radius:               .25rem !default;\n$border-radius-xl:            .35rem !default;\n$border-radius-lg:            .3rem !default;\n$border-radius-sm:            .2rem !default;\n\n$box-shadow-sm:               0 .125rem .25rem rgba($black, .075);\n$box-shadow:                  0 15px 35px rgba(50,50,93,.1), 0 5px 15px rgba(0,0,0,.07);\n$box-shadow-lg:               0 1rem 3rem rgba($black, .175);\n\n$component-active-color:        $white !default;\n$component-active-bg:           theme-color(\&quot;primary\&quot;) !default;\n$component-active-border-color: theme-color(\&quot;primary\&quot;) !default;\n\n$component-hover-color:        $gray-300 !default;\n$component-hover-bg:           $gray-300 !default;\n$component-hover-border-color: $gray-300 !default;\n\n$caret-width:                 .3em !default;\n\n$transition-base:             all .15s ease !default;\n$btn-transition:              $transition-base !default;\n$transition-fade:             opacity .15s linear !default;\n$transition-collapse:         height .35s ease !default;\n\n\n// Fonts\n\n$font-family-base: &#039;Open Sans&#039;, sans-serif !default;\n$font-family-alt: &#039;Open Sans&#039;, sans-serif !default;\n\n$font-size-base:              1rem !default; // Assumes the browser default, typically `16px`\n$font-size-xl:                ($font-size-base * 1.5);\n$font-size-lg:                ($font-size-base * 1.25);\n$font-size-sm:                ($font-size-base * .875);\n$font-size-xs:                ($font-size-base * .75);\n\n$font-weight-light:           300 !default;\n$font-weight-normal:          400 !default;\n$font-weight-bold:            600 !default;\n$font-weight-extra-bold:      700 !default;\n\n$font-weight-base:            $font-weight-normal !default;\n$shape-height-base:            1.5 !default;\n\n\n$h1-font-size:                $font-size-base * 2.5 !default;\n$h2-font-size:                $font-size-base * 2 !default;\n$h3-font-size:                $font-size-base * 1.75 !default;\n$h4-font-size:                $font-size-base * 1.5 !default;\n$h5-font-size:                $font-size-base * 1.25 !default;\n$h6-font-size:                $font-size-base !default;\n\n\n$headings-margin-bottom:      ($spacer / 2);\n$headings-font-family:        inherit !default;\n$headings-font-weight:        $font-weight-normal !default;\n$headings-line-height:        1.5 !default;\n$headings-color:              $gray-800 !default;\n\n$heading-letter-spacing:      .025em !default;\n$heading-font-size:           .95rem !default;\n$heading-text-transform:      uppercase !default;\n$heading-font-weight:         $headings-font-weight !default;\n\n$heading-title-letter-spacing:      .025em !default;\n$heading-title-font-size:           1.375rem !default;\n$heading-title-font-weight:         $font-weight-bold !default;\n$heading-title-text-transform:      uppercase !default;\n\n$heading-section-letter-spacing:      .025em !default;\n$heading-section-font-size:           1.375rem !default;\n$heading-section-font-weight:         $font-weight-bold !default;\n$heading-section-text-transform:      uppercase !default;\n\n$display1-size:               3.3rem !default;\n$display2-size:               2.75rem !default;\n$display3-size:               2.1875rem !default;\n$display4-size:               1.6275rem