-width solid $black;\n    }\n\n    .table {\n      border-collapse: collapse !important;\n\n      td,\n      th {\n        background-color: $white !important;\n      }\n    }\n\n    .table-bordered {\n      th,\n      td {\n        border: 1px solid $gray-300 !important;\n      }\n    }\n\n    .table-dark {\n      color: inherit;\n\n      th,\n      td,\n      thead th,\n      tbody + tbody {\n        border-color: $table-border-color;\n      }\n    }\n\n    .table .thead-dark th {\n      color: inherit;\n      border-color: $table-border-color;\n    }\n\n    // Bootstrap specific changes end\n  }\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC250" class="react-file-line html-div" data-testid="code-cell" data-line-number="250" style="position:relative">		&quot;\n/*!\n\n=========================================================\n* {{ site.product.name }} {{ site.product.name_long }} - v{{ site.product.version }}\n=========================================================\n\n* Product Page: {{ site.product.download }}\n* Copyright {{ &#039;now&#039; | date: \&quot;%Y\&quot; }} {{ site.author }} ({{ site.website.url }})\n* Licensed under MIT ({{ site.product.license }})\n\n* Coded by www.creative-tim.com\n\n=========================================================\n\n* The above copyright notice and this permission notice shall be included in all copies or substantial portions of the Software.\n\n*/\n\n// {{ site.product.name }} components\n\n@import \&quot;functions\&quot;;\n@import \&quot;mixins\&quot;;\n\n@import \&quot;reboot\&quot;;\n@import \&quot;global\&quot;;\n@import \&quot;utilities\&quot;;\n\n@import \&quot;accordion\&quot;;\n@import \&quot;alert\&quot;;\n@import \&quot;avatar\&quot;;\n@import \&quot;badge\&quot;;\n@import \&quot;buttons\&quot;;\n@import \&quot;card\&quot;;\n@import \&quot;carousel\&quot;;\n@import \&quot;close\&quot;;\n@import \&quot;content\&quot;;\n@import \&quot;