;mixins/modals\&quot;;\n@import \&quot;mixins/popover\&quot;;\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC253" class="react-file-line html-div" data-testid="code-cell" data-line-number="253" style="position:relative">		&quot;@mixin alert-variant($background, $border, $color) {\n    color: color-yiq($background);\n    @include gradient-bg($background);\n    border-color: $border;\n\n    hr {\n        border-top-color: darken($border, 5%);\n    }\n\n    .alert-link {\n        color: darken($color, 10%);\n    }\n}&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC254" class="react-file-line html-div" data-testid="code-cell" data-line-number="254" style="position:relative">		&quot;@mixin badge-variant($bg) {\n\tcolor: saturate(darken($bg, 10%), 10);\n    background-color: transparentize(lighten($bg, 25%), .5);\n\n  \t&amp;[href] {\n\t    @include hover-focus {\n\t        color: color-yiq($bg);\n\t        text-decoration: none;\n\t        background-color: darken($bg, 10%);\n\t    }\n\t}\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC255" class="react-file-line html-div" data-testid="code-cell" data-line-number="255" style="position:relative">		&quot;// Contextual backgrounds\n@mixin bg-variant($parent, $color) {\n    #{$parent} {\n        background-color: $color !important;\n    }\n    a#{$parent},\n    button#{$parent} {\n        @include hover-focus {\n          background-color: darken($color, 10%) !important;\n        }\n    }\n}\n\n@mixin bg-gradient-variant($parent, $color) {\n    #{$parent} {\n        background: linear-gradient(35deg, $color 0, adjust-hue($color, 25%) 100%) !important;\n    }\n}\n\n@mixin bg-translucent-variant($parent, $color) {\n    #{$parent} {\n        background-color: darken(rgba($color, $translucent-color-opacity), 7%) !important;\n    }\n    a#{$parent},\n    button#{$parent} {\n        @include hover-focus {\n            background-color: darken(rgba($color, $translucent-color-opacity), 12%) !important;\n        }\n    }\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC256" class="react-file-line html-div" data-testid="code-cell" data-line-number="256" style="position:relative">		&quot;@mixin button-variant($background, $border, $hover-background: darken($background, 0%), $hover-border: darken($border, 0%), $active-background: darken($background, 10%), $active-border: darken($border, 0%)) {\n    color: color-yiq($background);\n    @include gradient-bg($background);\n    border-color: $border;\n    @include box-shadow($btn-box-shadow);\n\n    @include hover {\n        color: color-yiq($hover-background);\n        @include gradient-bg($hover-background);\n        border-color: $hover-border;\n    }\n\n    &amp;:focus,\n    &amp;.focus {\n        // Avoid using mixin so we can pass custom focus shadow properly\n        @if $enable-shadows {\n            box-shadow: $btn-box-shadow, 0 0 0 $btn-focus-width rgba($border, .5);\n        }\n        @else {\n            box-shadow: 0 0 0 $btn-focus-width rgba($border, .5);\n        }\n    }\n    // Disabled comes first so active can properly restyle\n    &amp;.disabled,\n    &amp;:disabled {\n        color: color-yiq($background);\n        background-color: $background;\n        border-color: $border;\n    }\n\n    &amp;:not(:disabled):not(.disabled):active,\n    &amp;:not(:disabled):not(.disabled).active,\n    .show&gt;&amp;.dropdown-toggle {\n        color: color-yiq($active-background);\n        background-color: $active-background;\n        @if $enable-gradients {\n            background-image: none; // Remove the gradient for the pressed/active state\n        }\n        border-color: $active-border;\n\n        &amp;:focus {\n            // Avoid using mixin so we can pass custom focus shadow properly\n            @if $enable-shadows {\n                box-shadow: $btn-active-box-shadow, 0 0 0 $btn-focus-width rgba($border, .5);\n            }\n            @else {\n                box-shadow: 0 0 0 $btn-focus-width rgba($border, .5);\n            }\n        }\n    }\n}\n\n@mixin button-outline-variant($color, $color-hover: color-yiq($color), $active-background: $color, $active-border: $color) {\n    color: $color;\n    background-color: transparent;\n    background-image: none;\n    border-color: $color;\n\n    &amp;:hover {\n        color: $color-hover;\n        background-color: $active-background;\n        border-color: $active-border;\n    }\n\n    &amp;:focus,\n    &amp;.focus {\n        box-shadow: 0 0 0 $btn-focus-width rgba($color, .5);\n    }\n\n    &amp;.disabled,\n    &amp;:disabled {\n        color: $color;\n        background-color: transparent;\n    }\n\n    &amp;:not(:disabled):not(.disabled):active,\n    &amp;:not(:disabled):not(.disabled).active,\n    .show&gt;&amp;.dropdown-toggle {\n        color: color-yiq($active-background);\n        background-color: $active-background;\n        border-color: $active-border;\n\n        &amp;:focus {\n            // Avoid using mixin so we can pass custom focus shadow properly\n            @if $enable-shadows and $btn-active-box-shadow !=none {\n                box-shadow: $btn-active-box-shadow, 0 0 0 $btn-focus-width rgba($color, .5);\n            }\n            @else {\n                box-shadow: 0 0 0 $btn-focus-width rgba($color, .5);\n            }\n        }\n    }\n}\n\n// Button sizes\n@mixin button-size($padding-y, $padding-x, $font-size, $line-height, $border-radius) {\n    padding: $padding-y $padding-x;\n    font-size: $font-size;\n    line-height: $line-height; // Manually declare to provide an override to the browser default\n    @if $enable-rounded {\n        border-radius: $border-radius;\n    }\n    @else {\n        border-radius: 0;\n    }\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC257" class="react-file-line html-div" data-testid="code-cell" data-line-number="257" style="position:relative">		&quot;@mixin form-control-focus() {  \n  &amp;:focus {\n    color: $input-focus-color;\n    background-color: $input-focus-bg;\n    border-color: $input-focus-border-color;\n    outline: 0;\n    // Avoid using mixin so we can pass custom focus shadow properly\n    @if $enable-shadows {\n      box-shadow: $input-box-shadow, $input-focus-box-shadow;\n    } @else {\n      box-shadow: $input-focus-box-shadow;\n    }\n  }\n}\n\n\n@mixin form-validation-state($state, $color) {\n  .#{$state}-feedback {\n    display: none;\n    width: 100%;\n    margin-top: $form-feedback-margin-top;\n    font-size: $form-feedback-font-size;\n    color: $color;\n  }\n\n  .#{$state}-tooltip {\n    position: absolute;\n    top: 100%;\n    z-index: 5;\n    display: none;\n    max-width: 100%; // Contain to parent when possible\n    padding: .5rem;\n    margin-top: .1rem;\n    font-size: .875rem;\n    line-height: 1;\n    color: #fff;\n    background-color: rgba($color, .8);\n    border-radius: .2rem;\n  }\n\n  .form-control,\n  .custom-select {\n    .was-validated &amp;:#{$state},\n    &amp;.is-#{$state} {\n      border-color: $color;\n\n      &amp;:focus {\n        border-color: $color;\n        //box-shadow: 0 1px $input-focus-width 0 rgba($color, .75);\n      }\n\n      ~ .#{$state}-feedback,\n      ~ .#{$state}-tooltip {\n        display: block;\n      }\n    }\n  }\n\n  .form-check-input {\n    .was-validated &amp;:#{$state},\n    &amp;.is-#{$state} {\n      ~ .form-check-label {\n        color: $color;\n      }\n\n      ~ .#{$state}-feedback,\n      ~ .#{$state}-tooltip {\n        display: block;\n      }\n    }\n  }\n\n  .custom-control-input {\n    .was-validated &amp;:#{$state},\n    &amp;.is-#{$state} {\n      ~ .custom-control-label {\n        color: $color;\n\n        &amp;::before {\n          background-color: lighten($color, 25%);\n          border-color: lighten($color, 25%);\n        }\n      }\n\n      ~ .#{$state}-feedback,\n      ~ .#{$state}-tooltip {\n        display: block;\n      }\n\n      &amp;:checked {\n        ~ .custom-control-label::before {\n          @include gradient-bg(lighten($color, 10%));\n          border-color: lighten($color, 25%);\n        }\n      }\n\n      &amp;:focus {\n        ~ .custom-control-label::before {\n          box-shadow: 0 0 0 1px $body-bg, 0 0 0 $input-focus-width rgba($color, .25);\n        }\n      }\n    }\n  }\n\n  // custom file\n  .custom-file-input {\n    .was-validated &amp;:#{$state},\n    &amp;.is-#{$state} {\n      ~ .custom-file-label {\n        border-color: $color;\n\n        &amp;::before { border-color: inherit; }\n      }\n\n      ~ .#{$state}-feedback,\n      ~ .#{$state}-tooltip {\n        display: block;\n      }\n\n      &amp;:focus {\n        ~ .custom-file-label {\n          box-shadow: 0 0 0 $input-focus-width rgba($color, .25);\n        }\n      }\n    }\n  }\n}\n\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC258" class="react-file-line html-div" data-testid="code-cell" data-line-number="258" style="position:relative">		&quot;@mixin icon-shape-variant($color) {\n    color: saturate(darken($color, 10%), 10);\n    background-color: transparentize(lighten($color, 10%), .5);\n}&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC259" class="react-file-line html-div" data-testid="code-cell" data-line-number="259" style="position:relative">		&quot;@mixin modal-variant($background) {\n\t.modal-title {\n\t\tcolor: color-yiq($background);\n\t}\n\t.modal-header,\n\t.modal-footer {\n\t\tborder-color: rgba(color-yiq($background), .075);\n\t}\n\t.modal-content {\n\t\tbackground-color: $background;\n\t\tcolor: color-yiq($background);\n\n\t\t.heading {\n\t\t\tcolor: color-yiq($background);\n\t\t}\n\t}\n\n\t.close { \n    \t&amp;&gt;span:not(.sr-only) {\n    \t\tcolor: $white;\n    \t}\n    }\n}&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC260" class="react-file-line html-div" data-testid="code-cell" data-line-number="260" style="position:relative">		&quot;@mixin popover-variant($background) {\n\n\tbackground-color: $background;\n\n\t.popover-header {\n\t\tbackground-color: $background;\n\t\tcolor: color-yiq($background);\n\t}\n\n\t.popover-body {\n\t\tcolor: color-yiq($background);\n\t}\n\t.popover-header{\n\t\tborder-color: rgba(color-yiq($background), .2);\n\t}\n\t&amp;.bs-popover-top {\n\t\t.arrow::after {\n\t\t\tborder-top-color: $background;\n\t\t}\n\t}\n\t&amp;.bs-popover-right {\n\t\t.arrow::after {\n\t\t\tborder-right-color: $background;\n\t\t}\n\t}\n\t&amp;.bs-popover-bottom {\n\t\t.arrow::after {\n\t\t\tborder-bottom-color: $background;\n\t\t}\n\t}\n\t&amp;.bs-popover-left {\n\t\t.arrow::after {\n\t\t\tborder-left-color: $background;\n\t\t}\n\t}\n}&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC261" class="react-file-line html-div" data-testid="code-cell" data-line-number="261" style="position:relative">		&quot;iframe {\n    border: 0;\n}\n\nfigcaption,\nfigure,\nmain {\n    display: block;\n}\n\nmain {\n    overflow: hidden;\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC262" class="react-file-line html-div" data-testid="code-cell" data-line-number="262" style="position:relative">		&quot;// Nucleo icons\n\n.section-nucleo-icons .icons-container {\n    position: relative;\n    max-width: 100%;\n    height: 360px;\n    margin: 0 auto;\n    z-index: 1;\n}\n\n.section-nucleo-icons {\n\n    --icon-size: 5rem;\n    --icon-sm-size: 3.75rem;\n    --gutter: 7rem;\n\n    .icons-container {\n        i {\n            position: absolute;\n            display: inline-flex;\n            align-items: center;\n            justify-content: center;\n            border-radius: 50%;\n            background: $white;\n            z-index: 1;\n            transform: translate(-50%, -50%);\n            @include box-shadow($box-shadow);\n            transition: all .2s cubic-bezier(.25,.65,.9,.75);\n\n            &amp;.icon {\n                width: var(--icon-size);\n                height: var(--icon-size);\n                font-size: 1.7em;\n            }\n\n            &amp;.icon-sm {\n                width: var(--icon-sm-size);\n                height: var(--icon-sm-size);\n                font-size: 1.5em;\n            }\n\n            &amp;:nth-child(1) {\n                font-size: 42px;\n                color: theme-color(\&quot;warning\&quot;);\n                z-index: 2;\n            }\n        }\n\n        &amp;:not(.on-screen) {\n            i {\n                transform: translate(-50%, -50%);\n                left: 50%;\n                top: 50%;\n\n                &amp;:not(:nth-child(1)) {\n                    opacity: 0;\n                }\n            }\n        }\n\n        &amp;.on-screen {\n\n            i {\n                opacity: 1;\n\n                &amp;:nth-child(1) {\n                    left: 50%;\n                    top: 50%;\n                    font-size: 42px;\n                    color: theme-color(\&quot;warning\&quot;);\n                }\n\n                &amp;:nth-child(2) {\n                    left: calc(50% + (var(--gutter) * 1.7));\n                    top: 50%;\n                }\n\n                &amp;:nth-child(3) {\n                    left: calc(50% + var(--gutter));\n                    top: calc(50% + var(--gutter));\n                }\n\n                &amp;:nth-child(4) {\n                    left: calc(50% + var(--gutter));\n                    top: calc(50% - var(--gutter));\n                }\n\n                &amp;:nth-child(5) {\n                    left: calc(50% + (var(--gutter) * 3));\n                    top: 50%;\n                }\n\n                &amp;:nth-child(6) {\n                    left: calc(50% + (var(--gutter) * 2.7));\n                    top: calc(50% + (var(--gutter) * 1.5));\n                }\n\n                &amp;:nth-child(7) {\n                    left: calc(50% + (var(--gutter) * 2.7));\n                    top: calc(50% - (var(--gutter) * 1.5));\n                }\n\n                &amp;:nth-child(8) {\n                    left: calc(50% - (var(--gutter) * 1.7));\n                    top: 50%;\n                }\n\n                &amp;:nth-child(9) {\n                    left: calc(50% - var(--gutter));\n                    top: calc(50% + var(--gutter));\n                }\n\n                &amp;:nth-child(10) {\n                    left: calc(50% - var(--gutter));\n                    top: calc(50% - var(--gutter));\n                }\n\n                &amp;:nth-child(11) {\n                    left: calc(50% - (var(--gutter) * 4));\n                    top: 50%;\n                }\n\n                &amp;:nth-child(12) {\n                    left: calc(50% - (var(--gutter) * 2.7));\n                    top: calc(50% + (var(--gutter) * 1.5));\n                }\n\n                &amp;:nth-child(13) {\n                    left: calc(50% - (var(--gutter) * 2.7));\n                    top: calc(50% - (var(--gutter) * 1.5));\n                }\n            }\n\n        }\n    }\n\n    @include media-breakpoint-down(md) {\n      overflow: hidden;\n    }\n}\n\n\n// Blurable sections\n\n.blur--hover {\n    position: relative;\n\n    .blur-item {\n        transition: 1s cubic-bezier(.19,1,.22,1);\n        will-change: transform;\n        filter: blur(0);\n        opacity: 1;\n    }\n\n    .blur-hidden {\n        position: absolute;\n        top: calc(50% + 7px);\n        left: 50%;\n        transform: translate(-50