lor,\n$value in $brand-colors {\n    .btn-#{$color} {\n        @include button-variant($value, $value);\n    }\n}\n&quot;,</div></div></div><div class="react-code-text react-code-line-contents" style="min-height:auto"><div><div id="LC278" class="react-file-line html-div" data-testid="code-cell" data-line-number="278" style="position:relative">		&quot;\n.card {\n  position: relative;\n\n  &amp;.card-plain {\n    background: transparent;\n    box-shadow: none;\n    border: none;\n  }\n}\n\n.profile-page {\n    .card-profile {\n        margin-top: -150px;\n\n        .card-profile-image {\n            position: relative;\n            //min-height: 130px;\n\n            img {\n                max-width: 180px;\n                border-radius: $border-radius;\n                @extend .shadow;\n                transform: translate(-50%,-30%);\n                position: absolute;\n                left: 50%;\n                transition: $transition-base;\n\n                &amp;:hover {\n                    transform: translate(-50%, -33%);\n                }\n            }\n        }\n\n        .card-profile-stats {\n            padding: 1rem 0;\n\n            &gt; div {\n                text-align: center;\n                margin-right: 1rem;\n                padding: .875rem;\n\n                &amp;:last-child {\n                    margin-right: 0;\n                }\n\n                .heading {\n                    font-size: 1.1rem;\n                    font-weight: bold;\n                    display: block;\n                }\n                .description {\n                    font-size: .875rem;\n                    color: $gray-500;\n                }\n            }\n        }\n\n        .card-profile-actions {\n            padding: .875rem;\n        }\n\n        @include media-breakpoint-down(xs) {\n            .card-profile-actions {\n                margin-top: 110px;\n            }\n        }\n\n        @include media-breakpoint-between(sm, md) {\n            